def _get_headers() -> dict:
    """Rotate User-Agent each call with realistic browser headers."""
    ua = random.choice(_UA_LIST)
    is_mobile = 'Mobile' in ua or 'Android' in ua or 'iPhone' in ua or 'iPad' in ua
    return {
        'User-Agent': ua,
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8',
        'Accept-Language': random.choice([
            'en-US,en;q=0.9', 'en-GB,en;q=0.9', 'en-US,en;q=0.5',
            'en-US,en;q=0.9,fr;q=0.8', 'en-US,en;q=0.9,de;q=0.8',
        ]),
        'Accept-Encoding': 'gzip, deflate, br',
        'Connection': 'keep-alive',
        'Upgrade-Insecure-Requests': '1',
        'Sec-Fetch-Dest': 'document',
        'Sec-Fetch-Mode': 'navigate',
        'Sec-Fetch-Site': 'none',
        'Sec-Fetch-User': '?1',
        'Cache-Control': 'max-age=0',
        **({"Sec-CH-UA-Mobile": "?1"} if is_mobile else {"Sec-CH-UA-Mobile": "?0"}),
    }



# ══════════════════════════════════════════════════════════════════
# 🌐  REQUEST ENGINE — TLS Fingerprinting + Session + CSRF Auto-Carry
#     Backend priority: curl_cffi → httpx → requests (fallback)
#
#     pip install curl-cffi        # best TLS fingerprint (JA3/JA4)
#     pip install httpx[http2]     # HTTP/2 + custom TLS
# ══════════════════════════════════════════════════════════════════

# TLS impersonation profiles available in curl_cffi
_TLS_PROFILES = {
    "chrome":    "chrome136",
    "chrome120": "chrome120",
    "chrome110": "chrome110",
    "chrome107": "chrome107",
    "safari":    "safari18_0",
    "safari17":  "safari17_0",
    "firefox":   "firefox133",
    "firefox117": "firefox117",
    "edge":      "edge133",
}

# Sec-CH-UA hint strings aligned with each profile
_SEC_CH_UA = {
    "chrome136":  '"Chromium";v="136", "Google Chrome";v="136", "Not-A.Brand";v="99"',
    "chrome120":  '"Chromium";v="120", "Google Chrome";v="120", "Not-A.Brand";v="8"',
    "chrome110":  '"Chromium";v="110", "Google Chrome";v="110", "Not-A.Brand";v="99"',
    "chrome107":  '"Chromium";v="107", "Google Chrome";v="107", "Not-A.Brand";v="24"',
    "safari18_0": "",
    "safari17_0": "",
    "firefox133": "",
    "firefox117": "",
    "edge133":    '"Chromium";v="133", "Not-A.Brand";v="8", "Microsoft Edge";v="133"',
}

# ── CSRF / nonce regex patterns ───────────────────────────────────
_RE_CSRF = [
    re.compile(
        r"""name=["'](?:_token|csrf[_-]?token|authenticity_token|"""
        r"""_csrf|csrfmiddlewaretoken|__RequestVerificationToken)["']"""
        r"""(?:\s[^>]*)?\s+value=["']([^"']{8,})["']""",
        re.I),
    re.compile(
        r"""content=["']([^"']{20,})["'].*?name=["']csrf[_-]?token["']""",
        re.I),
    re.compile(
        r'''"(?:csrf[_-]?token|_token|xsrf[_-]?token)"\s*:\s*"([^"]{8,})"''',
        re.I),
    re.compile(
        r"""window\.__csrf\s*=\s*["']([^"']{8,})["']""",
        re.I),
    re.compile(
        r"""<meta[^>]+name=["']csrf-token["'][^>]+content=["']([^"']{8,})["']""",
        re.I),
]
_RE_NONCE = [
    re.compile(
        r"""name=["'](?:nonce|__nonce|_nonce)["'](?:\s[^>]*)?\s+value=["']([^"']{8,})["']""",
        re.I),
    re.compile(
        r'''"(?:nonce|requestNonce|antiForgery)"\s*:\s*"([^"]{8,})"''',
        re.I),
]


class _RequestEngine:
    """
    Unified request engine for /payload scans.

    Features
    --------
    * TLS Fingerprinting  -- curl_cffi impersonates real Chrome/Safari JA3/JA4.
                             httpx fallback keeps HTTP/2 + ALPN negotiation.
                             requests used only if both are absent.
    * Session Persistence -- cookies, connection pool and CSRF tokens survive
                             across every request in a single scan run.
    * CSRF Auto-Carry     -- after each response the engine scans the body for
                             CSRF / nonce tokens and injects them into the next
                             request automatically.
    * Proxy Support       -- honours proxy_manager.get_proxy() transparently.

    Usage
    -----
        engine = _make_engine("chrome")   # or "safari", "firefox", "edge"
        resp   = engine.get("https://example.com/checkout")
        resp2  = engine.post(endpoint, data={"card": "..."})
        engine.close()

        # or as context manager:
        with _make_engine("safari") as eng:
            html = eng.get(url).text
    """

    def __init__(self, profile="chrome", timeout=TIMEOUT, proxy=None):
        """
        profile : TLS impersonation key — see _TLS_PROFILES.
                  Ignored gracefully when curl_cffi is absent.
        timeout : seconds for connect + read.
        proxy   : requests-style proxy dict e.g. {"https": "http://1.2.3.4:8080"}.
                  Pass None to auto-use proxy_manager each call.
        """
        self.profile     = _TLS_PROFILES.get(profile, "chrome136")
        self.timeout     = timeout
        self._proxy      = proxy
        self._csrf_token = ""
        self._nonce      = ""

        if _CURL_CFFI_OK:
            self._session = _curl_cffi_requests.Session()
            self._backend = "curl_cffi"
        elif _HTTPX_OK:
            self._session = _httpx.Client(
                http2=True, verify=False,
                follow_redirects=True, timeout=timeout,
            )
            self._backend = "httpx"
        else:
            self._session        = requests.Session()
            self._session.verify = False
            self._backend        = "requests"

        logger.debug(
            "_RequestEngine  backend=%-10s  profile=%s",
            self._backend, self.profile,
        )

    # ── Internal helpers ──────────────────────────────────────────

    def _proxy_dict(self):
        if self._proxy is not None:
            return self._proxy
        try:
            return proxy_manager.get_proxy()
        except Exception:
            return None

    def _build_headers(self, extra=None):
        """Merge rotated browser headers + Sec-CH-UA hint + CSRF token."""
        h     = _get_headers()
        ch_ua = _SEC_CH_UA.get(self.profile, "")
        if ch_ua:
            h["Sec-CH-UA"]          = ch_ua
            h["Sec-CH-UA-Platform"] = '"Windows"'
        if self._csrf_token:
            h["X-CSRF-Token"]     = self._csrf_token
            h["X-Requested-With"] = "XMLHttpRequest"
        if extra:
            h.update(extra)
        return h

    def _extract_tokens(self, text):
        """Scan response body for CSRF / nonce tokens and cache them."""
        for pat in _RE_CSRF:
            m = pat.search(text)
            if m:
                c = m.group(1)
                if len(c) >= 8 and "{{" not in c:
                    self._csrf_token = c
                    break
        for pat in _RE_NONCE:
            m = pat.search(text)
            if m:
                c = m.group(1)
                if len(c) >= 8 and "{{" not in c:
                    self._nonce = c
                    break

    def _do_request(self, method, url, **kwargs):
        """
        Dispatch to the active backend.
        curl_cffi  → impersonate= kwarg enables JA3/JA4 TLS fingerprint.
        httpx      → HTTP/2 + proper ALPN (no TLS fingerprint spoofing).
        requests   → plain urllib3 fallback.
        """
        proxies = self._proxy_dict()
        if self._backend == "curl_cffi":
            return self._session.request(
                method, url,
                impersonate=self.profile,
                timeout=self.timeout,
                proxies=proxies or {},
                verify=False,
                **kwargs,
            )
        if self._backend == "httpx":
            kw = dict(kwargs)
            if proxies:
                p = proxies.get("https") or proxies.get("http")
                if p:
                    kw["proxies"] = {"https://": p, "http://": p}
            return self._session.request(method, url, **kw)
        # requests fallback
        return self._session.request(
            method, url,
            timeout=self.timeout, verify=False,
            proxies=proxies, allow_redirects=True,
            **kwargs,
        )

    # ── Public API ────────────────────────────────────────────────

    def get(self, url, headers=None, **kwargs):
        """
        HTTP GET — carries session cookies and CSRF token automatically.
        Scans the response body for new CSRF / nonce tokens after each call.
        """
        resp = self._do_request(
            "GET", url, headers=self._build_headers(headers), **kwargs
        )
        try:
            self._extract_tokens(resp.text)
        except Exception:
            pass
        return resp

    def post(self, url, data=None, json_body=None, headers=None, **kwargs):
        """
        HTTP POST — carries session cookies + CSRF token.
        Accepts form data dict or json_body dict.
        CSRF token is injected into data under common field names.
        """
        h  = self._build_headers(headers)
        kw = dict(kwargs)
        if json_body is not None:
            h.setdefault("Content-Type", "application/json")
            kw["json"] = json_body
        elif data is not None:
            if self._csrf_token:
                for fname in (
                    "_token", "csrf_token", "authenticity_token",
                    "_csrf", "csrfmiddlewaretoken",
                    "__RequestVerificationToken",
                ):
                    if fname not in data:
                        data = {**data, fname: self._csrf_token}
                        break
            if self._nonce:
                data = {**data, "nonce": self._nonce}
            kw["data"] = data
        resp = self._do_request("POST", url, headers=h, **kw)
        try:
            self._extract_tokens(resp.text)
        except Exception:
            pass
        return resp

    def close(self):
        """Release underlying connection pool / session."""
        try:
            self._session.close()
        except Exception:
            pass

    def __enter__(self):
        return self

    def __exit__(self, *_):
        self.close()

    # ── Read-only properties ──────────────────────────────────────

    @property
    def backend(self):
        """Active backend: 'curl_cffi' | 'httpx' | 'requests'."""
        return self._backend

    @property
    def csrf_token(self):
        """Last extracted CSRF token (empty string if none found yet)."""
        return self._csrf_token

    @property
    def cookies(self):
        """Current session cookies as a plain dict."""
        try:
            return dict(self._session.cookies)
        except Exception:
            return {}


def _make_engine(profile="chrome"):
    """
    Convenience factory — returns a ready _RequestEngine.

    Profile options
    ---------------
    "chrome" / "chrome120" / "chrome110"  -- Chrome TLS fingerprint
    "safari" / "safari17"                 -- Safari TLS fingerprint
    "firefox" / "firefox117"              -- Firefox TLS fingerprint
    "edge"                                -- Edge TLS fingerprint
    """
    engine = _RequestEngine(profile=profile)
    logger.info(
        "RequestEngine  backend=%-10s  profile=%-14s  curl_cffi=%s  httpx=%s",
        engine.backend, engine.profile,
        "OK" if _CURL_CFFI_OK else "missing",
        "OK" if _HTTPX_OK    else "missing",
    )
    return engine

# ══════════════════════════════════════════════════════════════════


def _get_page_fingerprint(url: str, timeout: int = 6) -> tuple:
    """
    Get (status_code, body_hash, content_length) for baseline comparison.
    Used to detect catch-all pages.
    """
    try:
        resp = requests.get(url, headers=_get_headers(), timeout=timeout,
                            stream=True, allow_redirects=True, verify=False,
                            proxies=proxy_manager.get_proxy())
        status = resp.status_code
        chunk  = b''
        for part in resp.iter_content(1024):
            chunk += part
            if len(chunk) >= 1024: break
        resp.close()
        body_hash = hashlib.md5(chunk[:512]).hexdigest()
        ct_length = int(resp.headers.get('Content-Length', len(chunk)))
        return status, body_hash, ct_length, resp.headers.get('Content-Type','')
    except Exception:
        return 0, '', 0, ''


def _detect_catchall(base_url: str) -> tuple:
    """
    Dual-probe catch-all detection with difflib similarity check.
    Uses two independent random paths to cross-confirm catch-all behaviour,
    and stores the baseline body bytes for per-probe similarity comparison.

    Returns (is_catchall: bool, baseline_hash: str, baseline_len: int,
             baseline_body: bytes)
    The 4th element (baseline_body) is used by _probe_one for difflib ratio.
    """
    import string as _str
    def _rand_path():
        name = ''.join(random.choices(_str.ascii_lowercase, k=18))
        return '/' + name + random.choice(['.html', '.php', '.json', ''])

    base = base_url.rstrip('/')
    path1 = _rand_path()
    path2 = _rand_path()

    try:
        r1 = requests.get(base + path1, headers=_get_headers(), timeout=7,
                          stream=True, allow_redirects=True, verify=False,
                          proxies=proxy_manager.get_proxy())
        s1 = r1.status_code
        body1 = b''.join(list(r1.iter_content(2048))[:2])
        r1.close()
    except Exception:
        s1, body1 = 0, b''

    if s1 != 200:
        return False, '', 0, b''

    # Second probe — confirms first isn't a coincidental 200
    try:
        r2 = requests.get(base + path2, headers=_get_headers(), timeout=7,
                          stream=True, allow_redirects=True, verify=False,
                          proxies=proxy_manager.get_proxy())
        s2 = r2.status_code
        body2 = b''.join(list(r2.iter_content(2048))[:2])
        r2.close()
    except Exception:
        s2, body2 = 0, b''

    if s2 != 200:
        # Only first path returned 200 — could be coincidence, not a true catch-all
        return False, '', 0, b''

    # Both random paths return 200 → confirmed catch-all
    baseline_body = body1[:1024]
    baseline_hash = hashlib.md5(baseline_body[:512]).hexdigest()
    baseline_len  = len(baseline_body)
    return True, baseline_hash, baseline_len, baseline_body


def _is_fake_200_content(body: bytes, ct: str) -> bool:
    if 'html' not in ct.lower():
        return False
    # Check first 2 KB instead of 800 bytes — some sites embed 404 signals deeper
    snippet = body[:2048].lower()
    return any(s in snippet for s in _FAKE_SIGS)


def _probe_one(
    base_url: str, path: str, label: str, severity: str,
    catchall: bool, baseline_hash: str, baseline_len: int,
    delay: float = 0.0,
    baseline_body: bytes = b'',
    session: "requests.Session | None" = None,
) -> dict | None:
    """
    Probe one path — GET + stream.
    Improvements over v17:
      • difflib.SequenceMatcher similarity check (catch-all resilience)
      • Reads 4 KB instead of 1 KB for better fake-200 detection
      • Content-type based confidence: JSON/XML/plain on .env/.git = auto-CRITICAL
      • Accepts optional pre-built requests.Session (connection reuse)
      • Retry once on Timeout before giving up
    """
    if delay > 0:
        time.sleep(delay)

    full_url = base_url.rstrip('/') + path
    _req = session if session is not None else requests

    def _do_get():
        return _req.get(
            full_url, headers=_get_headers(),
            timeout=9, stream=True,
            allow_redirects=True, verify=False,
            proxies=proxy_manager.get_proxy() if session is None else None,
        )

    try:
        resp = _do_get()
    except requests.exceptions.Timeout:
        # Single retry on timeout
        try:
            resp = _do_get()
        except Exception:
            return None
    except Exception:
        return None

    try:
        status = resp.status_code
        ct     = resp.headers.get('Content-Type', '')

        if status == 200:
            # Read up to 4 KB for better fake-200 / similarity detection
            chunk = b''
            for part in resp.iter_content(512):
                chunk += part
                if len(chunk) >= 4096: break
            resp.close()

            # ── Catch-all filter — triple-check ──
            if catchall:
                page_hash = hashlib.md5(chunk[:512]).hexdigest()
                page_len  = len(chunk)

                # 1. Exact hash match
                if page_hash == baseline_hash:
                    return None

                # 2. Length within ±5 % of baseline (handles gzip variance)
                if baseline_len > 0:
                    ratio = abs(page_len - baseline_len) / max(baseline_len, 1)
                    if ratio < 0.05:
                        return None

                # 3. difflib content similarity > 0.92 → same page with tiny variation
                if baseline_body:
                    sim = difflib.SequenceMatcher(
                        None, baseline_body[:512], chunk[:512], autojunk=False
                    ).ratio()
                    if sim > 0.92:
                        return None

            # ── Fake 200 (custom 404 HTML) ────────
            if _is_fake_200_content(chunk, ct):
                return None

            # ── Content-type confidence boost ─────
            ct_lower = ct.lower()
            _is_data_ct = any(x in ct_lower for x in (
                'json', 'xml', 'plain', 'yaml', 'toml', 'env', 'ini', 'text'
            ))
            _is_sensitive_path = any(x in path.lower() for x in (
                '.env', '.git', 'config', 'backup', 'dump', 'secret', 'key',
                'passwd', 'shadow', 'db', 'sql', 'log', 'admin', 'credential'
            ))
            # Non-HTML data response on a sensitive path → escalate to CRITICAL
            if _is_data_ct and _is_sensitive_path and severity not in ("CRITICAL",):
                severity = "CRITICAL"

            size = int(resp.headers.get('Content-Length', len(chunk)))
            return {
                "path": path, "full_url": full_url,
                "label": label, "severity": severity,
                "status": 200, "protected": False, "size": size,
                "content_type": ct[:60],
            }

        elif status == 403 and severity in ("CRITICAL","HIGH"):
            resp.close()
            # Cloudflare 403 = file might exist but CF blocks it
            cf = 'cloudflare' in resp.headers.get('Server','').lower() or\
                 'cf-ray' in resp.headers
            note = " (CF-blocked)" if cf else ""
            return {
                "path": path, "full_url": full_url,
                "label": label + note, "severity": "MEDIUM",
                "status": 403, "protected": True, "size": 0,
            }

        elif status in (301,302,307,308):
            loc = resp.headers.get('Location','')
            resp.close()
            if severity in ("HIGH","MEDIUM","LOW") and any(
                k in loc for k in ('login','auth','signin','session')
            ):
                return {
                    "path": path, "full_url": full_url,
                    "label": label + " (→ login)",
                    "severity": severity, "status": status,
                    "protected": True, "size": 0,
                }

        else:
            try: resp.close()
            except: pass

    except Exception:
        try: resp.close()
        except: pass

    return None


def _verify_subdomain_real(sub_url: str) -> bool:
    """
    A subdomain is 'real' only if:
    1. DNS resolves OK
    2. HTTP responds (any code)
    3. It has DIFFERENT content than a random path on SAME subdomain
       (i.e. not a Cloudflare/nginx catch-all that mirrors base domain)
    """
    try:
        hostname = urlparse(sub_url).hostname
        socket.gethostbyname(hostname)   # DNS must resolve
    except socket.gaierror:
        return False  # NXDOMAIN = not real

    # Check if it returns anything
    try:
        r = requests.get(sub_url, headers=_get_headers(), timeout=5,
                         proxies=proxy_manager.get_proxy(), allow_redirects=True, verify=False, stream=True)
        r.close()
        code = r.status_code
        if code >= 500:
            return False
    except Exception:
        return False

    # Verify it's NOT a catch-all mirror of the base domain
    is_catchall, _, _ = _detect_catchall(sub_url)
    # Even catch-all subdomains can be real services — just note it
    # We still include them but mark behavior
    return True


def _scan_target_sync(
    target_url: str, delay_per_req: float = 0.3
) -> tuple:
    """
    Scan one URL with catch-all detection and delays.
    v18 improvements:
      • Shared requests.Session per scan (TCP connection reuse, ~30% faster)
      • baseline_body passed to _probe_one for difflib similarity check
      • _detect_catchall now returns 4-tuple (unpack safely)
    """
    exposed   = []
    protected = []

    # Detect catch-all first — v18 returns 4-tuple
    _catchall_result = _detect_catchall(target_url)
    if len(_catchall_result) == 4:
        catchall, baseline_hash, baseline_len, baseline_body = _catchall_result
    else:
        catchall, baseline_hash, baseline_len = _catchall_result
        baseline_body = b''

    # Shared session — one TCP handshake per host, reused across all probes
    _session = requests.Session()
    _session.headers.update(_get_headers())
    _session.proxies = proxy_manager.get_proxy() or {}
    _session.verify  = False

    with concurrent.futures.ThreadPoolExecutor(max_workers=6) as ex:
        fmap = {
            ex.submit(
                _probe_one, target_url, path, label, sev,
                catchall, baseline_hash, baseline_len,
                delay_per_req * (i % 5),   # stagger 0/0.3/0.6/0.9/1.2s
                baseline_body,
                _session,
            ): (path, label, sev)
            for i, (path, label, sev) in enumerate(_VULN_PATHS)
        }
        for fut in concurrent.futures.as_completed(fmap, timeout=150):
            try:
                f = fut.result(timeout=18)
                if f:
                    (protected if f["protected"] else exposed).append(f)
            except Exception:
                pass

    _session.close()
    exposed.sort(key=lambda x: _SEV_ORDER.get(x["severity"],9))
    protected.sort(key=lambda x: _SEV_ORDER.get(x["severity"],9))
    return exposed, protected, catchall


def _discover_subdomains_sync(base_url: str, progress_q: list) -> list:
    """
    Discover live subdomains — with real verification (not catch-all mirrors).
    """
    parsed = urlparse(base_url)
    scheme = parsed.scheme
    parts  = parsed.hostname.split('.')
    root   = '.'.join(parts[-2:]) if len(parts) > 2 else parsed.hostname

    progress_q.append(
        f"📡 Subdomain discovery...\n"
        f"Testing `{len(_COMMON_SUBDOMAINS)}` common names on `{escape_md(root)}`"
    )

    live = []

    def check_sub(sub):
        url = f"{scheme}://{sub}.{root}"
        if _verify_subdomain_real(url):
            return url
        return None

    with concurrent.futures.ThreadPoolExecutor(max_workers=10) as ex:
        futures = {ex.submit(check_sub, sub): sub for sub in _COMMON_SUBDOMAINS}
        for fut in concurrent.futures.as_completed(futures, timeout=40):
            try:
                result = fut.result(timeout=8)
                if result:
                    live.append(result)
            except Exception:
                pass

    return live


def _vuln_scan_sync(url: str, progress_q: list, skip_subs: bool = False) -> dict:
    """Improved orchestrator — parallel targets + CORS + open redirect."""
    is_cloudflare = False
    results = {
        "url": url, "findings": [],
        "missing_headers": [], "clickjacking": False,
        "https": url.startswith("https://"),
        "server": "Unknown", "subdomains_found": [],
        "total_scanned": 0, "errors": 0,
        "cloudflare": False,
        "cors": {}, "open_redirects": [],
    }

    # ── Baseline headers ──────────────────────────
    progress_q.append("🔍 Checking security headers + CORS...")
    try:
        r0 = requests.get(
            url, timeout=10, headers=_get_headers(),
            proxies=proxy_manager.get_proxy(),
            allow_redirects=True, verify=False
        )
        hdrs = dict(r0.headers)
        srv  = hdrs.get("Server", "Unknown")
        results["server"] = srv[:60]
        is_cloudflare = "cloudflare" in srv.lower() or "cf-ray" in hdrs
        results["cloudflare"] = is_cloudflare

        for hdr, (name, sev) in _SEC_HEADERS.items():
            if hdr not in hdrs:
                results["missing_headers"].append((name, hdr, sev))
        if srv and any(c.isdigit() for c in srv):
            results["missing_headers"].append(
                ("Server version leak", f"Server: {srv[:50]}", "LOW"))
        xpb = hdrs.get("X-Powered-By", "")
        if xpb:
            results["missing_headers"].append(
                ("Tech disclosure", f"X-Powered-By: {xpb[:40]}", "LOW"))
        has_xfo = "X-Frame-Options" in hdrs
        has_fa  = "frame-ancestors" in hdrs.get("Content-Security-Policy", "")
        results["clickjacking"] = not has_xfo and not has_fa
    except Exception:
        results["errors"] += 1

    # ── CORS check ────────────────────────────────
    cors_result = _check_cors_misconfig(url)
    results["cors"] = cors_result
    if cors_result["vulnerable"]:
        sev = cors_result["severity"]
        progress_q.append(
            f"🚨 CORS misconfiguration — `{escape_md(sev)}`\n"
            f"ACAO: `{cors_result['acao']}`\n"
            f"Credentials: `{cors_result.get('acac','false')}`"
        )

    # ── Open redirect ─────────────────────────────
    progress_q.append("🔀 Testing open redirect payloads...")
    results["open_redirects"] = _check_open_redirect(url)
    if results["open_redirects"]:
        progress_q.append(
            f"🟠 Open redirect found — `{len(results['open_redirects'])}` params vulnerable"
        )

    req_delay   = 0.8 if is_cloudflare else 0.2
    if is_cloudflare:
        progress_q.append("☁️ *Cloudflare detected* — slower scan mode...")

    # ── Subdomain discovery ───────────────────────
    if not skip_subs:
        live_subs = _discover_subdomains_sync(url, progress_q)
        results["subdomains_found"] = live_subs
        if live_subs:
            progress_q.append(
                f"✅ *{len(live_subs)} subdomains found:*\n"
                + "\n".join(f"  • `{escape_md(urlparse(s).netloc)}`" for s in live_subs[:8])
            )
        else:
            progress_q.append("📭 No live subdomains found")
    else:
        progress_q.append("⏭️ Subdomain scan skipped")

    # ── Parallel target scan ──────────────────────
    all_targets = [url] + results["subdomains_found"]
    progress_q.append(
        f"🔍 Scanning `{len(all_targets)}` target(s) in parallel..."
    )

    def _scan_one(target):
        exposed, protected, catchall = _scan_target_sync(target, req_delay)
        return {
            "target":    target,
            "netloc":    urlparse(target).netloc,
            "exposed":   exposed,
            "protected": protected,
            "catchall":  catchall,
        }

    with concurrent.futures.ThreadPoolExecutor(max_workers=min(len(all_targets), 6)) as ex:
        futures = {ex.submit(_scan_one, t): t for t in all_targets}
        for fut in concurrent.futures.as_completed(futures, timeout=180):
            try:
                r = fut.result(timeout=30)
                results["total_scanned"] += len(_VULN_PATHS)
                if r["exposed"] or r["protected"]:
                    results["findings"].append(r)
                netloc = r["netloc"]
                exp_cnt = len(r["exposed"])
                if exp_cnt:
                    progress_q.append(f"🚨 `{escape_md(netloc)}` — `{escape_md(exp_cnt)}` exposed paths found")
            except Exception:
                results["errors"] += 1

    return results


# ── Also patch _format_vuln_report to show CORS + redirect ──────────
def _format_vuln_report(r: dict) -> str:
    domain = urlparse(r["url"]).netloc
    lines  = []

    total_exp = sum(len(f["exposed"]) for f in r["findings"])
    all_sevs  = [fi["severity"] for f in r["findings"] for fi in f["exposed"]]

    cors_vuln = r.get("cors", {}).get("vulnerable", False)
    cors_sev  = r.get("cors", {}).get("severity", "")
    redirects = r.get("open_redirects", [])

    if "CRITICAL" in all_sevs or cors_sev == "CRITICAL": overall = "🔴 CRITICAL RISK"
    elif "HIGH" in all_sevs or redirects or cors_sev == "HIGH": overall = "🟠 HIGH RISK"
    elif "MEDIUM" in all_sevs or r["clickjacking"]: overall = "🟡 MEDIUM RISK"
    elif r["missing_headers"]: overall = "🔵 LOW RISK"
    else: overall = "✅ CLEAN"

    cf_badge = " ☁️ Cloudflare" if r.get("cloudflare") else ""
    lines += [
        "🛡️ *Vulnerability Scan Report*",
        f"🌐 `{escape_md(domain)}`{cf_badge}",
        f"📊 Risk: *{overall}*",
        f"🔍 Paths: `{r['total_scanned']}` | Issues: `{escape_md(total_exp)}`",
        f"📡 Subdomains: `{len(r['subdomains_found'])}`",
        f"🖥️ Server: `{r['server']}`",
        "",
    ]

    # CORS result
    lines.append("*🌐 CORS Policy:*")
    if cors_vuln:
        sev = r["cors"]["severity"]
        em  = "🔴" if sev == "CRITICAL" else "🟠"
        lines.append(f"  {em} `{escape_md(sev)}` — {r['cors']['note']}")
        lines.append(f"  ACAO: `{r['cors']['acao']}`")
    else:
        lines.append("  ✅ No origin reflection")
    lines.append("")

    # Open redirect
    if redirects:
        lines.append(f"*🔀 Open Redirect:* `{len(redirects)}` params vulnerable")
        for rd in redirects[:3]:
            lines.append(f"  🟠 `?{rd['param']}=` → `{rd['location'][:60]}`")
        lines.append("")

    # Subdomains
    if r["subdomains_found"]:
        lines.append("*📡 Live Subdomains:*")
        for s in r["subdomains_found"]:
            lines.append(f"  • {s}")
        lines.append("")

    lines.append("*🔐 HTTPS:*")
    lines.append("  ✅ HTTPS enabled" if r["https"] else "  🔴 HTTP only — no encryption!")
    lines.append("")

    if r["findings"]:
        for f in r["findings"]:
            if f["exposed"]:
                lines.append(f"*🚨 Exposed — `{f['netloc']}`:*")
                for fi in f["exposed"]:
                    em   = _SEV_EMOJI.get(fi["severity"], "⚪")
                    lines.append(f"  {em} `{fi['severity']}` — {fi['label']} `[{fi['status']}]`")
                    lines.append(f"  🔗 {fi['full_url']}")
                lines.append("")
            if f["protected"]:
                lines.append(f"*⚠️ Gated (401/403) — `{f['netloc']}`:*")
                for fi in f["protected"][:5]:
                    em = _SEV_EMOJI.get(fi["severity"], "⚪")
                    lines.append(f"  {em} {fi['label']}")
                    lines.append(f"  🔗 {fi['full_url']}")
                lines.append("")
    else:
        lines += ["*✅ No exposed files found*", ""]

    lines.append("*🖼️ Clickjacking:*")
    if r["clickjacking"]:
        lines.append("  🟠 Vulnerable — no X-Frame-Options / frame-ancestors")
    else:
        lines.append("  ✅ Protected")
    lines.append("")

    if r["missing_headers"]:
        lines.append("*📋 Security Header Issues:*")
        for name, hdr, sev in r["missing_headers"][:8]:
            em = _SEV_EMOJI.get(sev, "⚪")
            if "leak" in name.lower() or "disclosure" in name.lower():
                lines.append(f"  {em} {name}: `{escape_md(hdr)}`")
            else:
                lines.append(f"  {em} Missing *{name}*")
        lines.append("")

    lines += [
        "━━━━━━━━━━━━━━━━━━",
        "⚠️ _Passive scan only — no exploitation_",
    ]
    return "\n".join(lines)


