    "internal","intranet","corp","corporate","private","secure","ssl",
    "login","auth","sso","oauth","id","identity","account","accounts",
    "db","database","mysql","postgres","redis","mongo","memcache","cache",
    "backup","old","legacy","v1","v2","v3","new","next","preview",
