def _pay_gateway_profile(findings: list, all_texts: list) -> dict:
    """
    Analyze payment findings + JS source to build a gateway security profile.
    Returns a dict with mode, methods, 3ds_status, pci_risk.
    """
    profile = {
        "gateways":   [],
        "live_keys":  [],
        "test_keys":  [],
        "unknown_mode": [],
        "methods":    [],
        "threeds":    [],
        "pci_risks":  [],
    }

    # ── Key mode detection ────────────────────────────────────────────────────
    for f in findings:
        val = f.get("value", "")
        gw  = f.get("type", "")
        matched = False
        for pat, gw_name, is_live, note in _PAY_KEY_PREFIX_MAP:
            if re.match(pat, val, re.I):
                entry = {"gateway": gw_name, "key_preview": val, "note": note}
                if is_live is True:
                    profile["live_keys"].append(entry)
                elif is_live is False:
                    profile["test_keys"].append(entry)
                else:
                    profile["unknown_mode"].append(entry)
                if gw_name not in profile["gateways"]:
                    profile["gateways"].append(gw_name)
                matched = True
                break
        if not matched and gw and gw not in profile["gateways"]:
            profile["gateways"].append(gw)

    # ── Combine all JS+HTML text for signal detection ─────────────────────────
    combined = "\n".join(text for text, _ in all_texts)

    # ── Payment method detection ──────────────────────────────────────────────
    for method_name, patterns in _PAY_METHOD_SIGNALS.items():
        for p in patterns:
            if re.search(p, combined, re.I):
                if method_name not in profile["methods"]:
                    profile["methods"].append(method_name)
                break

    # ── 3DS / SCA detection ───────────────────────────────────────────────────
    for signal_name, patterns in _3DS_SIGNALS.items():
        for p in patterns:
            if re.search(p, combined, re.I):
                if signal_name not in profile["threeds"]:
                    profile["threeds"].append(signal_name)
                break

    # ── PCI risk scan ─────────────────────────────────────────────────────────
    for pat, note in _PCI_RISK_SIGNALS:
        if re.search(pat, combined, re.I):
            if note not in profile["pci_risks"]:
                profile["pci_risks"].append(note)

    return profile


def _format_pay_gateway_profile(profile: dict) -> list:
    """Render gateway profile as Telegram message lines."""
    lines = ["", "💳 *Payment Gateway Profile*", "━━━━━━━━━━━━━━━━━━━━"]

    # Gateways detected
    if profile["gateways"]:
        lines.append(f"🏦 *Gateways:* {', '.join(profile['gateways'])}")

    # Key mode summary
    live_count = len(profile["live_keys"])
    test_count = len(profile["test_keys"])
    if live_count and test_count:
        lines.append(f"⚠️ *Mixed mode:* `{live_count}` live + `{test_count}` test keys")
    elif live_count:
        lines.append(f"🔴 *Mode: LIVE* — `{live_count}` live key(s) detected")
    elif test_count:
        lines.append(f"🟢 *Mode: TEST* — `{test_count}` test key(s) only")

    for e in profile["live_keys"][:3]:
        lines.append(f"  {e['note']} `{e['key_preview']}`")
    for e in profile["test_keys"][:2]:
        lines.append(f"  {e['note']}")

    # Payment methods
    if profile["methods"]:
        lines.append(f"💰 *Payment Methods:* {', '.join(profile['methods'])}")

    # 3DS status
    if profile["threeds"]:
        lines.append("🔐 *3DS / SCA Status:*")
        for s in profile["threeds"]:
            icon = "✅" if "enforce" in s.lower() or "sca" in s.lower() else "⚠️"
            lines.append(f"  {icon} {s}")

    # PCI risk
    if profile["pci_risks"]:
        lines.append("🏷️ *PCI Scope:*")
        for r in profile["pci_risks"][:4]:
            lines.append(f"  {r}")

    if not any([profile["live_keys"], profile["test_keys"],
                profile["methods"], profile["threeds"], profile["pci_risks"]]):
        lines.append("⚪ No gateway configuration signals detected in JS source")

    return lines


def _extract_sitekeys_from_data(html: str, all_js: dict, live_result: dict, base_url: str = "") -> list:
    """
    Reuse existing scan data (HTML + JS bundles + live network stream) to extract
    captcha sitekeys — including API response bodies, request URLs, and response headers.
    Used by /keydump and /paykeys to capture sitekey API responses without extra fetches.

    Returns list of finding dicts: {type, site_key, source, page_url, confidence, action?}
    """
    findings  = []
    seen_keys: set = set()

    # ── 1. Static HTML + JS bundles via existing _extract_captcha_info ────────
    try:
        for f in _extract_captcha_info(html, base_url, all_js):
            sk = f.get("site_key", "")
            if sk and sk not in seen_keys:
                seen_keys.add(sk)
                findings.append(f)
    except Exception:
        pass

    # ── 2. Live network: response bodies, request URLs, response headers ──────
    _SITEKEY_API_PATTERNS = [
        # JSON field — reCAPTCHA v2/v3/Enterprise
        ("reCAPTCHA sitekey (API response)",
         re.compile(r'(?i)["\']siteKey["\']\s*:\s*["\']([6L][A-Za-z0-9_\-]{38})["\']')),
        # JSON field — hCaptcha
        ("hCaptcha sitekey (API response)",
         re.compile(r'(?i)["\']sitekey["\']\s*:\s*["\']([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})["\']')),
        # JSON field — Cloudflare Turnstile
        ("Turnstile sitekey (API response)",
         re.compile(r'(?i)["\']siteKey["\']\s*:\s*["\']([01]x[A-Za-z0-9_\-]{20,60})["\']')),
        # reCAPTCHA URL param ?k= (anchor/bframe/reload calls)
        ("reCAPTCHA sitekey (API URL param)",
         re.compile(r'google\.com/recaptcha/(?:api2|enterprise)/[^\s"\']*[?&]k=([0-9A-Za-z_\-]{20,60})')),
        # reCAPTCHA render= in script src URL
        ("reCAPTCHA v3 sitekey (render param)",
         re.compile(r'recaptcha/(?:api|enterprise)\.js[^\s"\']*[?&]render=([0-9A-Za-z_\-]{20,60})')),
        # hCaptcha URL param ?sitekey= or ?s=
        ("hCaptcha sitekey (API URL param)",
         re.compile(r'hcaptcha\.com/[^\s"\']*[?&](?:sitekey|s)=([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})')),
        # Turnstile URL param
        ("Turnstile sitekey (API URL param)",
         re.compile(r'challenges\.cloudflare\.com/[^\s"\']*[?&](?:sitekey|k)=([01]x[A-Za-z0-9_\-]{20,60})')),
        # FunCaptcha / Arkose Labs public key from API
        ("FunCaptcha public_key (API response)",
         re.compile(r'(?i)["\'](?:public_key|data-pkey)["\'\s]*[=:]\s*["\']([A-F0-9]{8}-[A-F0-9]{4}-[A-F0-9]{4}-[A-F0-9]{4}-[A-F0-9]{12})["\']')),
        # Response header: x-captcha-key / x-recaptcha-key / x-hcaptcha-key
        ("Captcha key (response header)",
         re.compile(r'(?i)x-(?:captcha|recaptcha|hcaptcha)-(?:key|sitekey):\s*([A-Za-z0-9_\-]{20,})')),
        # Generic sitekey in any JSON body
        ("Captcha sitekey (JSON generic)",
         re.compile(r'(?i)["\'](?:site_key|sitekey|captcha_key|captcha_site_key)["\'\s]*:\s*["\']([A-Za-z0-9_\-]{20,80})["\']')),
    ]

    for req in live_result.get("live_requests", []):
        req_url  = req.get("url", "") or ""
        body     = req.get("body", "") or req.get("response_body", "") or ""
        headers  = req.get("headers", {}) or {}

        # Build header string for header-pattern scanning
        header_str = "\n".join(f"{k}: {v}" for k, v in headers.items())

        for scan_text, src_label in [
            (body,       f"API response ← {req_url[:70]}"),
            (req_url,    f"API request URL: {req_url[:100]}"),
            (header_str, f"Response header ← {req_url[:60]}"),
        ]:
            if not scan_text:
                continue
            for ktype, pat in _SITEKEY_API_PATTERNS:
                for m in pat.finditer(scan_text):
                    val = m.group(1).strip()
                    if not val or len(val) < 8 or val in seen_keys:
                        continue
                    seen_keys.add(val)
                    findings.append({
                        "type":       ktype,
                        "site_key":   val,
                        "source":     src_label,
                        "page_url":   base_url,
                        "confidence": "CONFIRMED ✅",
                    })

    return findings


def _format_sitekey_section(sitekeys: list, max_items: int = 10) -> list:
    """
    Format sitekey findings into Telegram-ready Markdown lines.
    Includes JSON solver params block for each entry.
    """
    if not sitekeys:
        return []

    _SK_TYPE_ICON = {
        "reCAPTCHA": "🔵",
        "hCaptcha":  "🟡",
        "Turnstile": "🟠",
        "FunCaptcha":"🔴",
        "GeeTest":   "🟢",
        "Captcha":   "🔑",
    }

    lines = [
        "",
        "🔑 *Captcha Sitekeys (API Response Capture)*",
        "━━━━━━━━━━━━━━━━━━━━",
    ]

    for i, f in enumerate(sitekeys[:max_items], 1):
        cap_type = f.get("type", "")
        sk       = (f.get("site_key") or f.get("value") or "").replace("`", "'")
        conf     = f.get("confidence", "")
        src      = f.get("source", "")[:70]
        action   = f.get("action", "")
        page     = f.get("page_url", "")
        enterprise = f.get("enterprise", False)
        min_score  = f.get("min_score", "")

        icon = next((v for k, v in _SK_TYPE_ICON.items() if k in cap_type), "🔑")
        lines.append(f"*{icon} [{i}]* {conf} *{escape_md(cap_type)}*")
        lines.append(f"  🔑 `{sk}`")
        if action:
            lines.append(f"  ⚡ action: `{escape_md(action)}`")
        if enterprise:
            lines.append(f"  🏢 enterprise")
        if min_score:
            lines.append(f"  📊 min\\_score: `{min_score}`")
        if src:
            lines.append(f"  📂 _{escape_md(src)}_")

        # ── JSON solver-params block ──────────────────────────────────────
        sp: dict = {"type": cap_type, "sitekey": sk}
        if page:
            sp["pageurl"] = page[:100]
        if action:
            sp["action"] = action
        if enterprise:
            sp["enterprise"] = 1
        if min_score:
            sp["min_score"] = float(min_score) if min_score else None

        import json as _json_sk
        try:
            sp_str = _json_sk.dumps(sp, indent=2, ensure_ascii=False)
        except Exception:
            sp_str = str(sp)
        lines.append(f"```\n{sp_str}\n```")
        lines.append("")

    return lines


def _paykeys_sync(url: str, progress_cb=None) -> dict:
    data = _extract_run(url, _PAY_JS_EVAL, progress_cb)
    if data.get("error"):
        return {"error": data["error"], "findings": [], "page_url": url}

    if progress_cb: progress_cb("🌐 Dynamic intercept + deep asset fetch...")
    dyn        = _playwright_dynamic_scan(url, "paykeys", progress_cb)
    new_assets = _deep_asset_fetch(url, data.get("network_log", []), progress_cb)
    data       = _merge_dynamic_into_data(data, dyn, new_assets)

    if progress_cb: progress_cb("🔴 Phase 2: real-time network stream intercept...")
    live_result = _stream_intercept_sync(url, progress_cb, extra_patterns=_LIVE_PAY_PATTERNS)

    # BUG FIX 4: If live intercept itself errored, log it but continue with empty result
    # Previously: error went unchecked → downstream calls crashed on missing keys
    if live_result.get("error"):
        if progress_cb:
            progress_cb(f"⚠️ Live intercept error: {live_result['error'][:80]} — continuing with static scan")
        live_result = {
            "live_requests":   [],
            "live_findings":   [],
            "sse_frames":      [],
            "ws_frames":       [],
            "response_bodies": {},
            "page_url":        url,
            "error":           live_result.get("error"),
        }

    # ── v19: extra scan passes ─────────────────────────────────────────────
    html_text = data.get("html", "")

    if progress_cb: progress_cb("🗺️ v19: Scanning source maps...")
    sourcemap_texts = _scan_sourcemaps(url, html_text, progress_cb)

    if progress_cb: progress_cb("⚙️ v19: Scanning service workers...")
    sw_texts = _scan_service_workers(url, html_text, progress_cb)

    if progress_cb: progress_cb("🔗 v19: Crawling payment sub-pages...")
    subpage_texts = _scan_payment_subpages(url, progress_cb)

    if progress_cb: progress_cb("🔍 v19: Probing GraphQL schema...")
    gql_texts = _scan_graphql_payment(url, progress_cb)

    findings = []
    seen = set()

    def _add(t, v, src, confidence=None, verified=None):
        v = v.strip()
        d = t + ":" + v[:80]
        if d not in seen and len(v) >= 6:
            if not _validate_payment_key(t, v):
                return
            seen.add(d)
            entry = {"type": t, "value": v, "source": src,
                     "env": _detect_env(t, v)}
            if confidence:
                entry["confidence"] = confidence
            if verified is not None:
                entry["verified"] = verified
            findings.append(entry)

    if progress_cb: progress_cb("🔍 Scanning HTML + JS + live + source maps + workers...")

    # ── 1. HTML + JS bundles (live bodies already merged via _gather_all_text_v2) ──
    # FIX P3: _gather_all_text_v2 includes live_result bodies — don't re-scan separately
    _all_texts_seen: set = set()
    for text, label in _gather_all_text_v2(data, live_result):
        text_id = label[:60]
        if text_id in _all_texts_seen:
            continue       # skip duplicates (live bodies may appear twice)
        _all_texts_seen.add(text_id)
        for key_type, pat in _PAY_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label)
        # Deobfuscation pass: decode atob/hex/join/fromCharCode hidden keys
        _deob = _deobfuscate_text(text)
        if _deob:
            for key_type, pat in _PAY_PATTERNS:
                for m in pat.finditer(_deob):
                    val = m.group(1) if m.lastindex else m.group(0)
                    _add(key_type, val.strip(), label + " [deobfuscated]")

    # ── 2. Source map texts ──
    for text, label in sourcemap_texts:
        for key_type, pat in _PAY_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label, confidence="HIGH_SOURCEMAP")

    # ── 3. Service worker texts ──
    for text, label in sw_texts:
        for key_type, pat in _PAY_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label, confidence="HIGH_SW")

    # ── 4. Sub-page texts ──
    for text, label in subpage_texts:
        for key_type, pat in _PAY_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label, confidence="SUBPAGE")

    # ── 5. GraphQL schema texts ──
    for text, label in gql_texts:
        for key_type, pat in _PAY_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label, confidence="GRAPHQL")

    # ── 6. Window globals ──
    if progress_cb: progress_cb("🔍 Scanning window globals + DOM...")
    for k, v in (data.get("dom_result") or {}).items():
        s = str(v)
        for key_type, pat in _PAY_PATTERNS:
            for mm in pat.finditer(s):
                val = mm.group(1) if mm.lastindex else mm.group(0)
                _add(key_type, val, f"window/{k}")

    # ── 7. iframe URLs ──
    if progress_cb: progress_cb("🔍 Scanning iframe payment URLs...")
    dom = data.get("dom_result") or {}
    iframe_json = dom.get("__iframes__", "[]")
    try:
        iframes = json.loads(iframe_json) if isinstance(iframe_json, str) else []
        for entry in iframes:
            src = entry.split("||")[0] if "||" in entry else entry
            for key_type, pat in _PAY_PATTERNS:
                for mm in pat.finditer(src):
                    val = mm.group(1) if mm.lastindex else mm.group(0)
                    _add(key_type, val, f"iframe src: {src[:80]}")
    except Exception:
        pass

    # ── 8. Framework env objects ──
    for env_key in ("__NEXT_DATA__","__NUXT__","__ENV__","_env_",
                    "give_global_vars","wc_stripe_params","wc_square_params",
                    "wc_razorpay_params","wc_paystack_params"):
        env_str = str((data.get("dom_result") or {}).get(env_key, ""))
        if env_str and len(env_str) > 10:
            for key_type, pat in _PAY_PATTERNS:
                for mm in pat.finditer(env_str):
                    val = mm.group(1) if mm.lastindex else mm.group(0)
                    _add(key_type, val, f"{env_key} (framework config)")

    # ── 9. Playwright dynamic interception ──
    dyn_pw = {"stripe_keys":[],"paypal_client_ids":[],"paystack_hits":[],"flutterwave_hits":[],"_engine":"none"}
    if PLAYWRIGHT_OK:
        if progress_cb: progress_cb("🌐 Dynamic payment interception (Playwright)...")
        try:
            dyn_pw = _paykeys_playwright(url, progress_cb)
        except Exception as _dyn_err:
            logger.debug("_paykeys_playwright error: %s", _dyn_err)

    for sk in dyn_pw.get("stripe_keys", []):
        _add("Stripe Publishable Key (dynamic)", sk["value"], sk.get("source","Playwright"))
    for pp in dyn_pw.get("paypal_client_ids", []):
        _add("PayPal Client ID (SDK URL)", pp["value"], pp.get("source","Playwright"))
    for ps in dyn_pw.get("paystack_hits", []):
        _add("Paystack Public Key (dynamic)", ps.get("value","") or ps.get("key",""), ps.get("source","Playwright"))
    for fw in dyn_pw.get("flutterwave_hits", []):
        _add("Flutterwave Public Key (dynamic)", fw.get("value","") or fw.get("public_key",""), fw.get("source","Playwright"))
    # ENH9: client_secret from XHR/fetch hook — PaymentIntent secret (very high value)
    for cs in dyn_pw.get("client_secrets", []):
        v = cs.get("value","")
        if v:
            _add("Stripe PaymentIntent client_secret 🔴", v, cs.get("source","Playwright XHR hook"),
                 confidence="CONFIRMED")

    # ── 10. v19: Full Stripe key verification with account info ────────────────
    stripe_findings = [f for f in findings if "Stripe" in f["type"] and
                       re.match(r'^(pk|sk)_(live|test)_', f.get("value",""))]
    if stripe_findings and progress_cb:
        progress_cb(f"✅ v19: Verifying {len(stripe_findings)} Stripe key(s) — fetching account info...")
    for f in stripe_findings[:3]:
        val = f.get("value", "")
        try:
            if val.startswith("sk_"):
                vr = _verify_stripe(val)
            else:
                vr = _verify_stripe_publishable(val)
            f["verified"]      = "VALID" if "✅" in vr.get("status","") else "INVALID"
            f["verify_status"] = vr.get("status", "")
            f["account_info"]  = vr.get("account_info", {})
        except Exception:
            pass

    # ── ENH: Deep JSON / Header / JWT / WebSocket / GraphQL / Storage ─────────
    if progress_cb:
        progress_cb("🔬 ENH: Deep JSON + Response Header + JWT + WS scan...")
    _pay_seen: set = {f["type"] + ":" + f["value"][:80] for f in findings}
    _enh_net  = data.get("network_log", [])
    for ef in _deep_json_response_scan(_enh_net, _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _response_header_cookie_scan(_enh_net, _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _jwt_payload_scan(_gather_all_text_v2(data, live_result), _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _websocket_deep_scan(live_result, _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _graphql_response_deep_scan(_enh_net, _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _browser_storage_scan(data.get("dom_result") or {}, _PAY_PATTERNS, _pay_seen):
        _add(ef["type"], ef["value"], ef["source"])

    # ── Gateway Profile (unique to v18) ───────────────────────────────────────
    all_texts_for_profile = _gather_all_text_v2(data, live_result)
    gateway_profile = _pay_gateway_profile(findings, all_texts_for_profile)

    # ── SDK Load Detection — detect SDKs even when no keys found ─────────────
    combined_for_sdk = "\n".join(t for t, _ in all_texts_for_profile) + "\n" + html_text
    sdk_hints = []
    for sdk_name, sdk_pat in _PAY_SDK_LOAD_SIGNALS:
        if sdk_pat.search(combined_for_sdk):
            sdk_hints.append(sdk_name)
    # Also scan raw HTML <script src> tags
    _html_for_sdk = data.get("html", "")
    for sdk_name, sdk_pat in _PAY_SDK_LOAD_SIGNALS:
        if sdk_name not in sdk_hints and sdk_pat.search(_html_for_sdk):
            sdk_hints.append(sdk_name)

    # ── 3DS / SCA Verification (v19 new) ────────────────────────────────────
    combined_js_for_3ds = "\n".join(t for t, _ in all_texts_for_profile)
    tds_result = None
    if stripe_findings:
        pk = stripe_findings[0]["value"]
        if progress_cb: progress_cb("🔐 Verifying 3DS/SCA enforcement via Stripe API...")
        try:
            tds_result = _verify_3ds_stripe(pk, combined_js_for_3ds)
        except Exception as _tds_err:
            logger.debug("3DS verify error: %s", _tds_err)

    # ── Sitekey extraction (Captcha API response capture) ─────────────────────
    if progress_cb: progress_cb("🔑 Extracting captcha sitekeys from API responses...")
    try:
        _pk_html   = data.get("html", "")
        _pk_all_js = {
            e["url"]: e.get("response_body", "")
            for e in data.get("network_log", [])
            if ".js" in e.get("url", "")
        }
        sitekeys = _extract_sitekeys_from_data(_pk_html, _pk_all_js, live_result, url)
    except Exception as _sk_e:
        logger.debug("paykeys sitekey extraction error: %s", _sk_e)
        sitekeys = []

    return {
        "error":    None,
        "findings": findings,
        "page_url": data["page_url"],
        "requests": len(data.get("network_log", [])),
        "js_count": sum(1 for e in data.get("network_log",[]) if ".js" in e["url"]),
        "dynamic":  dyn_pw,
        "live_result": live_result,
        "gateway_profile": gateway_profile,
        "tds_result":     tds_result,
        "sitekeys":  sitekeys,
        "sdk_hints": sdk_hints,
        "extra_scans": {
            "sourcemaps": len(sourcemap_texts),
            "service_workers": len(sw_texts),
            "subpages": len(subpage_texts),
            "graphql": len(gql_texts),
        },
    }

def _format_live_intercept_section(live_result: dict, findings: list) -> list:
    """
    Render a dedicated 🔴 Live Intercept block for the paykeys report.
    Shows intercepted request/SSE/WS counts, live-only findings,
    payment endpoint URLs, auth headers captured.
    """
    lines = []
    live_reqs  = live_result.get("live_requests", [])
    sse_frames = live_result.get("sse_frames",    [])
    ws_frames  = live_result.get("ws_frames",     [])
    live_finds = live_result.get("live_findings", [])
    err        = live_result.get("error")

    if not live_reqs and not live_finds and not sse_frames and not ws_frames:
        return []

    lines += ["", "🔴 *Live Network Intercept*", "━━━━━━━━━━━━━━━━━━━━"]

    req_c = len(live_reqs)
    sse_c = len(sse_frames)
    ws_c  = len(ws_frames)
    lf_c  = len(live_finds)
    lines.append(
        f"📡 Requests: `{req_c}` | SSE: `{sse_c}` | WS: `{ws_c}` | "
        f"🔍 Secrets: `{lf_c}`"
    )
    if err:
        lines.append(f"⚠️ _{escape_md(str(err)[:80])}_")

    # Pure live-only secrets (not in static scan)
    static_vals = {f.get("value","")[:60] for f in findings}
    live_only   = [lf for lf in live_finds
                   if lf.get("value","")[:60] not in static_vals]
    if live_only:
        lines.append("")
        lines.append(f"🔑 *Live-only secrets — {len(live_only)} found:*")
        for i, lf in enumerate(live_only[:15], 1):
            ltype = escape_md(lf.get("type", "unknown"))
            lval  = lf.get("value", "")[:80].replace("`", "'")
            lsrc  = escape_md(lf.get("source", "")[:100])
            conf  = lf.get("confidence", "HIGH")
            badge = "✅" if "CONFIRM" in conf else ("🔴" if "HIGH" in conf else "🟡")
            lines.append(f"  *[{i}]* {badge} `{ltype}`")
            lines.append(f"       🔑 `{lval}`")
            if lsrc:
                lines.append(f"       📂 _{lsrc}_")

    # Payment-relevant intercepted endpoints
    _pay_url_re = re.compile(
        r"(?i)(stripe|paypal|braintree|square|razorpay|adyen|mollie|checkout"
        r"|klarna|paddle|paystack|flutterwave|2c2p|midtrans|xendit|payment"
        r"|billing|cart|pay|wallet|kbzpay|ayapay|wavemoney)", re.I
    )
    pay_ep, seen_ep = [], set()
    for req in live_reqs:
        u = req.get("url", "")
        method = req.get("method", req.get("type", "GET")).upper()
        if _pay_url_re.search(u) and u[:80] not in seen_ep:
            seen_ep.add(u[:80])
            pay_ep.append((method, u))
    if pay_ep:
        lines.append("")
        lines.append(f"🌐 *Intercepted Payment Endpoints ({len(pay_ep)}):*")
        for method, ep_url in pay_ep[:10]:
            short = ep_url if len(ep_url) <= 85 else "..." + ep_url[-80:]
            lines.append(f"  `{method}` `{escape_md(short)}`")

    # Auth headers captured
    auth_hits = []
    for req in live_reqs:
        for hn, hv in req.get("headers", {}).items():
            if hn.lower() in ("authorization", "x-api-key", "x-auth-token",
                              "x-stripe-key", "stripe-signature"):
                short_v = hv[:40] + "…" if len(hv) > 40 else hv
                auth_hits.append(f"`{hn}`: `{escape_md(short_v)}`")
    if auth_hits:
        lines.append("")
        lines.append(f"🔐 *Auth Headers Intercepted ({len(auth_hits)}):*")
        for ah in auth_hits[:5]:
            lines.append(f"  {ah}")

    # SSE stream summary
    if sse_frames:
        sse_urls = list(dict.fromkeys(
            f.get("url","")[:70] for f in sse_frames if f.get("url")
        ))
        lines.append("")
        lines.append(f"📡 *SSE Streams ({sse_c} frames):*")
        for su in sse_urls[:3]:
            lines.append(f"  `{escape_md(su)}`")

    # WebSocket summary
    if ws_frames:
        ws_urls = list(dict.fromkeys(
            f.get("url","")[:70] for f in ws_frames if f.get("url")
        ))
        lines.append("")
        lines.append(f"🔌 *WebSocket Frames ({ws_c}):*")
        for wu in ws_urls[:3]:
            lines.append(f"  `{escape_md(wu)}`")

    return lines


async def cmd_paykeys(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/paykeys <url> — Extract payment keys from all major gateways"""
    if not await check_force_join(update, context): return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/paykeys https://example.com`\n\n"
            "💳 *Detects (v19 — 25+ gateways):*\n"
            "  🔵 Stripe · PayPal · Braintree · Square · Razorpay\n"
            "  🟣 Adyen · Klarna · Mollie · Checkout.com · Paddle\n"
            "  🟠 Paystack · Flutterwave · Cashfree · PayU\n"
            "  🟡 Affirm · Afterpay · Sezzle · Coinbase Commerce\n"
            "  🔴 Alipay · WeChat Pay · 2Checkout · Cybersource\n"
            "  ⚙️ WooCommerce keys · Authorize.net · Shopify\n\n"
            "🔍 *Scan layers:*\n"
            "  • HTML + JS bundles + Live network stream\n"
            "  • Source maps (.js.map) — unminified secrets\n"
            "  • Service workers (sw.js)\n"
            "  • Payment sub-pages (/checkout /cart /pay)\n"
            "  • GraphQL schema introspection\n"
            "  • Playwright constructor hooks (runtime intercept)\n"
            "  • Stripe live key API verification ✅\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown')
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith("http"): url = "https://" + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{escape_md(reason)}`", parse_mode='Markdown')
        return

    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"💳 *Payment Key Extractor v19 — `{escape_md(domain)}`*\n\n"
        "⏳ Scanning (25+ gateways + source maps + sub-pages)...",
        parse_mode='Markdown'
    )

    progress_q = []
    async def _prog():
        while True:
            await asyncio.sleep(2)
            if progress_q:
                t = progress_q[-1]; progress_q.clear()
                try:
                    await msg.edit_text(
                        f"💳 *Payment Keys v19 — `{escape_md(domain)}`*\n\n{escape_md(t)}",
                        parse_mode='Markdown'
                    )
                except Exception:
                    pass

    prog = asyncio.create_task(_prog())
    try:
        result = await run_scan(uid, _paykeys_sync, url, lambda t: progress_q.append(t))
    except Exception as e:
        prog.cancel()
        await safe_markdown_reply(msg, f"❌ `{escape_md(str(e))}`")
        return
    finally:
        prog.cancel()

    if result.get("error"):
        await safe_markdown_reply(msg, f"❌ `{escape_md(str(result['error']))}`")
        return

    raw_findings = result["findings"]
    live_result  = result.get("live_result") or {"live_requests":[],"live_findings":[],"sse_frames":[]}
    findings     = _confidence_crossref(raw_findings, live_result)
    page_url     = result["page_url"]
    reqs         = result.get("requests", 0)
    live_reqs    = len(live_result.get("live_requests", []))
    extra        = result.get("extra_scans", {})
    sitekeys     = result.get("sitekeys", [])
    sdk_hints    = result.get("sdk_hints", [])

    confirmed   = [f for f in findings if "CONFIRMED"   in f.get("confidence","")]
    high_live   = [f for f in findings if f.get("confidence","").startswith("HIGH")]
    static_only = [f for f in findings if "STATIC"      in f.get("confidence","")]
    live_keys   = [f for f in findings if f.get("env") == "🔴 LIVE"]

    if not findings:
        # ── No keys found — still show SDK hints + gateway profile + sitekeys ──
        no_key_lines = [
            f"💳 *Payment Key Extractor v19 — `{escape_md(domain)}`*",
            "━━━━━━━━━━━━━━━━━━━━",
            "",
            f"📭 *Payment keys မတွေ့ပါ*",
            f"🌐 `{escape_md(page_url)}`",
            f"📡 Static: `{reqs}` | Live: `{live_reqs}`",
            f"🗺️ Maps: `{extra.get('sourcemaps',0)}` | "
            f"⚙️ SW: `{extra.get('service_workers',0)}` | "
            f"🔗 Pages: `{extra.get('subpages',0)}`",
        ]

        # SDK detection hints — ဘယ် payment SDK ကို load လုပ်ထားသည်
        if sdk_hints:
            no_key_lines.append("")
            no_key_lines.append(f"📦 *Detected Payment SDKs ({len(sdk_hints)}):*")
            for sdk in sdk_hints[:12]:
                no_key_lines.append(f"  • {escape_md(sdk)}")
            no_key_lines.append("")
            no_key_lines.append(
                "⚠️ _SDK detected but keys not exposed client\\-side_\n"
                "_\\(server\\-side only / hosted checkout / tokenization\\)_"
            )
        else:
            no_key_lines.append("")
            no_key_lines.append("📦 _Payment SDKs မတွေ့ပါ — site uses server-side payment flow_")

        # Gateway profile (methods, 3DS, PCI signals)
        gw_profile = result.get("gateway_profile")
        if gw_profile:
            _gp_lines = _format_pay_gateway_profile(gw_profile)
            # Only append if there's something meaningful
            if any(x.strip() and not x.startswith("━") and "No gateway" not in x
                   for x in _gp_lines[2:]):
                no_key_lines += _gp_lines

        # 🔴 Live intercept data (even when no keys extracted)
        live_no_key_section = _format_live_intercept_section(live_result, [])
        if live_no_key_section:
            no_key_lines += live_no_key_section

        # Sitekeys even when no payment keys
        if sitekeys:
            no_key_lines += _format_sitekey_section(sitekeys)

        await safe_markdown_reply(msg, _truncate_safe_md("\n".join(no_key_lines)))
        return

    # ── Build enhanced report ──────────────────────────────────────────────
    lines = [
        f"💳 *Payment Keys — `{escape_md(domain)}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        f"🌐 `{escape_md(page_url[:60])}`",
        f"📡 Static: `{reqs}` | Live: `{live_reqs}` requests",
        f"🗺️ Maps: `{extra.get('sourcemaps',0)}` | ⚙️ SW: `{extra.get('service_workers',0)}` | 🔗 Pages: `{extra.get('subpages',0)}`",
        f"✅ CONFIRMED: `{len(confirmed)}` | 🔴 LIVE keys: `{len(live_keys)}` | 📊 Total: `{len(findings)}`",
        "",
    ]

    # Deduplicated ordering: CONFIRMED → LIVE → STATIC
    seen_vals = set()
    ordered   = []
    for f, badge in (
        [(f, "✅ CONFIRMED") for f in confirmed] +
        [(f, "🔴 LIVE")      for f in high_live if f not in confirmed] +
        [(f, "⚠️ STATIC")   for f in static_only]
    ):
        k = f.get("value", "")
        if k not in seen_vals:
            seen_vals.add(k)
            ordered.append((f, badge))

    for i, (f, badge) in enumerate(ordered[:50], 1):
        val     = f.get("value", "")
        env     = f.get("env", _detect_env(f["type"], val))
        vfy     = f.get("verified", "")
        vfy_tag = " ✔️" if vfy == "VALID" else (" ✖️" if vfy == "INVALID" else "")
        conf    = f.get("confidence", "")
        src_tag = ""
        if "SOURCEMAP" in conf: src_tag = " 🗺️"
        elif "SW"      in conf: src_tag = " ⚙️"
        elif "SUBPAGE" in conf: src_tag = " 🔗"
        elif "GRAPHQL" in conf: src_tag = " 📐"

        env_warn = " ⚠️" if (env == "🔴 LIVE" and "secret" in f.get("type","").lower()) else ""

        lines.append(f"*[{i}]* {badge} {env}{vfy_tag}{src_tag}{env_warn}")
        lines.append(f"  📌 `{escape_md(f['type'])}`")
        _val_safe = val[:80].replace("`", "'")
        lines.append(f"  🔑 `{_val_safe}`")

        # ── Source info — full URL + extract method ───────────────────────────
        src_full = f.get("source", "")
        if src_full:
            lines.append(f"  📂 _{escape_md(src_full[:120])}_")

        # ── Stripe account_info block (auto-verified) ─────────────────────────
        ai = f.get("account_info") or {}
        vs = f.get("verify_status", "")
        if ai and "Stripe" in f.get("type", ""):
            lines.append(f"  ┌ *Stripe Account Info* {vs}")
            if ai.get("business_name"):
                lines.append(f"  │ 🏢 `{escape_md(str(ai['business_name']))}`")
            if ai.get("country"):
                lines.append(f"  │ 🌏 Country: `{ai['country'].upper()}`")
            if ai.get("default_currency"):
                lines.append(f"  │ 💱 Currency: `{ai['default_currency'].upper()}`")
            if ai.get("account_type"):
                lines.append(f"  │ 📋 Type: `{escape_md(str(ai['account_type']))}`")
            if ai.get("charges_enabled") is not None:
                lines.append(f"  │ 💳 Charges: {'✅' if ai['charges_enabled'] else '❌'}")
            if ai.get("payouts_enabled") is not None:
                lines.append(f"  │ 💸 Payouts: {'✅' if ai['payouts_enabled'] else '❌'}")
            if ai.get("email"):
                lines.append(f"  │ 📧 `{escape_md(str(ai['email']))}`")
            if ai.get("account_id"):
                lines.append(f"  │ 🆔 `{escape_md(str(ai['account_id'])[:24])}`")
            lm = ai.get("livemode")
            if lm is not None:
                lines.append(f"  └ 📡 livemode: `{lm}`")
        elif vs:
            lines.append(f"  ✅ `{escape_md(vs)}`")

        lines.append("")

    lines.append("━━━━━━━━━━━━━━━━━━\n⚠️ _Authorized testing only_")

    # ── 🔴 Live Intercept Section (realtime XHR/fetch/SSE/WS findings) ───────
    live_section = _format_live_intercept_section(live_result, findings)
    if live_section:
        lines += live_section

    # ── Gateway Profile block (v18 unique) ─────────────────────────────────
    gw_profile = result.get("gateway_profile")
    if gw_profile:
        lines += _format_pay_gateway_profile(gw_profile)

    # ── 3DS / SCA Verification block ────────────────────────────────────────
    tds_result = result.get("tds_result")
    if tds_result:
        lines.append("")
        lines += _fmt_3ds_result(tds_result)

    # ── Sitekey section (Captcha API response capture) ───────────────────────
    if sitekeys:
        lines += _format_sitekey_section(sitekeys)

    report = "\n".join(lines)

    await safe_markdown_reply(msg, _truncate_safe_md(report))

    # ── Sitekey found but no payment keys — send sitekey-only message ────────
    if sitekeys and not findings:
        sk_only_lines = [
            f"💳 *Payment Key Extractor v19 — `{escape_md(domain)}`*",
            "━━━━━━━━━━━━━━━━━━━━",
            f"🌐 `{escape_md(page_url)}`",
            f"📡 Static: `{reqs}` | Live: `{live_reqs}`",
            "📭 Payment keys မတွေ့ပါ",
        ] + _format_sitekey_section(sitekeys)
        await safe_markdown_reply(msg, _truncate_safe_md("\n".join(sk_only_lines)))
        return

    # ── Cache verifiable keys for inline button ────────────────────────────
    _verifiable_types = {
        "Stripe Secret Key", "Stripe Publishable Key",
        "Razorpay Key ID", "Razorpay Key Secret",
        "Square Access Token", "Square Application ID",
        "PayPal Client ID", "PayPal Secret",
    }
    verifiable = [
        f for f in findings
        if f.get("type","") in _verifiable_types and f.get("value","")
    ]
    if verifiable:
        _paykeys_verify_cache[uid] = {
            "domain":   domain,
            "findings": verifiable,
            "ts":       time.time(),
        }

    # ── Export JSON ────────────────────────────────────────────────────────
    import io as _io
    ts     = datetime.now().strftime("%Y%m%d_%H%M%S")
    safe_d = re.sub(r'[^\w\-]', '_', domain)
    try:
        await context.bot.send_document(
            chat_id=update.effective_chat.id,
            document=_io.BytesIO(json.dumps({
                "domain":                  domain,
                "page_url":                page_url,
                "scanned_at":             datetime.now().isoformat(),
                "bot_version":            "v19",
                "findings":               findings,
                "sitekeys":               sitekeys,
                "sdk_hints":              sdk_hints,
                "live_requests_captured": live_reqs,
                "sse_frames_captured":    len(live_result.get("sse_frames",[])),
                "confirmed":              len(confirmed),
                "live_keys":              len(live_keys),
                "static_only":            len(static_only),
                "extra_scans":            extra,
            }, indent=2, ensure_ascii=False).encode()),
            filename=f"paykeys_{safe_d}_{ts}.json",
            caption=(
                f"💳 Payment Keys v19 — `{escape_md(domain)}`\n"
                f"✅ Confirmed: `{len(confirmed)}` | 🔴 Live: `{len(live_keys)}` | Total: `{len(findings)}`\n"
                f"🔑 Sitekeys: `{len(sitekeys)}`"
            ),
            parse_mode='Markdown'
        )
    except Exception as e:
        logger.warning("paykeys export error: %s", e)

    # ── Inline verify button (only if verifiable keys exist) ───────────────
    if verifiable:
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(
                f"🔍 Verify Keys ({len(verifiable)})",
                callback_data=f"vk_run_{uid}"
            )
        ]])
        await update.effective_message.reply_text(
            f"🔍 *{len(verifiable)} verifiable key(s) တွေ့ပါသည်*\n"
            "Read-only API check စတင်ရန် နှိပ်ပါ",
            reply_markup=kb,
            parse_mode='Markdown'
        )

