# 🤖  /autosolve — Direct sitekey solve via 2captcha / CapSolver
# ══════════════════════════════════════════════════

# Captcha type aliases — user-friendly → internal
_AUTOSOLVE_TYPE_MAP = {
    # reCAPTCHA v2
    "recaptchav2":   "reCAPTCHA v2",
    "recaptcha2":    "reCAPTCHA v2",
    "rv2":           "reCAPTCHA v2",
    "v2":            "reCAPTCHA v2",
    # reCAPTCHA v3
    "recaptchav3":   "reCAPTCHA v3",
    "recaptcha3":    "reCAPTCHA v3",
    "rv3":           "reCAPTCHA v3",
    "v3":            "reCAPTCHA v3",
    # reCAPTCHA Enterprise
    "enterprise":    "reCAPTCHA Enterprise",
    "recaptchaent":  "reCAPTCHA Enterprise",
    # hCaptcha
    "hcaptcha":      "hCaptcha",
    "hcap":          "hCaptcha",
    "h":             "hCaptcha",
    # Cloudflare Turnstile
    "turnstile":     "Cloudflare Turnstile",
    "cf":            "Cloudflare Turnstile",
    "cfts":          "Cloudflare Turnstile",
}


def _parse_autosolve_args(args: list) -> list:
    """
    Parse /autosolve args into list of tasks.

    Accepts 3 formats:
    1. Positional:  type sitekey pageurl [type sitekey pageurl ...]
    2. JSON object: {"type":"reCAPTCHA v2","sitekey":"6Lc...","pageurl":"https://..."}
    3. JSON array:  [{"type":...}, {"type":...}]

    Returns: [{"type": str, "sitekey": str, "pageurl": str, ...}, ...]
    """
    import json as _json

    tasks  = []

    # ── Try JSON parse first (single object or array) ─────────────────────────
    raw_str = " ".join(args).strip()

    # Handle JSON object or array
    if raw_str.startswith("{") or raw_str.startswith("["):
        try:
            parsed = _json.loads(raw_str)
            if isinstance(parsed, dict):
                parsed = [parsed]
            for item in parsed:
                sitekey = (item.get("sitekey") or item.get("site_key") or
                           item.get("key") or "").strip()
                pageurl = (item.get("pageurl") or item.get("page_url") or
                           item.get("url") or "").strip()
                raw_type = (item.get("type") or "").strip()
                cap_type = _AUTOSOLVE_TYPE_MAP.get(raw_type.lower().replace(" ", ""))
                if not cap_type:
                    # Try partial match
                    for alias, full in _AUTOSOLVE_TYPE_MAP.items():
                        if alias in raw_type.lower():
                            cap_type = full
                            break
                if not cap_type:
                    cap_type = raw_type or "reCAPTCHA v2"
                if not pageurl.startswith("http"):
                    pageurl = "https://" + pageurl if pageurl else ""
                if sitekey and pageurl:
                    tasks.append({
                        "type":       cap_type,
                        "sitekey":    sitekey,
                        "pageurl":    pageurl,
                        "action":     item.get("action", ""),
                        "enterprise": int(item.get("enterprise", 0)),
                        "min_score":  float(item.get("min_score", 0) or 0),
                        "invisible":  int(item.get("invisible", 0)),
                        "data_s":     item.get("data-s", ""),
                    })
            return tasks
        except (_json.JSONDecodeError, Exception):
            pass  # Fall through to positional parse

    # ── Positional parse: type sitekey pageurl [type sitekey pageurl ...] ─────
    tokens = list(args)
    i = 0
    while i + 2 < len(tokens):
        raw_type = tokens[i].lower().strip()
        sitekey  = tokens[i + 1].strip()
        pageurl  = tokens[i + 2].strip()
        cap_type = _AUTOSOLVE_TYPE_MAP.get(raw_type)
        if not cap_type:
            i += 1
            continue
        if not pageurl.startswith("http"):
            pageurl = "https://" + pageurl
        tasks.append({
            "type":       cap_type,
            "sitekey":    sitekey,
            "pageurl":    pageurl,
            "action":     "",
            "enterprise": 0,
            "min_score":  0.0,
            "invisible":  0,
            "data_s":     "",
        })
        i += 3
    return tasks


@user_guard
async def cmd_autosolve(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/autosolve <type> <sitekey> <pageurl> — Solve captcha directly"""
    uid = update.effective_user.id

    if not context.args:
        db     = await db_read()
        keys   = db.get("users", {}).get(str(uid), {}).get("api_keys", {})
        cap_st = "✅ Set" if keys.get("capsolver") else "❌ Not set"
        two_st = "✅ Set" if keys.get("2captcha")  else "❌ Not set"
        await update.effective_message.reply_text(
            "🤖 *AutoSolve — Captcha Token Solver*\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "📌 *အသုံးပြုနည်း:*\n"
            "`/autosolve <type> <sitekey> <pageurl>`\n\n"
            "📋 *ဥပမာ:*\n"
            "`/autosolve v2 6Lc4xxxx https://example.com`\n"
            "`/autosolve hcaptcha abc-123 https://example.com`\n"
            "`/autosolve turnstile 0x4A... https://example.com`\n\n"
            "🏷 *Captcha Types:*\n"
            "  `v2`         — reCAPTCHA v2\n"
            "  `v3`         — reCAPTCHA v3\n"
            "  `enterprise` — reCAPTCHA Enterprise\n"
            "  `hcaptcha`   — hCaptcha\n"
            "  `turnstile`  — Cloudflare Turnstile\n\n"
            "💡 _/sitekey ရဲ့ result ထဲက sitekey + pageurl ကို copy ယူပြီး သုံးပါ_\n\n"
            "━━━━━━━━━━━━━━━━━━━━\n"
            f"🟢 CapSolver:  {cap_st}\n"
            f"🔵 2captcha:   {two_st}\n\n"
            "🔑 _Key မရှိသေးရင်: `/setapikey capsolver YOUR\\_KEY`_",
            parse_mode="Markdown"
        )
        return

    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode="Markdown")
        return

    tasks = _parse_autosolve_args(context.args)
    if not tasks:
        await update.effective_message.reply_text(
            "❌ Format: `/autosolve v2 6Lc4xxx https://example.com`",
            parse_mode="Markdown"
        )
        return

    # ── Get API keys (DB first → .env fallback) ───────────────────────────────
    key_2cap = await _get_user_apikey(uid, "2captcha")
    key_caps = await _get_user_apikey(uid, "capsolver")

    if not key_2cap and not key_caps:
        await update.effective_message.reply_text(
            "❌ *API key မရှိပါ*\n\n"
            "တစ်ကြိမ်တည်း set လုပ်ပါ —\n"
            "`/setapikey capsolver YOUR_KEY`\n"
            "`/setapikey 2captcha YOUR_KEY`\n\n"
            "_CapSolver: capsolver.com_\n"
            "_2captcha: 2captcha.com_",
            parse_mode="Markdown"
        )
        return

    # Prefer capsolver → 2captcha
    if key_caps:
        service, apikey, svc_icon = "capsolver", key_caps, "🟢"
    else:
        service, apikey, svc_icon = "2captcha",  key_2cap, "🔵"

    task_lines = "\n".join(
        f"  [{i+1}] `{t['type']}` `{t['sitekey'][:24]}...`"
        for i, t in enumerate(tasks)
    )
    msg = await update.effective_message.reply_text(
        f"🤖 *AutoSolve* {svc_icon} `{service}`\n"
        f"━━━━━━━━━━━━━━━━━━━━\n"
        f"{task_lines}\n\n"
        f"⏳ Solving... (max 120s each)",
        parse_mode="Markdown"
    )

    results = []
    for i, task in enumerate(tasks):
        cap_type = task["type"]
        sitekey  = task["sitekey"]
        pageurl  = task["pageurl"]

        try:
            await msg.edit_text(
                f"🤖 *AutoSolve* {svc_icon} `{service}`\n"
                f"━━━━━━━━━━━━━━━━━━━━\n"
                f"⏳ `[{i+1}/{len(tasks)}]` {escape_md(cap_type)}\n"
                f"🔑 `{sitekey[:30]}...`\n"
                f"🌐 `{pageurl[:60]}`",
                parse_mode="Markdown"
            )
        except Exception:
            pass

        try:
            if service == "2captcha":
                res = await asyncio.to_thread(
                    _2captcha_solve_sync,
                    apikey, cap_type, sitekey, pageurl,
                    task.get("action",""), task.get("enterprise",0),
                    task.get("min_score",0.0), task.get("invisible",0),
                    task.get("data_s","")
                )
            else:
                res = await asyncio.to_thread(
                    _capsolver_solve_sync,
                    apikey, cap_type, sitekey, pageurl,
                    task.get("action",""), task.get("enterprise",0),
                    task.get("min_score",0.0), task.get("invisible",0)
                )
        except Exception as e:
            res = {"token": "", "cost": "", "error": str(e)}

        results.append({
            "idx":     i + 1,
            "type":    cap_type,
            "sitekey": sitekey,
            "pageurl": pageurl,
            "token":   res.get("token", ""),
            "cost":    res.get("cost", ""),
            "error":   res.get("error"),
        })

    # ── Build result ──────────────────────────────────────────────────────────
    solved = [r for r in results if r["token"]]
    failed = [r for r in results if not r["token"]]

    lines = [
        f"🤖 *AutoSolve* {svc_icon} `{service}`",
        "━━━━━━━━━━━━━━━━━━━━",
        f"✅ `{len(solved)}` solved | ❌ `{len(failed)}` failed",
        "",
    ]

    for r in results:
        if r["token"]:
            tp = r["token"][:80] + ("..." if len(r["token"]) > 80 else "")
            lines.append(f"*[{r['idx']}] ✅ {escape_md(r['type'])}*")
            lines.append(f"  🔑 `{r['sitekey']}`")
            lines.append(f"  🌐 `{r['pageurl'][:70]}`")
            if r["cost"]: lines.append(f"  💰 `{r['cost']}`")
            lines.append(f"  📋 *Token:*\n```\n{tp}\n```")
        else:
            # ── User-friendly error message ───────────────────────────────────
            err = str(r["error"] or "No token returned")
            if "WRONG_USER_KEY" in err or "wrong_user_key" in err.lower():
                err_msg = "❌ API key မှားနေသည် — key စစ်ဆေးပါ"
            elif "ZERO_BALANCE" in err or "zero_balance" in err.lower():
                err_msg = "❌ Account balance မရှိ — 2captcha/CapSolver ငွေဖြည့်ပါ"
            elif "ERROR_CAPTCHA_UNSOLVABLE" in err:
                err_msg = "❌ Captcha ဖြေမရပါ — sitekey / pageurl စစ်ဆေးပါ"
            elif "Timeout" in err:
                err_msg = "❌ Timeout — service ကြည့်ပါ"
            else:
                err_msg = f"❌ `{escape_md(err[:80])}`"
            lines.append(f"*[{r['idx']}] ❌ {escape_md(r['type'])}*")
            lines.append(f"  🔑 `{r['sitekey'][:40]}`")
            lines.append(f"  {err_msg}")
        lines.append("")

    lines.append("━━━━━━━━━━━━━━━━━━")
    lines.append("⚠️ _Authorized testing only_")

    try:
        await msg.edit_text(
            _truncate_safe_md("\n".join(lines)), parse_mode="Markdown")
    except Exception:
        await update.effective_message.reply_text(
            _truncate_safe_md("\n".join(lines)), parse_mode="Markdown")


        await update.effective_message.reply_text(
            _truncate_safe_md("\n".join(lines)),
            parse_mode="Markdown"
        )


# ══════════════════════════════════════════════════
# 🛒  /cartscan — Product picker + checkout scan
# ══════════════════════════════════════════════════

# Cache: {uid: {"url": str, "products": [...], "ts": float}}
_cartscan_cache: dict = {}
_CARTSCAN_TTL = 600   # 10 min


def _discover_products_playwright(url: str, progress_cb=None) -> list:
    """
    Use Playwright to discover products/items on a shop/product page.
    Returns list of {"name": str, "price": str, "url": str, "add_selector": str}
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return []

    products = []

    with sync_playwright() as pw:
        browser = pw.chromium.launch(headless=True, args=[
            "--no-sandbox", "--disable-blink-features=AutomationControlled"
        ])
        ctx  = browser.new_context(user_agent=(
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/120.0.0.0 Safari/537.36"
        ))
        page = ctx.new_page()

        try:
            if progress_cb: progress_cb("🌐 Loading shop page...")
            try:
                page.goto(url, wait_until="networkidle", timeout=30_000)
            except PWTimeout:
                page.goto(url, wait_until="domcontentloaded", timeout=15_000)

            page.wait_for_timeout(2000)

            # ── Extra scroll to trigger lazy-loaded product grids ────────────
            try:
                page.evaluate("window.scrollTo(0, document.body.scrollHeight / 2)")
                page.wait_for_timeout(800)
                page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
                page.wait_for_timeout(800)
            except Exception:
                pass

            # ── Extract products via JS evaluation ───────────────────────────
            raw = page.evaluate("""() => {
                const items = [];
                const seen  = new Set();

                function cleanText(t) {
                    return (t || '').replace(/\\s+/g, ' ').trim();
                }

                function addItem(name, price, href, addSel) {
                    name = cleanText(name);
                    price = cleanText(price);
                    const key = name.toLowerCase() + '|' + price;
                    if (seen.has(key) || !name || name.length < 2) return;
                    seen.add(key);
                    items.push({ name: name.slice(0, 60), price: price.slice(0, 30), url: href || window.location.href, add_selector: addSel || '' });
                }

                // ── 1. Schema.org Product markup ──────────────────────────
                document.querySelectorAll('[itemtype*="schema.org/Product"],[itemtype*="Product"]').forEach(el => {
                    const name  = cleanText((el.querySelector('[itemprop="name"]') || {}).textContent);
                    const priceEl = el.querySelector('[itemprop="price"]');
                    const price = priceEl ? (priceEl.getAttribute('content') || priceEl.textContent) : '';
                    const link  = (el.querySelector('a[href]') || {}).href || '';
                    addItem(name, price, link, '');
                });

                // ── 2. WooCommerce ─────────────────────────────────────────
                document.querySelectorAll('.products .product, ul.products li.product, .wc-block-grid__product').forEach(el => {
                    const name  = cleanText((el.querySelector('.woocommerce-loop-product__title, .wc-block-grid__product-title, h2, h3') || {}).textContent);
                    const price = cleanText((el.querySelector('.price .woocommerce-Price-amount, .price .amount, .woocommerce-Price-amount') || {}).textContent);
                    const link  = (el.querySelector('a.woocommerce-LoopProduct-link, a') || {}).href || '';
                    const btn   = el.querySelector('a.add_to_cart_button, button.add_to_cart_button');
                    addItem(name, price, link, btn ? (btn.getAttribute('data-product_id') || '') : '');
                });

                // ── 3. Shopify ────────────────────────────────────────────
                document.querySelectorAll('.product-item, .grid__item, [class*="product-card"], [class*="ProductCard"]').forEach(el => {
                    const name  = cleanText((el.querySelector('[class*="product-title"],[class*="card__heading"],[class*="ProductCard__Name"],h2,h3') || {}).textContent);
                    const priceEl = el.querySelector('[class*="price__regular"],[class*="ProductCard__Price"],[class*="price"]:not([class*="compare"])');
                    const price = priceEl ? cleanText(priceEl.textContent) : '';
                    const link  = (el.querySelector('a[href]') || {}).href || '';
                    addItem(name, price, link, '');
                });

                // ── 4. GiveWP / Donation plugins ──────────────────────────
                document.querySelectorAll('.give-wrap, [class*="give-"], [id*="give-"], .charitable-campaign, [class*="donation"]').forEach(el => {
                    const name  = cleanText((el.querySelector('h1,h2,h3,[class*="title"],[class*="name"]') || {}).textContent);
                    const amounts = Array.from(el.querySelectorAll('[data-amount],[value][type="radio"],[class*="amount"] label, .give-btn-level'));
                    amounts.forEach(a => {
                        const amt = a.getAttribute('data-amount') || a.getAttribute('value') || cleanText(a.textContent);
                        if (amt && /[0-9]/.test(amt)) {
                            addItem(name || 'Donation', '$' + amt, window.location.href, a.tagName.toLowerCase() + (a.className ? '.' + a.className.split(' ')[0] : ''));
                        }
                    });
                    if (!amounts.length && name) addItem(name, '', window.location.href, '');
                });

                // ── 5. Generic price + product name ───────────────────────
                document.querySelectorAll('[class*="product"],[class*="item-card"],[class*="plan"],[class*="tier"],[class*="pricing"],[class*="package"]').forEach(el => {
                    const name = cleanText((el.querySelector('h2,h3,h4,[class*="title"],[class*="name"],[class*="plan-name"]') || {}).textContent);
                    const priceEl = el.querySelector('[class*="price"],[class*="amount"],[class*="cost"],[data-price]');
                    const price = priceEl ? cleanText(priceEl.getAttribute('data-price') || priceEl.textContent) : '';
                    const link  = (el.querySelector('a[href]') || {}).href || window.location.href;
                    if (price && /[0-9]/.test(price) && price.length < 30) {
                        addItem(name, price, link, '');
                    }
                });

                // ── 6. Pricing table rows ─────────────────────────────────
                document.querySelectorAll('table tr').forEach(tr => {
                    const cells = Array.from(tr.querySelectorAll('td,th'));
                    if (cells.length < 2) return;
                    const name  = cleanText(cells[0].textContent);
                    const priceCell = cells.find(c => /[0-9]/.test(c.textContent) && c.textContent.length < 20);
                    if (priceCell && name) addItem(name, cleanText(priceCell.textContent), window.location.href, '');
                });

                // ── 7. Amount input fields (donation forms) ────────────────
                document.querySelectorAll('input[name*="amount"],input[name*="price"],input[id*="amount"]').forEach(inp => {
                    const val = inp.getAttribute('value') || inp.getAttribute('placeholder') || '';
                    if (val && /[0-9]/.test(val)) {
                        const label = cleanText((document.querySelector('label[for="' + inp.id + '"]') || {}).textContent) || 'Custom Amount';
                        addItem(label, val, window.location.href, inp.name || inp.id || 'input');
                    }
                });

                return items.slice(0, 30);
            }""")

            if raw:
                for item in raw:
                    if item.get("name"):
                        products.append({
                            "name":         (item["name"] or "")[:60].strip(),
                            "price":        (item.get("price") or "")[:30].strip(),
                            "url":          item.get("url") or url,
                            "add_selector": item.get("add_selector", ""),
                        })

            # ── Fallback 1: any link with price-like text ─────────────────────
            if not products:
                if progress_cb: progress_cb("🔗 Fallback: scanning links with price text...")
                try:
                    links = page.evaluate("""() => {
                        const hrefs = [];
                        const seen  = new Set();
                        document.querySelectorAll('a[href]').forEach(a => {
                            const h   = a.href || '';
                            const txt = (a.textContent || '').replace(/\\s+/g,' ').trim();
                            if (!h || seen.has(h) || txt.length < 2 || txt.length > 80) return;
                            const low = h.toLowerCase();
                            if (/(product|item|shop|store|buy|plan|pricing|donate|give|donation|checkout|pay)/.test(low)) {
                                seen.add(h);
                                hrefs.push({ name: txt.slice(0,60), price: '', url: h, add_selector: '' });
                            }
                        });
                        return hrefs.slice(0, 20);
                    }""")
                    if links:
                        products = [p for p in links if p.get("name")]
                except Exception:
                    pass

            # ── Fallback 2: page title as single item if no products found ────
            if not products:
                if progress_cb: progress_cb("📄 Fallback: using page as single item...")
                try:
                    title = page.title() or urlparse(url).netloc
                    products = [{"name": title[:60], "price": "", "url": url, "add_selector": ""}]
                except Exception:
                    products = [{"name": urlparse(url).netloc, "price": "", "url": url, "add_selector": ""}]

        except Exception as e:
            if progress_cb: progress_cb(f"⚠️ Product discovery error: {e}")
        finally:
            try: browser.close()
            except Exception: pass

    return products


def _cartscan_run_sync(product_url: str, product_name: str,
                        progress_cb=None) -> dict:
    """
    Simulate selecting a product, adding to cart, reaching checkout,
    then run full sitekey + paykeys scan on the checkout page.
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return {"error": "playwright not installed", "sitekeys": [], "paykeys": []}

    sitekeys: list = []
    paykeys:  list = []
    scan_url  = product_url
    sk_seen:  set = set()
    pk_seen:  set = set()

    _SK_PATTERNS = [
        (re.compile(r'["\']([6L][A-Za-z0-9_\-]{38})["\']'), "reCAPTCHA v2/v3"),
        (re.compile(r'["\']([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})["\']', re.I), "hCaptcha"),
        (re.compile(r'["\']([01]x[A-Za-z0-9_\-]{20,60})["\']'), "Cloudflare Turnstile"),
        (re.compile(r'data-sitekey=["\']([A-Za-z0-9_\-]{20,80})["\']', re.I), "Captcha (sitekey attr)"),
        (re.compile(r'["\']sitekey["\']\s*:\s*["\']([A-Za-z0-9_\-]{20,80})["\']', re.I), "Captcha (JSON sitekey)"),
    ]
    _PK_PATTERNS = [
        (re.compile(r'(pk_live_[A-Za-z0-9]{20,})'),   "Stripe PK Live"),
        (re.compile(r'(pk_test_[A-Za-z0-9]{20,})'),   "Stripe PK Test"),
        (re.compile(r'(sk_live_[A-Za-z0-9]{20,})'),   "Stripe SK Live"),
        (re.compile(r'(rzp_live_[A-Za-z0-9]{14,})'),  "Razorpay Live"),
        (re.compile(r'(rzp_test_[A-Za-z0-9]{14,})'),  "Razorpay Test"),
        (re.compile(r'"client_id"\s*:\s*"([A-Za-z0-9_\-]{10,80})"', re.I), "PayPal Client ID"),
        (re.compile(r'(EAAA[A-Za-z0-9]{20,})'),       "Square Access Token"),
    ]

    def _scan_text(text: str, source: str):
        if not text or not isinstance(text, str):
            return
        for pat, ktype in _SK_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1).strip()
                if val and val not in sk_seen and len(val) >= 10:
                    sk_seen.add(val)
                    sitekeys.append({"type": ktype, "site_key": val,
                                     "source": source, "page_url": scan_url})
        for pat, ktype in _PK_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1).strip()
                if val and val not in pk_seen:
                    pk_seen.add(val)
                    paykeys.append({"type": ktype, "value": val,
                                    "source": source,
                                    "env": "🔴 LIVE" if "live" in ktype.lower() else "🟡 TEST"})

    with sync_playwright() as pw:
        browser = pw.chromium.launch(headless=True, args=[
            "--no-sandbox", "--disable-blink-features=AutomationControlled"
        ])
        ctx  = browser.new_context(user_agent=(
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/120.0.0.0 Safari/537.36"
        ))
        page = ctx.new_page()
        network_bodies: list = []

        def _on_response(resp):
            try:
                ct = resp.headers.get("content-type", "")
                if any(x in ct for x in ("javascript", "json", "html")):
                    try:
                        body = resp.text()
                        if body:
                            network_bodies.append((body, f"network ← {resp.url[:80]}"))
                    except Exception:
                        pass
            except Exception:
                pass

        page.on("response", _on_response)

        try:
            # ── Step 1: Load product page ─────────────────────────────────────
            if progress_cb: progress_cb(f"🌐 Loading product: {product_name[:40]}...")
            try:
                page.goto(product_url, wait_until="networkidle", timeout=30_000)
            except PWTimeout:
                page.goto(product_url, wait_until="domcontentloaded", timeout=15_000)

            scan_url = page.url
            page.wait_for_timeout(1500)

            # Scan initial page HTML + JS
            html = page.content()
            _scan_text(html, f"Product page HTML: {scan_url[:80]}")

            # ── Step 2: Add to cart ───────────────────────────────────────────
            if progress_cb: progress_cb("🛒 Adding item to cart...")
            add_selectors = [
                'button[name="add"]', '.single_add_to_cart_button',
                '.product-form__submit', 'button.add_to_cart_button',
                '[class*="add-to-cart"]', '[class*="addToCart"]',
                'button[data-product_id]', 'input[name="add-to-cart"]',
                'button[type="submit"]', '.btn-add-to-cart',
                '[id*="add-to-cart"]', '[id*="addToCart"]',
            ]
            added = False
            for sel in add_selectors:
                try:
                    el = page.query_selector(sel)
                    if el and el.is_visible():
                        el.scroll_into_view_if_needed()
                        page.wait_for_timeout(400)
                        el.click(timeout=3000)
                        page.wait_for_timeout(1500)
                        try:
                            page.wait_for_load_state("networkidle", timeout=6_000)
                        except Exception:
                            pass
                        added = True
                        if progress_cb: progress_cb(f"✅ Added to cart via: {sel}")
                        break
                except Exception:
                    pass

            if not added and progress_cb:
                progress_cb("⚠️ Add-to-cart button not found — proceeding to checkout directly")

            # ── Step 3: Navigate to checkout ─────────────────────────────────
            if progress_cb: progress_cb("🔀 Navigating to checkout...")
            checkout_selectors = [
                'a[href*="checkout"]', '.checkout-button',
                '#proceed-to-checkout', 'button[name="checkout"]',
                '[class*="checkout"]', '.wc-proceed-to-checkout a',
                'a.cart_checkout', '.btn-checkout',
            ]
            for sel in checkout_selectors:
                try:
                    el = page.query_selector(sel)
                    if el and el.is_visible():
                        el.click(timeout=3000)
                        page.wait_for_timeout(2000)
                        try:
                            page.wait_for_load_state("networkidle", timeout=8_000)
                        except Exception:
                            pass
                        break
                except Exception:
                    pass

            # Try direct /checkout URL if no button found
            parsed = urlparse(product_url)
            base   = f"{parsed.scheme}://{parsed.netloc}"
            for path in ["/checkout", "/cart", "/shop/checkout", "/order"]:
                if "checkout" in page.url or "cart" in page.url:
                    break
                try:
                    page.goto(base + path, wait_until="networkidle", timeout=10_000)
                    if page.url != base + path:
                        break
                except Exception:
                    pass

            scan_url = page.url
            if progress_cb: progress_cb(f"📍 Checkout URL: {scan_url[:60]}")

            # ── Step 4: Fill checkout form fields ─────────────────────────────
            if progress_cb: progress_cb("📝 Filling checkout form to trigger captcha...")
            form_fills = [
                ('input[name="email"]',           "test@example.com"),
                ('input[type="email"]',            "test@example.com"),
                ('input[name="billing_email"]',    "test@example.com"),
                ('input[name="firstname"]',        "Test"),
                ('input[name="lastname"]',         "User"),
                ('input[name="first_name"]',       "Test"),
                ('input[name="last_name"]',        "User"),
                ('input[name="billing_first_name"]',"Test"),
                ('input[name="billing_last_name"]', "User"),
                ('input[name="phone"]',            "+10000000000"),
                ('input[name="billing_phone"]',    "+10000000000"),
            ]
            for sel, val in form_fills:
                try:
                    el = page.query_selector(sel)
                    if el and el.is_visible():
                        el.fill(val)
                        page.wait_for_timeout(200)
                except Exception:
                    pass

            page.wait_for_timeout(2500)
            try:
                page.wait_for_load_state("networkidle", timeout=8_000)
            except Exception:
                pass

            # ── Step 5: Scan checkout page ────────────────────────────────────
            if progress_cb: progress_cb("🔍 Scanning checkout page for sitekeys + payment keys...")
            checkout_html = page.content()
            _scan_text(checkout_html, f"Checkout HTML: {scan_url[:80]}")

            # Scan all collected network responses
            for body, src in network_bodies:
                _scan_text(body, src)

            # Scan window globals at runtime
            try:
                win_str = page.evaluate("""() => {
                    const keys = ['___grecaptcha_cfg','hcaptcha','Turnstile','Stripe',
                                  'Square','Razorpay','PayPal','wc_stripe_params',
                                  'wc_checkout_params','wc_razorpay_params'];
                    const out = {};
                    keys.forEach(k => { try { if(window[k]) out[k] = JSON.stringify(window[k]).slice(0,5000); } catch(e){} });
                    return JSON.stringify(out);
                }""")
                if win_str:
                    _scan_text(win_str, "window globals (runtime)")
            except Exception:
                pass

            # Scan data-sitekey DOM elements
            try:
                dom_keys = page.evaluate("""() =>
                    Array.from(document.querySelectorAll('[data-sitekey]'))
                         .map(el => ({
                             key: el.getAttribute('data-sitekey'),
                             cls: el.className || el.tagName,
                         }))
                """)
                for dk in (dom_keys or []):
                    sk = dk.get("key", "")
                    if sk and sk not in sk_seen:
                        sk_seen.add(sk)
                        ktype = ("Cloudflare Turnstile" if "cf-turnstile" in dk.get("cls","")
                                 else "hCaptcha" if "h-captcha" in dk.get("cls","")
                                 else "reCAPTCHA")
                        sitekeys.append({"type": ktype, "site_key": sk,
                                         "source": f"DOM [data-sitekey] checkout ({dk.get('cls','')[:40]})",
                                         "page_url": scan_url})
            except Exception:
                pass

            # ── Step 6: __NEXT_DATA__ / Nuxt deep scan ────────────────────────
            try:
                next_data = page.evaluate("() => JSON.stringify(window.__NEXT_DATA__ || window.__NUXT__ || {})")
                if next_data and len(next_data) > 10:
                    _scan_text(next_data, "Next.js/__NEXT_DATA__ (checkout)")
            except Exception:
                pass

        except Exception as e:
            if progress_cb: progress_cb(f"⚠️ Scan error: {e}")
        finally:
            try: browser.close()
            except Exception: pass

    return {
        "error":    None,
        "sitekeys": sitekeys,
        "paykeys":  paykeys,
        "scan_url": scan_url,
    }


@user_guard
async def cmd_cartscan(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/cartscan <url> — Discover products, pick one, scan checkout for sitekeys + payment keys"""
    uid = update.effective_user.id

    if not context.args:
        await update.effective_message.reply_text(
            "🛒 *CartScan — Product Picker + Checkout Scanner*\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "*Usage:*\n"
            "  `/cartscan https://example.com/shop`\n"
            "  `/cartscan https://example.com/product/item-a`\n\n"
            "*What it does:*\n"
            "  1️⃣ Shop page မှ product list ထုတ်သည်\n"
            "  2️⃣ Inline keyboard နဲ့ item ရွေးခိုင်းသည်\n"
            "  3️⃣ Add to cart → checkout flow simulate\n"
            "  4️⃣ Checkout page မှ sitekey + payment key scan\n\n"
            "⚠️ _Authorized testing only_",
            parse_mode="Markdown"
        )
        return

    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(
            f"⏳ `{wait}s` စောင့်ပါ", parse_mode="Markdown")
        return

    raw = context.args[0].strip()
    url = raw if raw.startswith("http") else "https://" + raw

    ok, reason = is_safe_url(url)
    if not ok:
        await update.effective_message.reply_text(
            f"🚫 `{escape_md(reason)}`", parse_mode="Markdown")
        return

    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"🛒 *CartScan — `{escape_md(domain)}`*\n\n"
        f"⏳ Product list ရှာနေသည်...",
        parse_mode="Markdown"
    )

    # ── Discover products ─────────────────────────────────────────────────────
    progress_q = []
    async def _prog():
        while True:
            await asyncio.sleep(2)
            if progress_q:
                t = progress_q[-1]; progress_q.clear()
                try:
                    await msg.edit_text(
                        f"🛒 *CartScan — `{escape_md(domain)}`*\n\n{escape_md(t)}",
                        parse_mode="Markdown"
                    )
                except Exception:
                    pass

    prog = asyncio.create_task(_prog())
    try:
        products = await asyncio.to_thread(
            _discover_products_playwright, url,
            lambda t: progress_q.append(t)
        )
    finally:
        prog.cancel()

    if not products:
        await safe_markdown_reply(msg,
            f"🛒 *CartScan — `{escape_md(domain)}`*\n\n"
            f"📭 Product မတွေ့ပါ\n"
            f"_Product page URL ကို တိကျစွာ ထည့်ကြည့်ပါ_\n"
            f"_ဥပမာ: /cartscan https://example.com/shop_"
        )
        return

    # ── Cache products ────────────────────────────────────────────────────────
    _cartscan_cache[uid] = {
        "url":      url,
        "domain":   domain,
        "products": products,
        "ts":       time.time(),
    }

    # ── Build inline keyboard ─────────────────────────────────────────────────
    kb_rows = []
    for idx, p in enumerate(products[:20]):
        name  = p["name"][:25]
        price = p["price"]
        label = f"{'💲' if price else '📦'} {name}" + (f" ({price})" if price else "")
        kb_rows.append([
            InlineKeyboardButton(label[:50], callback_data=f"cs_pick_{uid}_{idx}")
        ])

    await safe_markdown_reply(msg,
        f"🛒 *CartScan — `{escape_md(domain)}`*\n"
        f"━━━━━━━━━━━━━━━━━━━━\n"
        f"📦 Products found: `{len(products)}`\n\n"
        f"_Item တစ်ခုကို ရွေးပါ — checkout scan လုပ်ပေးမည်_\n"
        f"⚠️ _Authorized testing only_"
    )
    await update.effective_message.reply_text(
        "👇 *Item ရွေးပါ:*",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb_rows)
    )


async def cartscan_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Handle CartScan item selection.
    Pattern: cs_pick_<uid>_<idx>
    """
    query = update.callback_query
    try:
        await query.answer("⏳ Checkout scan စတင်နေသည်...")
    except Exception:
        pass

    try:
        parts = query.data.split("_")
        uid   = int(parts[2])
        idx   = int(parts[3])
    except Exception:
        await query.answer("❌ Parse error", show_alert=True)
        return

    if query.from_user.id != uid:
        await query.answer("🚫 သင်မဟုတ်ပါ", show_alert=True)
        return

    cached = _cartscan_cache.get(uid)
    if not cached or (time.time() - cached.get("ts", 0)) > _CARTSCAN_TTL:
        await query.answer("⚠️ Cache expired — /cartscan ထပ်လုပ်ပါ", show_alert=True)
        return

    products = cached.get("products", [])
    if idx >= len(products):
        await query.answer("⚠️ Index error", show_alert=True)
        return

    product     = products[idx]
    p_name      = product["name"]
    p_url       = product["url"] or cached["url"]
    p_price     = product.get("price", "")
    domain      = cached["domain"]

    # ── Progress message ──────────────────────────────────────────────────────
    prog_msg = await context.bot.send_message(
        chat_id=query.from_user.id,
        text=(
            f"🛒 *CartScan — `{escape_md(domain)}`*\n"
            f"━━━━━━━━━━━━━━━━━━━━\n"
            f"📦 Selected: *{escape_md(p_name)}*"
            + (f" `({escape_md(p_price)})`" if p_price else "") + "\n"
            f"🌐 `{p_url[:70]}`\n\n"
            f"⏳ Add to cart → checkout → scan..."
        ),
        parse_mode="Markdown"
    )

    progress_q2 = []
    async def _prog2():
        while True:
            await asyncio.sleep(2)
            if progress_q2:
                t = progress_q2[-1]; progress_q2.clear()
                try:
                    await prog_msg.edit_text(
                        f"🛒 *CartScan — `{escape_md(domain)}`*\n"
                        f"📦 *{escape_md(p_name)}*\n\n"
                        f"{escape_md(t)}",
                        parse_mode="Markdown"
                    )
                except Exception:
                    pass

    prog2 = asyncio.create_task(_prog2())
    try:
        result = await asyncio.to_thread(
            _cartscan_run_sync,
            p_url, p_name,
            lambda t: progress_q2.append(t)
        )
    finally:
        prog2.cancel()

    sitekeys  = result.get("sitekeys", [])
    paykeys   = result.get("paykeys",  [])
    scan_url  = result.get("scan_url", p_url)
    error     = result.get("error")

    if error:
        await prog_msg.edit_text(
            f"❌ *CartScan Error*\n`{escape_md(str(error))}`",
            parse_mode="Markdown"
        )
        return

    # ── Build result report ───────────────────────────────────────────────────
    lines = [
        f"🛒 *CartScan Result — `{escape_md(domain)}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        f"📦 Item: *{escape_md(p_name)}*" + (f" `({escape_md(p_price)})`" if p_price else ""),
        f"🌐 Checkout: `{scan_url[:80]}`",
        f"🔑 Sitekeys: `{len(sitekeys)}` | 💳 Payment Keys: `{len(paykeys)}`",
        "",
    ]

    # ── Sitekeys ──────────────────────────────────────────────────────────────
    if sitekeys:
        lines.append("🔑 *Captcha Sitekeys:*")
        for i, f in enumerate(sitekeys, 1):
            sk  = (f.get("site_key") or "")[:60]
            src = f.get("source", "")[:100]
            lines.append(f"  *[{i}]* `{escape_md(f.get('type',''))}` ✅")
            lines.append(f"  🔑 `{sk}`")
            lines.append(f"  📂 _{escape_md(src)}_")
            # Solver-ready params
            sp = json.dumps({
                "type":    f.get("type",""),
                "sitekey": sk,
                "pageurl": f.get("page_url", scan_url),
            }, indent=2)
            lines.append(f"```\n{sp}\n```")
        lines.append("")
    else:
        lines.append("🔑 Sitekeys: _မတွေ့ပါ_\n")

    # ── Payment Keys ──────────────────────────────────────────────────────────
    if paykeys:
        lines.append("💳 *Payment Keys:*")
        for i, pk in enumerate(paykeys, 1):
            val = pk.get("value","")[:80]
            src = pk.get("source","")[:80]
            env = pk.get("env","")
            lines.append(f"  *[{i}]* `{escape_md(pk.get('type',''))}` {env}")
            lines.append(f"  🔑 `{val}`")
            lines.append(f"  📂 _{escape_md(src)}_")
        lines.append("")
    else:
        lines.append("💳 Payment Keys: _မတွေ့ပါ_\n")

    lines.append("━━━━━━━━━━━━━━━━━━")
    lines.append("⚠️ _Authorized testing only_")

    try:
        await prog_msg.edit_text(
            _truncate_safe_md("\n".join(lines)),
            parse_mode="Markdown"
        )
    except Exception:
        await context.bot.send_message(
            chat_id=query.from_user.id,
            text=_truncate_safe_md("\n".join(lines)),
            parse_mode="Markdown"
        )


def _verify_stripe(key: str) -> dict:
    """Stripe sk_live_ / sk_test_ → GET /v1/account + /v1/balance (read-only, full info)"""
    env_label = "🔴 LIVE" if key.startswith("sk_live_") else "🟡 TEST"
    masked    = key[:12] + "..." + key[-4:]
    headers   = {"Authorization": f"Bearer {key}"}

    account_info: dict = {}

    # ── GET /v1/account — full info with sk_ ─────────────────────────────────
    try:
        ra = requests.get("https://api.stripe.com/v1/account",
                          headers=headers, timeout=12)
        if ra.status_code == 200:
            account_info = ra.json()
        elif ra.status_code == 401:
            err = ra.json().get("error", {}).get("message", "Unauthorized")
            return {"gateway": "Stripe", "status": "❌ INVALID / REVOKED",
                    "env": env_label, "detail": err[:80], "key": masked,
                    "account_info": {}}
        elif ra.status_code == 403:
            return {"gateway": "Stripe", "status": "⚠️ VALID (Restricted scope)",
                    "env": env_label,
                    "detail": "Key valid but restricted — no account scope",
                    "key": masked, "account_info": {}}
    except requests.exceptions.Timeout:
        return {"gateway": "Stripe", "status": "❌ Timeout", "env": env_label,
                "detail": "API ကို 12s အတွင်း မရောက်ပါ", "key": masked, "account_info": {}}
    except Exception as e:
        return {"gateway": "Stripe", "status": "❌ Error", "env": env_label,
                "detail": str(e)[:60], "key": masked, "account_info": {}}

    # ── GET /v1/balance ───────────────────────────────────────────────────────
    balance_str = ""
    try:
        rb   = requests.get("https://api.stripe.com/v1/balance",
                            headers=headers, timeout=12)
        if rb.status_code == 200:
            avail = rb.json().get("available", [])
            balance_str = ", ".join(
                f"{b.get('currency','?').upper()} {b.get('amount',0)/100:.2f}"
                for b in avail[:3]
            )
    except Exception:
        pass

    # ── Extract fields ────────────────────────────────────────────────────────
    business_profile = account_info.get("business_profile") or {}
    settings         = account_info.get("settings") or {}
    dashboard        = settings.get("dashboard") or {}

    country          = account_info.get("country", "")
    default_currency = account_info.get("default_currency", "")
    business_name    = (business_profile.get("name")
                        or dashboard.get("display_name")
                        or account_info.get("display_name", ""))
    charges_enabled  = account_info.get("charges_enabled")
    payouts_enabled  = account_info.get("payouts_enabled")
    account_type     = account_info.get("type", "")
    account_id       = account_info.get("id", "")
    livemode         = account_info.get("livemode", key.startswith("sk_live_"))
    email            = account_info.get("email", "")

    detail_parts = []
    if business_name:    detail_parts.append(f"🏢 {business_name}")
    if country:          detail_parts.append(f"🌏 {country.upper()}")
    if default_currency: detail_parts.append(f"💱 {default_currency.upper()}")
    if account_type:     detail_parts.append(f"📋 {account_type}")
    if balance_str:      detail_parts.append(f"💰 {balance_str}")
    if charges_enabled is not None:
        detail_parts.append("✅ charges" if charges_enabled else "❌ charges_off")
    if payouts_enabled is not None:
        detail_parts.append("✅ payouts" if payouts_enabled else "❌ payouts_off")

    detail = " | ".join(detail_parts) or "Account info retrieved"

    return {
        "gateway":      "Stripe",
        "status":       "✅ VALID (Secret Key)",
        "env":          env_label,
        "detail":       detail,
        "key":          masked,
        "account_info": {
            "business_name":    business_name,
            "country":          country,
            "default_currency": default_currency,
            "account_type":     account_type,
            "charges_enabled":  charges_enabled,
            "payouts_enabled":  payouts_enabled,
            "livemode":         livemode,
            "account_id":       account_id,
            "email":            email,
            "balance":          balance_str,
        },
    }


def _verify_stripe_publishable(key: str) -> dict:
    """
    Stripe pk_live_ / pk_test_ — fetch account public info.
    GET /v1/account with pk_ returns limited but useful fields.
    Falls back to token endpoint probe for livemode confirmation.
    """
    env_label = "🔴 LIVE" if key.startswith("pk_live_") else "🟡 TEST"
    masked    = key[:12] + "..." + key[-4:]
    headers   = {"Authorization": f"Bearer {key}"}
    account_info: dict = {}

    # Try GET /v1/account
    try:
        r = requests.get("https://api.stripe.com/v1/account",
                         headers=headers, timeout=12)
        if r.status_code == 200:
            account_info = r.json()
        elif r.status_code == 401:
            err = r.json().get("error", {}).get("message", "Unauthorized")
            return {"gateway": "Stripe", "status": "❌ INVALID / REVOKED",
                    "env": env_label, "detail": err[:80], "key": masked,
                    "account_info": {}}
    except Exception as e:
        return {"gateway": "Stripe", "status": "❌ Error",
                "env": env_label, "detail": str(e)[:60], "key": masked,
                "account_info": {}}

    # Probe via token endpoint if /v1/account returned nothing useful
    if not account_info:
        try:
            probe = requests.post(
                "https://api.stripe.com/v1/tokens",
                headers=headers,
                data={"card[number]": "4242424242424242",
                      "card[exp_month]": "12",
                      "card[exp_year]": "2030",
                      "card[cvc]": "123"},
                timeout=12,
            )
            pj = probe.json()
            if probe.status_code == 200:
                account_info["_probe_livemode"] = pj.get("livemode", False)
                account_info["_probe_status"]   = "token_created"
            elif probe.status_code in (400, 402):
                account_info["_probe_livemode"] = key.startswith("pk_live_")
                account_info["_probe_status"]   = "key_valid_card_error"
        except Exception:
            pass

    # Extract fields
    business_profile = account_info.get("business_profile") or {}
    settings         = account_info.get("settings") or {}
    dashboard        = settings.get("dashboard") or {}

    country          = account_info.get("country", "")
    default_currency = account_info.get("default_currency", "")
    business_name    = (business_profile.get("name")
                        or dashboard.get("display_name")
                        or account_info.get("display_name", ""))
    charges_enabled  = account_info.get("charges_enabled")
    payouts_enabled  = account_info.get("payouts_enabled")
    account_type     = account_info.get("type", "")
    account_id       = account_info.get("id", "")
    livemode         = account_info.get("_probe_livemode", key.startswith("pk_live_"))
    email            = account_info.get("email", "")

    detail_parts = []
    if business_name:    detail_parts.append(f"🏢 {business_name}")
    if country:          detail_parts.append(f"🌏 {country.upper()}")
    if default_currency: detail_parts.append(f"💱 {default_currency.upper()}")
    if account_type:     detail_parts.append(f"📋 {account_type}")
    if charges_enabled is not None:
        detail_parts.append("✅ charges_enabled" if charges_enabled else "❌ charges_disabled")
    if payouts_enabled is not None:
        detail_parts.append("✅ payouts_enabled" if payouts_enabled else "❌ payouts_disabled")
    if email:            detail_parts.append(f"📧 {email}")
    if account_id:       detail_parts.append(f"🆔 {account_id[:18]}")
    detail_parts.append(f"📡 livemode: {livemode}")

    detail = " | ".join(detail_parts) or "Public key — limited info"

    return {
        "gateway":      "Stripe",
        "status":       "✅ VALID (Publishable Key)",
        "env":          env_label,
        "detail":       detail,
        "key":          masked,
        "account_info": {
            "business_name":    business_name,
            "country":          country,
            "default_currency": default_currency,
            "account_type":     account_type,
            "charges_enabled":  charges_enabled,
            "payouts_enabled":  payouts_enabled,
            "livemode":         livemode,
            "account_id":       account_id,
            "email":            email,
        },
    }


def _verify_paypal_pair(client_id: str, secret: str) -> dict:
    """PayPal client_id + secret → POST /v1/oauth2/token"""
    masked = client_id[:10] + "..."
    try:
        r = requests.post(
            "https://api-m.paypal.com/v1/oauth2/token",
            data={"grant_type": "client_credentials"},
            auth=(client_id, secret),
            headers={"Accept": "application/json"},
            timeout=12,
        )
        if r.status_code == 200:
            data  = r.json()
            scope = data.get("scope", "")
            # Detect sandbox vs live from scope or URL
            is_sb = "sandbox" in scope.lower()
            return {"gateway": "PayPal", "status": "✅ VALID",
                    "env": "🟡 SANDBOX" if is_sb else "🔴 LIVE",
                    "detail": f"App: {data.get('app_id','?')} | Expires: {data.get('expires_in','?')}s",
                    "key": masked}
        else:
            err = r.json().get("error_description", r.text[:80])
            return {"gateway": "PayPal", "status": "❌ INVALID",
                    "env": "?", "detail": err, "key": masked}
    except requests.exceptions.Timeout:
        return {"gateway": "PayPal", "status": "❌ Timeout", "env": "?",
                "detail": "API တွင်မထွက်ပါ", "key": masked}
    except Exception as e:
        return {"gateway": "PayPal", "status": "❌ Error", "env": "?",
                "detail": str(e)[:60], "key": masked}


def _verify_razorpay_pair(key_id: str, key_secret: str) -> dict:
    """Razorpay rzp_live_/rzp_test_ + secret → GET /v1/balance"""
    env_label = "🔴 LIVE" if "live" in key_id else "🟡 TEST"
    masked    = key_id[:12] + "..."
    try:
        r = requests.get(
            "https://api.razorpay.com/v1/balance",
            auth=(key_id, key_secret),
            timeout=12,
        )
        if r.status_code == 200:
            data = r.json()
            bal  = data.get("balance", 0) / 100
            curr = data.get("currency", "INR")
            return {"gateway": "Razorpay", "status": "✅ VALID", "env": env_label,
                    "detail": f"Balance: {curr} {bal:.2f}", "key": masked}
        elif r.status_code == 401:
            return {"gateway": "Razorpay", "status": "❌ INVALID", "env": env_label,
                    "detail": "Bad credentials", "key": masked}
        else:
            # Some accounts get 403/404 on /balance but key is valid — try /payments
            r2 = requests.get(
                "https://api.razorpay.com/v1/payments?count=1",
                auth=(key_id, key_secret), timeout=10
            )
            if r2.status_code == 200:
                return {"gateway": "Razorpay", "status": "✅ VALID", "env": env_label,
                        "detail": "Auth OK (payments endpoint)", "key": masked}
            elif r2.status_code == 401:
                return {"gateway": "Razorpay", "status": "❌ INVALID", "env": env_label,
                        "detail": "401 on both endpoints", "key": masked}
            else:
                return {"gateway": "Razorpay", "status": f"⚠️ HTTP {r.status_code}/{r2.status_code}",
                        "env": env_label, "detail": r2.text[:60], "key": masked}
    except requests.exceptions.Timeout:
        return {"gateway": "Razorpay", "status": "❌ Timeout", "env": env_label,
                "detail": "12s timeout", "key": masked}
    except Exception as e:
        return {"gateway": "Razorpay", "status": "❌ Error", "env": env_label,
                "detail": str(e)[:60], "key": masked}


def _verify_square(token: str) -> dict:
    """Square EAAAl.../sq0atp- → GET /v2/locations (read-only)"""
    is_sb     = token.startswith("EAAAl") or "sandbox" in token.lower()
    env_label = "🟡 SANDBOX" if is_sb else "🔴 LIVE"
    masked    = token[:10] + "..." + token[-4:]
    base_url  = (
        "https://connect.squareupsandbox.com"
        if is_sb else
        "https://connect.squareup.com"
    )
    try:
        r = requests.get(
            f"{base_url}/v2/locations",
            headers={
                "Authorization": f"Bearer {token}",
                "Square-Version": "2024-06-04",
                "Content-Type": "application/json",
            },
            timeout=12,
        )
        if r.status_code == 200:
            locs = r.json().get("locations", [])
            names = ", ".join(l.get("name","?") for l in locs[:2])
            return {"gateway": "Square", "status": "✅ VALID", "env": env_label,
                    "detail": f"{len(locs)} location(s): {names}", "key": masked}
        elif r.status_code == 401:
            return {"gateway": "Square", "status": "❌ INVALID / REVOKED",
                    "env": env_label, "detail": "401 Unauthorized", "key": masked}
        elif r.status_code == 403:
            return {"gateway": "Square", "status": "⚠️ VALID (No location scope)",
                    "env": env_label, "detail": "Key valid, restricted permissions", "key": masked}
        else:
            return {"gateway": "Square", "status": f"⚠️ HTTP {r.status_code}",
                    "env": env_label, "detail": r.text[:80], "key": masked}
    except requests.exceptions.Timeout:
        return {"gateway": "Square", "status": "❌ Timeout", "env": env_label,
                "detail": "12s timeout", "key": masked}
    except Exception as e:
        return {"gateway": "Square", "status": "❌ Error", "env": env_label,
                "detail": str(e)[:60], "key": masked}


def _verify_finding(f: dict) -> dict:
    """paykeys finding တစ်ခုကို gateway type ပေါ်မူတည်ပြီး verify လုပ်တယ်"""
    ftype = f.get("type", "")
    val   = f.get("value", "").strip()

    if not val:
        return {"gateway": ftype, "status": "⚠️ Empty value", "env": "?",
                "detail": "Value မပါပါ", "key": "—"}

    # ── Stripe ───────────────────────────────────────────────────────────
    if "Stripe Secret" in ftype or re.match(r'^sk_(live|test)_', val):
        return _verify_stripe(val)
    if "Stripe Publishable" in ftype or re.match(r'^pk_(live|test)_', val):
        return _verify_stripe_publishable(val)

    # ── Square ───────────────────────────────────────────────────────────
    if "Square" in ftype or re.match(r'^(EAAA|sq0atp-|sq0idp-)', val):
        return _verify_square(val)

    # ── Razorpay — needs pair; single key ကို flag ပါ ────────────────────
    if "Razorpay Key ID" in ftype or re.match(r'^rzp_(live|test)_', val):
        return {"gateway": "Razorpay", "status": "⚠️ Pair needed",
                "env": "🔴 LIVE" if "live" in val else "🟡 TEST",
                "detail": "Razorpay ကို /verifykeys rzp_id rzp_secret နဲ့ manual verify လုပ်ပါ",
                "key": val[:12]+"..."}
    if "Razorpay Key Secret" in ftype:
        return {"gateway": "Razorpay Secret", "status": "⚠️ Pair needed",
                "env": "?", "detail": "ID+Secret pair လိုပါသည်", "key": val[:8]+"..."}

    # ── PayPal — needs pair ───────────────────────────────────────────────
    if "PayPal" in ftype:
        return {"gateway": "PayPal", "status": "⚠️ Pair needed",
                "env": "?",
                "detail": "PayPal ကို /verifykeys pp_client_id pp_secret နဲ့ manual verify လုပ်ပါ",
                "key": val[:10]+"..."}

    return {"gateway": ftype or "Unknown", "status": "⚠️ Auto-detect မရပါ",
            "env": "?", "detail": "Format မသိ — manual check လုပ်ပါ", "key": val[:10]+"..."}


def _run_verify_all(findings: list[dict]) -> list[dict]:
    """Thread pool ဖြင့် findings တွေကို concurrent verify လုပ်တယ်"""
    with concurrent.futures.ThreadPoolExecutor(max_workers=6) as ex:
        futures = {ex.submit(_verify_finding, f): f for f in findings}
        results = []
        for fut in concurrent.futures.as_completed(futures, timeout=60):
            try:
                results.append(fut.result())
            except Exception as e:
                orig = futures[fut]
                results.append({
                    "gateway": orig.get("type", "?"),
                    "status":  "❌ Error",
                    "env":     "?",
                    "detail":  str(e)[:60],
                    "key":     orig.get("value","")[:8]+"...",
                })
    return results


def _build_verify_report(results: list[dict], domain: str) -> str:
    """Verify results ကို Telegram Markdown report အဖြစ် build လုပ်တယ် — account info ပါဝင်"""
    valid   = [r for r in results if "✅" in r["status"]]
    warn    = [r for r in results if "⚠️" in r["status"]]
    invalid = [r for r in results if "❌" in r["status"]]
    live    = [r for r in results if "LIVE" in r.get("env","")]

    lines = [
        f"🔍 *Payment Key Verifier — `{escape_md(domain)}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        f"📊 Checked: `{len(results)}` | ✅ Valid: `{len(valid)}` | "
        f"❌ Invalid: `{len(invalid)}` | 🔴 Live: `{len(live)}`\n",
    ]

    ordered = valid + warn + invalid
    for i, r in enumerate(ordered, 1):
        lines.append(f"*[{i}]* {r['gateway']} — {r['status']}")
        lines.append(f"  🌐 `{r.get('env','?')}`")
        lines.append(f"  🔑 `{escape_md(r['key'])}`")
        lines.append(f"  📋 _{escape_md(r.get('detail',''))}_")

        # ── Stripe account_info full block ────────────────────────────────────
        ai = r.get("account_info") or {}
        if ai and r.get("gateway") == "Stripe" and "✅" in r["status"]:
            lines.append("")
            lines.append("  📦 *Stripe Account Info:*")
            if ai.get("business_name"):
                lines.append(f"  🏢 Business: `{escape_md(ai['business_name'])}`")
            if ai.get("country"):
                lines.append(f"  🌏 Country: `{ai['country'].upper()}`")
            if ai.get("default_currency"):
                lines.append(f"  💱 Currency: `{ai['default_currency'].upper()}`")
            if ai.get("account_type"):
                lines.append(f"  📋 Type: `{escape_md(ai['account_type'])}`")
            if ai.get("charges_enabled") is not None:
                tag = "✅ Enabled" if ai["charges_enabled"] else "❌ Disabled"
                lines.append(f"  💳 Charges: {tag}")
            if ai.get("payouts_enabled") is not None:
                tag = "✅ Enabled" if ai["payouts_enabled"] else "❌ Disabled"
                lines.append(f"  💸 Payouts: {tag}")
            if ai.get("email"):
                lines.append(f"  📧 Email: `{escape_md(ai['email'])}`")
            if ai.get("account_id"):
                lines.append(f"  🆔 ID: `{escape_md(ai['account_id'][:24])}`")
            lm = ai.get("livemode")
            if lm is not None:
                lines.append(f"  📡 Livemode: `{lm}`")

        lines.append("")

    lines.append("━━━━━━━━━━━━━━━━━━")
    lines.append("🔒 _Read-only — No charge/transaction performed_")
    lines.append("⚠️ _Authorized testing only_")
    return "\n".join(lines)


# ── Inline button callback ────────────────────────────────────────────────

async def verifykeys_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle [🔍 Verify Keys] button from /paykeys"""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass

    # callback_data = "vk_run_{uid}"
    try:
        uid = int(query.data.split("_")[2])
    except Exception:
        return

    if query.from_user.id != uid:
        await query.answer("🚫 သင်မဟုတ်ပါ", show_alert=True)
        return

    cached = _paykeys_verify_cache.get(uid)
    if not cached or (time.time() - cached.get("ts", 0)) > _PAYKEYS_CACHE_TTL:
        await query.answer("⚠️ Cache ကုန်ပြီ — /paykeys ထပ်လုပ်ပါ", show_alert=True)
        return

    findings = cached["findings"]
    domain   = cached["domain"]

    # Edit button message to show progress
    try:
        await query.edit_message_text(
            f"🔍 *Verifying {len(findings)} key(s) from `{escape_md(domain)}`...*\n\n"
            "⏳ Read-only API calls လုပ်နေသည်...",
            parse_mode='Markdown'
        )
    except Exception:
        pass

    results = await asyncio.to_thread(_run_verify_all, findings)
    report  = _build_verify_report(results, domain)

    try:
        await query.edit_message_text(
            _truncate_safe_md(report),
            parse_mode='Markdown'
        )
    except Exception:
        await context.bot.send_message(
            chat_id=query.message.chat_id,
            text=_truncate_safe_md(report),
            parse_mode='Markdown'
        )


# ── /verifykeys command (standalone, manual key input) ───────────────────

async def cmd_verifykeys(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/verifykeys <key(s)> — Verify payment keys manually (read-only)"""
    if not await check_force_join(update, context):
        return

    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/verifykeys <key1> [key2] ...`\n\n"
            "💳 *Supported:*\n"
            "  🔵 Stripe secret  — `sk_live_...` / `sk_test_...`\n"
            "  🔵 Stripe public  — `pk_live_...` / `pk_test_...`\n"
            "  🟣 Square         — `EAAA...` / `sq0atp-...`\n"
            "  🟠 Razorpay pair  — `rzp_live_xxx secret`\n"
            "  🟡 PayPal pair    — `client_id secret`\n\n"
            "🔒 *Read-only — No charge/transaction*\n"
            "⚠️ _Authorized testing only_",
            parse_mode='Markdown'
        )
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    args = list(context.args)
    msg  = await update.effective_message.reply_text(
        f"🔍 *Key Verifier*\n\n⏳ {len(args)} key(s) checking...",
        parse_mode='Markdown'
    )

    # Build synthetic findings from raw args, handling pairs
    findings = []
    i = 0
    while i < len(args):
        key = args[i].strip()
        nxt = args[i+1].strip() if i+1 < len(args) else ""

        if re.match(r'^rzp_(live|test)_[A-Za-z0-9]{14,}$', key) and nxt:
            # Razorpay ID+secret pair — verify directly
            result = await asyncio.to_thread(_verify_razorpay_pair, key, nxt)
            findings_results = [result]
            i += 2
            # Build report immediately
            report = _build_verify_report(findings_results, "manual")
            await safe_markdown_reply(msg, _truncate_safe_md(report))
            return

        elif (re.match(r'^[A-Za-z0-9\-_]{16,80}$', key) and nxt and
              re.match(r'^[A-Za-z0-9\-_]{16,80}$', nxt) and
              not re.match(r'^sk_|^pk_|^rzp_|^EAAA|^sq0', key)):
            # PayPal client_id + secret pair
            result = await asyncio.to_thread(_verify_paypal_pair, key, nxt)
            findings_results = [result]
            i += 2
            report = _build_verify_report(findings_results, "manual")
            await safe_markdown_reply(msg, _truncate_safe_md(report))
            return

        else:
            # Single key — auto-detect type
            findings.append({"type": _guess_key_type(key), "value": key})
            i += 1

    results = await asyncio.to_thread(_run_verify_all, findings)
    report  = _build_verify_report(results, "manual")
    await safe_markdown_reply(msg, _truncate_safe_md(report))


def _guess_key_type(val: str) -> str:
    """Raw key string ကနေ gateway type ခန့်မှန်းတယ်"""
    if re.match(r'^sk_(live|test)_', val):   return "Stripe Secret Key"
    if re.match(r'^pk_(live|test)_', val):   return "Stripe Publishable Key"
    if re.match(r'^(EAAA|sq0atp-|sq0idp-)', val): return "Square Access Token"
    if re.match(r'^rzp_(live|test)_', val):  return "Razorpay Key ID"
    return "Unknown"


