# Card-field metadata mapping for synthetic fields
_SYNTH_CARD_META = {
    # field name pattern → (field_label, card_type, icon)
    r'card.?number|cardnum|cc.?num|encryptedcard': ("Card Number",       "Card Number",   "💳"),
    r'exp.?month|cc.?exp.?m|expiry.?m':            ("Expiry Month",      None,            "📅"),
    r'exp.?year|cc.?exp.?y|expiry.?y':             ("Expiry Year",       None,            "📅"),
    r'exp.?date|expirat|ccexpiry|card.?expir':      ("Expiry MM/YY",     None,            "📅"),
    r'cvv|cvc|csc|cvn|cc.?code|security.?code|encryptedsecur': ("CVV/CVC", "CVV/CVC", "🔒"),
    r'postal|zip':                                  ("Postal / ZIP",      None,            "📮"),
    r'first.?name|fname':                           ("First Name",        None,            "👤"),
    r'last.?name|lname|surname':                    ("Last Name",         None,            "👤"),
    r'email':                                       ("Email",             None,            "✉️"),
    r'phone|contact|mobile':                        ("Phone",             None,            "📱"),
    r'amount|donation|price':                       ("Amount",            None,            "💰"),
    r'currency':                                    ("Currency",          None,            "💱"),
    r'name':                                        ("Cardholder Name",   None,            "👤"),
}

def _synth_field_meta(name: str):
    """Return (field_label, card_type, icon) for a synthetic field name."""
    nl = name.lower()
    for pat, (label, card_type, icon) in _SYNTH_CARD_META.items():
        if re.search(pat, nl):
            return label, card_type, icon
    return name.replace("_", " ").title(), None, "✏️"


# ══════════════════════════════════════════════════════════════
# A: Multi-page checkout step tracker
# ══════════════════════════════════════════════════════════════

def _detect_checkout_steps(html: str, js_text: str, url: str) -> dict:
    """
    Detect multi-step checkout flow: how many steps exist,
    which step is currently active, and step labels.
    """
    html    = html    or ""
    js_text = js_text or ""
    html    = html    or ""
    js_text = js_text or ""
    combined = html + js_text
    steps_found: list[dict] = []
    current_step: int | None = None
    total_steps: int | None = None
    method = 'unknown'

    # ── 1. aria-label / data-step attributes ──────────────────────────────
    _ARIA_STEP = re.compile(
        r'<[^>]+(?:data-step|data-checkout-step|data-step-index)'
        r'\s*=\s*["\']?(\d+)["\']?[^>]*(?:aria-label=["\']([^"\']*)["\'])?[^>]*>',
        re.I
    )
    for m in _ARIA_STEP.finditer(html):
        n    = int(m.group(1))
        lbl  = m.group(2) or f'Step {n}'
        steps_found.append({'step': n, 'label': lbl.strip()[:60]})

    # ── 2. WooCommerce / Magento / Shopify progress bars ─────────────────
    _STEP_CLASS = re.compile(
        r'class=["\'][^"\']*(?:checkout-step|step-item|progress-step|'
        r'breadcrumb-item|wizard-step|step-indicator)[^"\']*["\'][^>]*>([^<]{2,60})',
        re.I
    )
    for m in _STEP_CLASS.finditer(html):
        lbl = re.sub(r'\s+', ' ', m.group(1)).strip()
        if lbl and len(lbl) > 1:
            steps_found.append({'step': len(steps_found) + 1, 'label': lbl[:60]})
        if len(steps_found) >= 10:
            break

    # ── 3. JS step config / router ────────────────────────────────────────
    _JS_STEPS = [
        re.compile(r'(?:totalSteps|stepsCount|numSteps|step_count)\s*[=:]\s*(\d+)', re.I),
        re.compile(r'steps\s*[=:]\s*\[(?:[^]]{0,300})\]', re.I),
        re.compile(r'(?:currentStep|activeStep|stepIndex|current_step)\s*[=:]\s*(\d+)', re.I),
    ]
    for pat in _JS_STEPS:
        m = pat.search(js_text)
        if m:
            try:
                val = int(m.group(1))
                if pat.pattern.startswith('(?:totalSteps'):
                    total_steps = val
                elif pat.pattern.startswith('(?:currentStep'):
                    current_step = val
                method = 'js_config'
            except (IndexError, ValueError):
                pass

    # ── 4. URL step indicator ─────────────────────────────────────────────
    _url_step = re.search(r'/(?:step|checkout)[/_-]?(\d+)|[?&]step=(\d+)', url, re.I)
    if _url_step:
        current_step = int(_url_step.group(1) or _url_step.group(2))
        method = 'url_param'

    # ── 5. Active step detection ─────────────────────────────────────────
    _ACTIVE_PAT = re.compile(
        r'class=["\'][^"\']*(?:active|current|is-active|selected)[^"\']*["\'][^>]*>'
        r'[^<]*(?:[Ss]tep|[Cc]heckout|[Bb]illing|[Ss]hipping|[Pp]ayment)[^<]*<',
        re.I
    )
    if not current_step and _ACTIVE_PAT.search(html):
        method = 'active_class'

    # ── Dedup + sort ──────────────────────────────────────────────────────
    seen_labels: set[str] = set()
    deduped = []
    for s in steps_found:
        key = s['label'].lower()[:30]
        if key not in seen_labels:
            seen_labels.add(key)
            deduped.append(s)

    if not total_steps and deduped:
        total_steps = len(deduped)

    return {
        'detected':      bool(deduped or total_steps),
        'total_steps':   total_steps,
        'current_step':  current_step,
        'steps':         deduped[:10],
        'method':        method,
    }


# ══════════════════════════════════════════════════════════════
# B: Gateway SDK version detector
# ══════════════════════════════════════════════════════════════

def _detect_sdk_versions(html: str, js_text: str) -> list:
    """
    Detect loaded gateway SDK versions and variants.
    Returns list of {gateway, sdk, version, variant, note}
    """
    html    = html    or ""
    js_text = js_text or ""
    html    = html    or ""
    js_text = js_text or ""
    combined = html + js_text
    results: list[dict] = []

    # ── Stripe ────────────────────────────────────────────────────────────
    _STRIPE_CHECKS = [
        # Stripe.js v3 (current) — js.stripe.com/v3
        (re.compile(r'js\.stripe\.com/v3', re.I),
         'Stripe.js', 'v3', 'current',
         'PaymentElement / CardElement API'),
        # Stripe.js v2 (legacy)
        (re.compile(r'js\.stripe\.com/v2', re.I),
         'Stripe.js', 'v2', 'legacy',
         '⚠️ Legacy — createToken() only, no SCA/3DS2'),
        # Stripe.js v1 (very old)
        (re.compile(r'js\.stripe\.com/v1', re.I),
         'Stripe.js', 'v1', 'deprecated',
         '🔴 Deprecated — no longer supported by Stripe'),
        # PaymentElement (new embedded UI)
        (re.compile(r'PaymentElement|stripe\.elements\(\).*payment', re.I | re.S),
         'Stripe PaymentElement', 'v3+', 'recommended',
         'Handles cards, wallets, BNPL in one element'),
        # Stripe Terminal SDK
        (re.compile(r'stripe-terminal|StripeTerminal', re.I),
         'Stripe Terminal SDK', 'n/a', 'in-person',
         'Physical card reader integration'),
        # Stripe Connect
        (re.compile(r'stripe\.com/connect|StripeConnect', re.I),
         'Stripe Connect', 'n/a', 'platform',
         'Marketplace / multi-party payment'),
    ]
    for pat, sdk, ver, variant, note in _STRIPE_CHECKS:
        if pat.search(combined):
            results.append({
                'gateway': 'Stripe', 'sdk': sdk,
                'version': ver, 'variant': variant, 'note': note,
            })

    # ── Braintree ─────────────────────────────────────────────────────────
    _BT_CHECKS = [
        (re.compile(r'braintree-web@([\d.]+)', re.I),
         'braintree-web', None, 'current', 'Hosted Fields / Drop-in UI'),
        (re.compile(r'braintree\.com/web/([\d.]+)', re.I),
         'Braintree CDN', None, 'cdn', None),
        (re.compile(r'BraintreeDropIn|dropin\.create', re.I),
         'Braintree Drop-in UI', None, 'hosted', 'Full UI, no PCI scope'),
        (re.compile(r'braintree\.hostedFields|hostedFields\.create', re.I),
         'Braintree Hosted Fields', None, 'custom-ui', 'Custom UI, no PCI scope'),
        (re.compile(r'PayPalCheckout|braintree.*paypal', re.I | re.S),
         'Braintree PayPal', None, 'wallet', 'PayPal via Braintree'),
    ]
    for pat, sdk, ver, variant, note in _BT_CHECKS:
        m = pat.search(combined)
        if m:
            detected_ver = m.group(1) if ver is None and m.lastindex else (ver or 'unknown')
            results.append({
                'gateway': 'Braintree', 'sdk': sdk,
                'version': detected_ver, 'variant': variant,
                'note': note or '',
            })

    # ── Adyen ─────────────────────────────────────────────────────────────
    _ADYEN_CHECKS = [
        (re.compile(r'@adyen/web@?([\d.]+)?|adyen-web@([\d.]+)', re.I),
         'Adyen Web Components', None, 'current',
         'Drop-in / Component API (v5+)'),
        (re.compile(r'checkoutshopper.*?adyen\.com', re.I),
         'Adyen Checkout Shopper', None, 'cdn', None),
        (re.compile(r'AdyenCheckout\s*\(', re.I),
         'Adyen Checkout JS', None, 'component', 'AdyenCheckout() init detected'),
        (re.compile(r'adyen-cse|CSEKey|adyen\.encrypt', re.I),
         'Adyen CSE (Legacy)', None, 'legacy',
         '⚠️ Client-Side Encryption legacy — use Web Components'),
    ]
    for pat, sdk, ver, variant, note in _ADYEN_CHECKS:
        m = pat.search(combined)
        if m:
            gv = next((g for g in (m.group(1), m.group(2)) if g), ver or 'unknown')
            results.append({
                'gateway': 'Adyen', 'sdk': sdk,
                'version': gv, 'variant': variant, 'note': note or '',
            })

    # ── Square ────────────────────────────────────────────────────────────
    _SQ_CHECKS = [
        (re.compile(r'web\.squarecdn\.com/v([\d]+)', re.I),
         'Square Web Payments SDK', None, 'current', None),
        (re.compile(r'SqPaymentForm', re.I),
         'Square SqPaymentForm', None, 'legacy',
         '⚠️ Deprecated by Square — migrate to Web Payments SDK'),
    ]
    for pat, sdk, ver, variant, note in _SQ_CHECKS:
        m = pat.search(combined)
        if m:
            gv = m.group(1) if m.lastindex else (ver or 'unknown')
            results.append({
                'gateway': 'Square', 'sdk': sdk,
                'version': f'v{gv}' if gv and not gv.startswith('v') else gv,
                'variant': variant, 'note': note or '',
            })

    # ── PayPal ────────────────────────────────────────────────────────────
    if re.search(r'paypal\.com/sdk/js\?client-id=', combined, re.I):
        _pp_sdk_ver = re.search(r'paypal\.com/sdk/js\?[^"\']*version=([\d.]+)', combined, re.I)
        results.append({
            'gateway': 'PayPal', 'sdk': 'PayPal JS SDK',
            'version': _pp_sdk_ver.group(1) if _pp_sdk_ver else 'current',
            'variant': 'smart-buttons', 'note': 'PayPal Smart Buttons / Hosted Fields',
        })

    # ── Klarna ────────────────────────────────────────────────────────────
    if re.search(r'klarna\.com/v1/library|klarnaCheckout|KlarnaOSM', combined, re.I):
        results.append({
            'gateway': 'Klarna', 'sdk': 'Klarna Checkout SDK',
            'version': 'v1', 'variant': 'embedded', 'note': 'BNPL / Pay Later embed',
        })

    return results


# ══════════════════════════════════════════════════════════════
# C: Dynamic pricing detector
# ══════════════════════════════════════════════════════════════

def _detect_dynamic_pricing(html: str, js_text: str) -> dict:
    """
    Detect if the amount field value changes dynamically
    (quantity selectors, tiered pricing, custom amount inputs,
    coupon/promo code discount application).
    """
    signals: list[dict] = []
    amount_fields: list[str] = []
    min_amount: str | None = None
    max_amount: str | None = None
    currency: str | None = None
    is_dynamic = False

    # ── 1. JS amount watchers ─────────────────────────────────────────────
    _JS_AMT_PATS = [
        (re.compile(r'(?:amount|price|total)\s*[=:]\s*(?:qty|quantity)\s*\*\s*(?:price|rate|unitPrice)', re.I),
         'quantity × price calculation'),
        (re.compile(r'addEventListener\(["\'](?:change|input)["\'][^)]*(?:amount|qty|quantity|price)', re.I | re.S),
         'amount field change listener'),
        (re.compile(r'(?:calculateTotal|updateTotal|computePrice|recalculate)\s*\(', re.I),
         'price recalculation function'),
        (re.compile(r'(?:discount|coupon|promo)\s*(?:code|applied|amount)', re.I),
         'coupon/promo discount'),
        (re.compile(r'tiered?(?:Pricing|Price|Rate)|priceTier|price_tier', re.I),
         'tiered pricing'),
        (re.compile(r'(?:min|minimum)[_\s]?(?:amount|donation|price)\s*[=:]\s*["\']?([\d.]+)', re.I),
         'min amount enforced'),
        (re.compile(r'(?:max|maximum)[_\s]?(?:amount|donation|price)\s*[=:]\s*["\']?([\d.]+)', re.I),
         'max amount enforced'),
        (re.compile(r'suggested[_\s]?(?:amounts?|donations?)\s*[=:]\s*\[([^\]]+)\]', re.I),
         'suggested amounts array'),
    ]
    for pat, desc in _JS_AMT_PATS:
        m = pat.search(js_text)
        if m:
            is_dynamic = True
            extra = {}
            try:
                if 'min' in desc:
                    min_amount = m.group(1)
                elif 'max' in desc:
                    max_amount = m.group(1)
                elif 'suggested' in desc:
                    extra['suggested'] = m.group(1)[:60]
            except (IndexError, AttributeError):
                pass
            signals.append({'signal': desc, 'source': 'js', **extra})

    # ── 2. HTML amount input attributes ──────────────────────────────────
    _AMT_INPUT = re.compile(
        r'<input[^>]+(?:name|id)=["\'][^"\']*(?:amount|price|total|donation)[^"\']*["\'][^>]*>',
        re.I
    )
    for m in _AMT_INPUT.finditer(html):
        tag = m.group(0)
        field_name = re.search(r'name=["\']([^"\']+)["\']', tag, re.I)
        if field_name:
            amount_fields.append(field_name.group(1))
        _min = re.search(r'min=["\']?([\d.]+)', tag, re.I)
        _max = re.search(r'max=["\']?([\d.]+)', tag, re.I)
        if _min and not min_amount:
            min_amount = _min.group(1)
            is_dynamic = True
            signals.append({'signal': f'HTML min={min_amount}', 'source': 'html'})
        if _max and not max_amount:
            max_amount = _max.group(1)
            is_dynamic = True
            signals.append({'signal': f'HTML max={max_amount}', 'source': 'html'})
        _step = re.search(r'step=["\']?([\d.]+)', tag, re.I)
        if _step:
            signals.append({'signal': f'Amount step={_step.group(1)}', 'source': 'html'})

    # ── 3. Radio / preset amount buttons ─────────────────────────────────
    _RADIO_AMT = re.compile(
        r'<input[^>]+type=["\']radio["\'][^>]*value=["\']?([\d.]+)["\']?[^>]*'
        r'(?:name=["\'][^"\']*(?:amount|donation|price)[^"\']*["\'])?',
        re.I
    )
    preset_amounts = []
    for m in _RADIO_AMT.finditer(html):
        try:
            v = float(m.group(1))
            if 0 < v < 100_000:
                preset_amounts.append(m.group(1))
        except ValueError:
            pass
    if preset_amounts:
        is_dynamic = True
        signals.append({
            'signal':  f'Preset amounts: {", ".join(preset_amounts[:6])}',
            'source': 'html_radio',
        })

    # ── 4. Currency detection ─────────────────────────────────────────────
    _CURR_PAT = re.compile(
        r'(?:currency|Currency)\s*[=:]\s*["\']([A-Z]{3})["\']'
        r'|(?:Intl\.NumberFormat|new Intl)\s*\(\s*["\']([a-z-]+)["\'][^)]*["\']([A-Z]{3})["\']',
        re.I
    )
    _cm = _CURR_PAT.search((js_text or "") + (html or ""))
    if _cm:
        currency = _cm.group(1) or _cm.group(3)

    return {
        'is_dynamic':    is_dynamic,
        'amount_fields': list(set(amount_fields))[:6],
        'min_amount':    min_amount,
        'max_amount':    max_amount,
        'currency':      currency,
        'preset_amounts': list(dict.fromkeys(preset_amounts))[:8],
        'signals':       signals[:10],
    }


# ══════════════════════════════════════════════════════════════
# D: WAF / bot-protection fingerprinter
# ══════════════════════════════════════════════════════════════

def _detect_waf_fingerprint(
    html: str,
    js_text: str,
    headers: dict | None = None,
    cookies: dict | None = None,
) -> list:
    """
    Detect WAF / bot-protection vendors from response headers,
    cookies, HTML/JS content, and script URLs.
    Returns list of {vendor, confidence, signals, bypass_note}
    """
    combined  = (html or '') + (js_text or '')
    headers   = {k.lower(): v for k, v in (headers or {}).items()}
    cookies   = {k.lower(): v for k, v in (cookies or {}).items()}
    results: list[dict] = []

    def _build(vendor, confidence, signals, bypass_note=''):
        results.append({
            'vendor':      vendor,
            'confidence':  confidence,   # 'confirmed' | 'likely' | 'possible'
            'signals':     signals,
            'bypass_note': bypass_note,
        })

    # ── Cloudflare ────────────────────────────────────────────────────────
    _cf_sigs = []
    if 'cf-ray' in headers:
        _cf_sigs.append('cf-ray header')
    if 'cf-cache-status' in headers:
        _cf_sigs.append('cf-cache-status header')
    if '__cfruid' in cookies or 'cf_clearance' in cookies:
        _cf_sigs.append('cf_clearance / __cfruid cookie')
    if re.search(r'cloudflare|__cf_chl|cf-challenge|cf_chl_prog', combined, re.I):
        _cf_sigs.append('CF challenge JS')
    if re.search(r'challenges\.cloudflare\.com|cdn-cgi/challenge', combined, re.I):
        _cf_sigs.append('CF challenge URL')
    if _cf_sigs:
        conf = 'confirmed' if len(_cf_sigs) >= 2 else 'likely'
        _build('Cloudflare', conf, _cf_sigs,
               'JS challenge / Turnstile CAPTCHA — requires real browser or Playwright')

    # ── Akamai Bot Manager ────────────────────────────────────────────────
    _ak_sigs = []
    if 'akamai-origin-hop' in headers or 'akamai-grn' in headers:
        _ak_sigs.append('Akamai header')
    if 'ak_bmsc' in cookies or 'bm_sz' in cookies or '_abck' in cookies:
        _ak_sigs.append('ak_bmsc / _abck cookie (Bot Manager)')
    if re.search(r'akamai|akam\b|akmai', combined, re.I):
        _ak_sigs.append('Akamai JS reference')
    if re.search(r'_abck|bm_sz|bmak\b', combined, re.I):
        _ak_sigs.append('Akamai sensor script variable')
    if _ak_sigs:
        conf = 'confirmed' if '_abck' in cookies or 'ak_bmsc' in cookies else 'likely'
        _build('Akamai Bot Manager', conf, _ak_sigs,
               '_abck cookie requires sensor data from Akamai JS — very hard to bypass headless')

    # ── Imperva / Incapsula ───────────────────────────────────────────────
    _im_sigs = []
    if 'x-iinfo' in headers or 'x-cdn' in headers:
        _im_sigs.append('X-Iinfo / X-CDN header')
    if 'incap_ses' in cookies or 'visid_incap' in cookies or 'nlbi_' in cookies:
        _im_sigs.append('incap_ses / visid_incap cookie')
    if re.search(r'imperva|incapsula|/_Incapsula_Resource', combined, re.I):
        _im_sigs.append('Imperva/Incapsula JS reference')
    if _im_sigs:
        conf = 'confirmed' if len(_im_sigs) >= 2 else 'likely'
        _build('Imperva / Incapsula', conf, _im_sigs,
               'Cookie-based challenge — Playwright with stealth plugin often sufficient')

    # ── Kasada ────────────────────────────────────────────────────────────
    _ks_sigs = []
    if re.search(r'kasada|kpsdk|kp-telemetry', combined, re.I):
        _ks_sigs.append('Kasada SDK JS')
    if 'x-kpsdk-ct' in headers or 'x-kpsdk-st' in headers:
        _ks_sigs.append('x-kpsdk-ct / x-kpsdk-st header')
    if 'kpsdk_w' in cookies or 'kpsdk_d' in cookies:
        _ks_sigs.append('kpsdk cookie')
    if _ks_sigs:
        _build('Kasada', 'confirmed', _ks_sigs,
               '🔴 Very hard — custom crypto + TLS fingerprinting + headless detection')

    # ── DataDome ─────────────────────────────────────────────────────────
    _dd_sigs = []
    if re.search(r'datadome\.co|dd\.js|ddm\.js', combined, re.I):
        _dd_sigs.append('DataDome JS loaded')
    if 'datadome' in cookies:
        _dd_sigs.append('datadome cookie')
    if 'x-datadome-clientid' in headers:
        _dd_sigs.append('X-DataDome-ClientID header')
    if _dd_sigs:
        _build('DataDome', 'confirmed', _dd_sigs,
               'ML bot detection — missing cookie triggers CAPTCHA or 403')

    # ── PerimeterX / HUMAN ────────────────────────────────────────────────
    _px_sigs = []
    if re.search(r'perimeterx|px\.js|pxScript|/_px/', combined, re.I):
        _px_sigs.append('PerimeterX JS reference')
    if re.search(r'_pxhd|_pxvid|_px2|_px3', cookies, re.I) or \
       any(k.startswith('_px') for k in cookies):
        _px_sigs.append('_px* cookie')
    if 'x-px-client-uuid' in headers:
        _px_sigs.append('X-PX-Client-UUID header')
    if _px_sigs:
        _build('PerimeterX (HUMAN)', 'confirmed', _px_sigs,
               'JS sensor data required — Playwright stealth + human-like delays needed')

    # ── Cloudflare Turnstile (standalone) ─────────────────────────────────
    if re.search(r'challenges\.cloudflare\.com/turnstile|cf-turnstile', combined, re.I):
        _build('Cloudflare Turnstile', 'confirmed',
               ['Turnstile widget JS detected'],
               'CAPTCHA-like widget — cf-turnstile-response token required in POST')

    # ── reCAPTCHA Enterprise (stricter than standard) ─────────────────────
    if re.search(r'enterprise\.js|recaptcha/enterprise', combined, re.I):
        _build('reCAPTCHA Enterprise', 'confirmed',
               ['enterprise.js loaded'],
               '🔴 Harder than standard reCAPTCHA — token bound to user interaction')

    # ── AWS WAF (managed rules) ────────────────────────────────────────────
    _aws_sigs = []
    if 'x-amzn-requestid' in headers or 'x-amz-cf-id' in headers:
        _aws_sigs.append('AWS header (CF/APIGateway)')
    if 'aws-waf-token' in cookies:
        _aws_sigs.append('aws-waf-token cookie')
    if re.search(r'aws-waf-challenge|awswaf\.js', combined, re.I):
        _aws_sigs.append('AWS WAF challenge JS')
    if _aws_sigs:
        conf = 'confirmed' if 'aws-waf-token' in cookies else 'possible'
        _build('AWS WAF', conf, _aws_sigs,
               'Token-based challenge — aws-waf-token cookie required')

    return results


def _detect_embedded_payment_platforms(html: str, js_text: str = "") -> list:
    """
    ENH: Detect known third-party donation/payment embed platforms from
    iframe src, script src, and inline JS globals.

    Returns list of dicts:
      {
        'provider':      str,
        'iframe_src':    str | None,   # first matched iframe/script URL
        'tokenized':     bool,
        'synthetic_fields': [field_dict, ...],
        'source':        'iframe_embed' | 'script_embed',
      }
    """
    combined = (html or '') + (js_text or '')
    detected = []
    seen_providers: set = set()

    # Extract all iframe src and script src URLs from HTML
    iframe_srcs = re.findall(
        r'<iframe[^>]+src=["\']([^"\']+)["\']',
        html, re.I
    )
    script_srcs = re.findall(
        r'<script[^>]+src=["\']([^"\']+)["\']',
        html, re.I
    )
    all_urls = iframe_srcs + script_srcs

    for provider, patterns, synth_field_names, tokenized in _EMBED_PAYMENT_PLATFORMS:
        if provider in seen_providers:
            continue

        matched_src   = None
        matched_source = 'script_embed'

        # Check against collected URLs first
        for url_candidate in all_urls:
            for pat in patterns:
                if re.search(pat, url_candidate, re.I):
                    matched_src = url_candidate
                    matched_source = (
                        'iframe_embed' if url_candidate in iframe_srcs
                        else 'script_embed'
                    )
                    break
            if matched_src:
                break

        # Fallback: check combined HTML+JS text (catches dynamically injected iframes)
        if not matched_src:
            for pat in patterns:
                m = re.search(pat, combined, re.I)
                if m:
                    # Try to capture surrounding URL
                    _ctx = combined[max(0, m.start()-120):m.end()+120]
                    _url_m = re.search(r'https?://[^\s\'"<>]+', _ctx)
                    matched_src    = _url_m.group(0).strip('.,)') if _url_m else f"[{provider}]"
                    matched_source = 'script_embed'
                    break

        if not matched_src:
            continue

        seen_providers.add(provider)

        # Build synthetic fields
        synthetic_fields = []
        for fname in synth_field_names:
            flabel, fcard_type, ficon = _synth_field_meta(fname)
            synthetic_fields.append({
                'name':         fname,
                'type':         'text',
                'value':        '',
                'required':     True,
                'field_label':  flabel,
                'icon':         ficon,
                'is_dynamic':   True,
                'is_card':      fcard_type is not None,
                'card_type':    fcard_type,
                'placeholder':  '',
                'from_iframe':  matched_source == 'iframe_embed',
                'source':       matched_source,
                'note':         (
                    f'Hosted by {provider} — fields rendered in cross-origin iframe, '
                    f'direct DOM access blocked by browser same-origin policy'
                ),
            })

        detected.append({
            'provider':         provider,
            'iframe_src':       matched_src,
            'tokenized':        tokenized,
            'synthetic_fields': synthetic_fields,
            'source':           matched_source,
        })

    return detected


def _detect_payment_gateway(html: str, js_sources: str = '') -> list:
    """HTML + JS မှ payment gateway detect လုပ်သည်။"""
    combined   = (html or '') + (js_sources or '')
    tokenized  = bool(re.search(
        r'createToken|createPaymentMethod|tokenize|\.token\b|paymentIntent|'
        r'stripe\.js|braintree\.js|accept\.js', combined, re.I))
    iframe_based = bool(re.search(
        r'stripe\.elements|paypal\.Buttons|dropin\.create|<iframe[^>]+(stripe|paypal|braintree)',
        combined, re.I))
    # FIX 5: Stripe Elements / Payment Element / Checkout SDK = NOT raw POST
    # These all tokenize card data client-side → server never sees raw card
    _stripe_sdk = bool(re.search(
        r'stripe\.elements\(|stripe\.paymentElement\(|'
        r'stripe\.redirectToCheckout|stripe\.confirmPayment|'
        r'elements\.create\(["\'](card|payment)["\'\)]|'
        r'loadStripe\(|@stripe/stripe-js|js\.stripe\.com/v3',
        combined, re.I
    ))
    _braintree_sdk = bool(re.search(
        r'braintree\.client\.create|hostedFields\.create|'
        r'dropin\.create|braintreegateway\.com/web',
        combined, re.I
    ))
    _adyen_sdk = bool(re.search(
        r'AdyenCheckout|adyen\.com|checkoutshopper',
        combined, re.I
    ))
    # Any known tokenization SDK = card data never reaches server raw
    if _stripe_sdk or _braintree_sdk or _adyen_sdk:
        tokenized    = True
        iframe_based = True   # treat as safe — hosted/elements
    raw_post = not tokenized and not iframe_based

    found = []
    for name, js_pat, ep_pat, icon in _PAYMENT_GATEWAYS:
        confidence = 0
        if js_pat.search(combined):  confidence += 2
        if ep_pat.search(combined):  confidence += 2
        if confidence > 0:
            if iframe_based:
                tok = "🔒 iframe/Hosted Fields (card data never touches server)"
            elif tokenized:
                tok = "🔐 JS Tokenization (card → token before POST)"
            else:
                tok = "⚠️ Possibly Raw POST (card data may reach server)"
            found.append({
                'name': name, 'icon': icon,
                'confidence': confidence,
                'tokenization': tok,
                'raw_post_risk': raw_post,
            })
    return sorted(found, key=lambda x: -x['confidence'])


def _extract_forms_static(html: str, page_url: str) -> list:
    """BeautifulSoup ဖြင့် <form> + orphan fields ကို extract လုပ်သည်။
    ENH: label map, aria-label, placeholder, select options, orphan field capture.
    """
    from bs4 import BeautifulSoup
    soup = BeautifulSoup(html, 'html.parser')

    # ── Build label map: input id/name → visible label text ──────────────
    label_map = {}
    for lbl in soup.find_all('label'):
        txt = lbl.get_text(strip=True)
        if not txt:
            continue
        for_id = lbl.get('for', '').strip()
        if for_id:
            label_map[for_id] = txt
        # Also map by wrapped input
        wrapped = lbl.find(['input', 'select', 'textarea'])
        if wrapped:
            wid = wrapped.get('id', '') or wrapped.get('name', '')
            if wid and wid not in label_map:
                label_map[wid] = txt

    def _get_label(inp) -> str:
        for key in [inp.get('id', ''), inp.get('name', '')]:
            if key and key in label_map:
                return label_map[key]
        al = inp.get('aria-label', '') or inp.get('title', '')
        if al:
            return al
        ph = inp.get('placeholder', '')
        if ph:
            return ph
        # Nearest preceding sibling text
        try:
            for sib in reversed(list(inp.previous_siblings)):
                t = getattr(sib, 'get_text', lambda **k: '')(strip=True)
                if t and 2 < len(t) < 80:
                    return t
        except Exception:
            pass
        return ''

    def _build_field(inp, label_override='') -> dict | None:
        name  = inp.get('name') or inp.get('id') or ''
        if not name:
            return None
        ftype        = str(inp.get('type',        'text') or 'text').lower()
        value        = str(inp.get('value',        '')    or '')
        placeholder  = str(inp.get('placeholder',  '')    or '')
        aria_label   = str(inp.get('aria-label',   '')    or inp.get('title', '') or '')
        label_text   = str(label_override or _get_label(inp) or '')
        req          = inp.has_attr('required') or inp.get('required') == 'required'
        autocomplete = inp.get('autocomplete', '')
        pattern      = inp.get('pattern', '')
        minlength    = inp.get('minlength', '') or inp.get('minLength', '')
        maxlength    = inp.get('maxlength', '') or inp.get('maxLength', '')
        inp_min      = inp.get('min', '')
        inp_max      = inp.get('max', '')
        # ── Honeypot detection (inline CSS hiding) ──────────────────────
        _style       = (inp.get('style', '') or '').lower().replace(' ', '')
        _is_honeypot = (
            'display:none' in _style or
            'visibility:hidden' in _style or
            'opacity:0' in _style or
            ('position:absolute' in _style and
             any(x in _style for x in ('left:-', 'top:-', 'left:-999', 'top:-999'))) or
            inp.get('tabindex') == '-1' or
            inp.get('aria-hidden') == 'true'
        )
        # Select options
        options = []
        if inp.name == 'select':
            options = [o.get('value', '') or o.get_text(strip=True)
                       for o in inp.find_all('option') if o.get('value', '') != ''][:20]
        label, icon, is_dyn, card_type = _classify_field(
            name, value, ftype, placeholder, aria_label, label_text
        )

        # ── False positive filter for card fields ──────────────────────────
        # Reject card classification if:
        #  1. Value is a short non-card string (Y/N/true/false/0/1 flag) — NOT empty
        #  2. Name starts with 'old'/'prev'/'existing'/'saved' (token/history fields)
        #  3. Field type is hidden AND value is clearly a flag (1-2 chars, non-numeric)
        if card_type in ('Card Number', 'CVV/CVC', 'Routing Number', 'Account Number'):
            _name_lo  = name.lower()
            _val_lo   = value.strip().lower()
            # A flag value is a short, clearly boolean/non-card string (not empty — empty is normal)
            _flag_val = bool(_val_lo) and _val_lo in (
                'y', 'n', 'yes', 'no', 'true', 'false',
                '0', '1', 'on', 'off', 'enabled', 'disabled',
            )
            _is_old_field = bool(re.match(
                r'^(old|prev|previous|existing|saved|stored|last|former)',
                _name_lo
            ))
            # Hidden field with a flag-like value (1-2 chars that are non-numeric) is a flag
            _is_hidden_flag = (
                ftype == 'hidden'
                and bool(_val_lo)
                and len(_val_lo) <= 2
                and not _val_lo.isdigit()
            )
            if _flag_val or _is_old_field or _is_hidden_flag:
                card_type = None
                label     = label_text or 'User Input'
                icon      = '✏️'
        entry = {
            'name': name, 'type': ftype, 'value': value[:80],
            'required':     req,
            'field_label':  label_text or label,
            'icon':         icon,
            'is_dynamic':   is_dyn,
            'is_card':      card_type is not None,
            'card_type':    card_type,
            'placeholder':  placeholder,
            'autocomplete': autocomplete,
            'is_honeypot':  _is_honeypot,
        }
        if pattern:    entry['pattern']    = pattern
        if minlength:  entry['minlength']  = minlength
        if maxlength:  entry['maxlength']  = maxlength
        if inp_min:    entry['min']        = inp_min
        if inp_max:    entry['max']        = inp_max
        if options:
            entry['options'] = options
        return entry

    results = []
    in_form_names: set = set()

    for idx, form in enumerate(soup.find_all('form')):
        action   = form.get('action', '')
        method   = form.get('method', 'GET').upper()
        enctype  = form.get('enctype', 'application/x-www-form-urlencoded')
        endpoint = (urljoin(page_url, action)
                    if action and not action.startswith('http') else (action or page_url))
        fields = []
        for inp in form.find_all(['input', 'textarea', 'select']):
            f = _build_field(inp)
            if f:
                fields.append(f)
                in_form_names.add(f['name'])

        # ── ENH: Capture submit buttons ───────────────────────────────────
        submit_buttons = []
        # <input type="submit"> and <input type="button">
        for inp in form.find_all('input', type=lambda t: t and t.lower() in ('submit', 'button')):
            btn_text  = inp.get('value', '') or inp.get('aria-label', '') or 'Submit'
            btn_name  = inp.get('name', '') or inp.get('id', '') or 'submit'
            submit_buttons.append({
                'tag':   'input',
                'type':  inp.get('type', 'submit').lower(),
                'name':  btn_name,
                'text':  btn_text,
                'value': inp.get('value', ''),
            })
        # <button> elements
        for btn in form.find_all('button'):
            btype = btn.get('type', 'submit').lower()
            if btype in ('submit', 'button', ''):
                btn_text = btn.get_text(strip=True) or btn.get('aria-label', '') or btn.get('value', '') or 'Submit'
                btn_name = btn.get('name', '') or btn.get('id', '') or 'button'
                submit_buttons.append({
                    'tag':   'button',
                    'type':  btype,
                    'name':  btn_name,
                    'text':  btn_text[:80],
                    'value': btn.get('value', ''),
                })

        card_fields = [f for f in fields if f.get('is_card')]
        results.append({
            'source': 'static', 'form_idx': idx + 1,
            'endpoint': endpoint, 'method': method, 'enctype': enctype,
            'fields': fields, 'card_fields': card_fields,
            'is_payment': len(card_fields) > 0,
            'submit_buttons': submit_buttons,
        })

    # ── ENH: Capture inputs OUTSIDE any <form> (orphan fields) ───────────
    orphan_fields = []
    for inp in soup.find_all(['input', 'textarea', 'select']):
        if inp.find_parent('form'):
            continue
        ftype = inp.get('type', 'text').lower()
        if ftype in ('submit', 'button', 'reset', 'image'):
            continue
        f = _build_field(inp)
        if f and f['name'] not in in_form_names:
            orphan_fields.append(f)
            in_form_names.add(f['name'])

    if orphan_fields:
        card_fields = [f for f in orphan_fields if f.get('is_card')]
        results.append({
            'source': 'static_orphan', 'form_idx': len(results) + 1,
            'endpoint': page_url, 'method': 'POST',
            'enctype': 'application/x-www-form-urlencoded',
            'fields': orphan_fields, 'card_fields': card_fields,
            'is_payment': len(card_fields) > 0,
            'note': 'Fields outside <form> tags',
        })

    return results


def _extract_requests_playwright(url: str, progress_cb=None) -> list:
    """Playwright network intercept — fetch/XHR POST ဖမ်းသည်။"""
    if not PLAYWRIGHT_OK:
        return []
    safe, _ = is_safe_url(url)
    if not safe:
        return []

    captured = []
    js_text  = ''

    try:
        from playwright.sync_api import sync_playwright
        with sync_playwright() as pw:
            browser = pw.chromium.launch(
                headless=True,
                args=["--no-sandbox","--disable-dev-shm-usage",
                      "--disable-blink-features=AutomationControlled","--disable-gpu"])
            ctx = browser.new_context(
                user_agent=("Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                            "AppleWebKit/537.36 (KHTML, like Gecko) "
                            "Chrome/122.0.0.0 Safari/537.36"),
                viewport={"width": 1366, "height": 768},
                ignore_https_errors=True)
            ctx.add_init_script("""
                Object.defineProperty(navigator, 'webdriver',  {get: () => undefined});
                Object.defineProperty(navigator, 'plugins',    {get: () => [1,2,3,4,5]});
                Object.defineProperty(navigator, 'languages',  {get: () => ['en-US','en']});
                Object.defineProperty(navigator, 'platform',   {get: () => 'Win32'});
                Object.defineProperty(navigator, 'hardwareConcurrency', {get: () => 8});
                window.chrome = {runtime: {}, loadTimes: function(){}, csi: function(){}, app: {}};
                Object.defineProperty(Notification, 'permission', {get: () => 'default'});
                window.outerWidth  = 1366;
                window.outerHeight = 768;
            """)
            page = ctx.new_page()

            def on_request(request):
                if request.method not in ('POST','PUT','PATCH'): return
                try:
                    body     = request.post_data or ''
                    ct       = request.headers.get('content-type','')
                    endpoint = request.url
                    fields   = []

                    if 'json' in ct:
                        try:
                            data = json.loads(body)
                            if isinstance(data, dict):
                                for k, v in data.items():
                                    label,icon,is_dyn,card_type = _classify_field(k,str(v))
                                    fields.append({'name':k,'type':'json','value':str(v)[:80],
                                        'required':True,'field_label':label,'icon':icon,
                                        'is_dynamic':is_dyn,'is_card':card_type is not None,
                                        'card_type':card_type})
                        except Exception: pass
                    elif 'urlencoded' in ct or 'form' in ct:
                        try:
                            for k,vals in parse_qs(body).items():
                                v = vals[0] if vals else ''
                                label,icon,is_dyn,card_type = _classify_field(k,v)
                                fields.append({'name':k,'type':'form','value':v[:80],
                                    'required':True,'field_label':label,'icon':icon,
                                    'is_dynamic':is_dyn,'is_card':card_type is not None,
                                    'card_type':card_type})
                        except Exception: pass
                    elif 'multipart' in ct:
                        for match in re.finditer(r'name="([^"]+)"', body):
                            k = match.group(1)
                            label,icon,is_dyn,card_type = _classify_field(k,'')
                            fields.append({'name':k,'type':'multipart','value':'',
                                'required':False,'field_label':label,'icon':icon,
                                'is_dynamic':is_dyn,'is_card':card_type is not None,
                                'card_type':card_type})

                    card_fields = [f for f in fields if f.get('is_card')]
                    if fields or body:
                        captured.append({
                            'source':'playwright','form_idx':len(captured)+1,
                            'endpoint':endpoint,'method':request.method,'enctype':ct or 'unknown',
                            'fields':fields,'card_fields':card_fields,
                            'is_payment':len(card_fields)>0,
                            'raw_body': body[:200] if not fields else '',
                        })
                except Exception: pass

            # FIX 3: Response body capture — GET responses contain tokens/keys
            # that never appear in POST body (Stripe pk_, CSRF, session tokens)
            _resp_bodies: dict = {}   # url → body text
            _RESP_CT = ("json", "javascript", "text", "html", "xml", "form", "graphql")
            _KEY_RE = re.compile(
                r'pk_(?:live|test)_[A-Za-z0-9]{20,}'
                r'|(?:csrf|_token|nonce|authenticity_token)[^\n]{0,4}:\s*["\'][^"\']{8,}["\']'
                r'|client_secret[^\n]{0,4}:\s*["\'][^"\']{10,}["\']'
                r'|access_token[^\n]{0,4}:\s*["\'][^"\']{10,}["\']'
                r'|eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+',
                re.I
            )

            def on_response(response):
                try:
                    ct = (response.headers.get("content-type") or "").lower()
                    if not any(x in ct for x in _RESP_CT):
                        return
                    cl = int(response.headers.get("content-length") or 0)
                    if cl > 1_000_000:   # skip files > 1MB
                        return
                    if _KEY_RE.search(response.url):
                        return          # skip CDN/external JS
                    body = response.body().decode("utf-8", errors="replace")[:12_000]
                    if _KEY_RE.search(body):
                        _resp_bodies[response.url] = body
                except Exception:
                    pass

            page.on('response', on_response)
            page.on('request', on_request)
            if progress_cb: progress_cb("🌐 Playwright loading + intercepting...")

            # FIX 2: domcontentloaded avoids networkidle hang on WS/polling sites
            # Falls back: load → commit (bare minimum — gets HTML + fires hooks)
            try:
                page.goto(url, wait_until="domcontentloaded", timeout=28_000)
            except Exception:
                try:
                    page.goto(url, wait_until="load", timeout=20_000)
                except Exception:
                    try:
                        page.goto(url, wait_until="commit", timeout=15_000)
                    except Exception:
                        pass
            # Wait for lazy-load XHR (React hydration, SPA router settle)
            try:
                page.wait_for_load_state("networkidle", timeout=6_000)
            except Exception:
                pass
            # Fixed flush — always wait at least 2.5s for async SDK init calls
            try: page.wait_for_timeout(2500)
            except Exception: pass

            # ── ENH: DOM field extraction from rendered page + iframes ─────
            if progress_cb: progress_cb("🔍 Extracting DOM fields (rendered + iframes)...")
            try:
                dom_raw = page.evaluate("""() => {
                    const fields = [];
                    const seen   = new Set();

                    function getLabel(el) {
                        if (el.id) {
                            const lbl = document.querySelector('label[for="' + el.id + '"]');
                            if (lbl) return lbl.innerText.trim();
                        }
                        if (el.getAttribute('aria-label')) return el.getAttribute('aria-label').trim();
                        if (el.title) return el.title.trim();
                        if (el.placeholder) return el.placeholder.trim();
                        let p = el.parentElement;
                        while (p && p.tagName !== 'FORM' && p.tagName !== 'BODY') {
                            if (p.tagName === 'LABEL') return p.innerText.replace(el.value||'','').trim();
                            p = p.parentElement;
                        }
                        let sib = el.previousElementSibling;
                        while (sib) {
                            const t = (sib.innerText || '').trim();
                            if (t && t.length > 1 && t.length < 80) return t;
                            sib = sib.previousElementSibling;
                        }
                        const par = el.closest('div,td,li,fieldset');
                        if (par) {
                            const clone = par.cloneNode(true);
                            clone.querySelectorAll('input,select,textarea,button').forEach(e=>e.remove());
                            const t = clone.innerText.trim();
                            if (t && t.length < 80) return t;
                        }
                        return el.name || el.id || '';
                    }

                    function extractFrom(root, prefix) {
                        root.querySelectorAll('input,textarea,select').forEach(el => {
                            const name = el.name || el.id || '';
                            const type = (el.type || 'text').toLowerCase();
                            if (!name || ['submit','button','image','reset'].includes(type)) return;
                            const key = prefix + ':' + name;
                            if (seen.has(key)) return;
                            seen.add(key);
                            const opts = el.tagName === 'SELECT'
                                ? Array.from(el.options).map(o=>o.value||o.text).filter(Boolean).slice(0,20)
                                : [];
                            // ── Honeypot detection via computedStyle ──
                            let is_honeypot = false;
                            try {
                                const cs = window.getComputedStyle(el);
                                is_honeypot = (
                                    cs.display === 'none' ||
                                    cs.visibility === 'hidden' ||
                                    parseFloat(cs.opacity) === 0 ||
                                    el.getAttribute('tabindex') === '-1' ||
                                    el.getAttribute('aria-hidden') === 'true' ||
                                    (parseInt(cs.left) < -100 && cs.position === 'absolute') ||
                                    (parseInt(cs.top)  < -100 && cs.position === 'absolute')
                                );
                            } catch(e) {}
                            fields.push({
                                name, type,
                                value:        (el.value||'').slice(0,80),
                                placeholder:  el.placeholder||'',
                                required:     el.required || el.getAttribute('required')!==null,
                                label:        getLabel(el).slice(0,80),
                                options:      opts,
                                from_iframe:  prefix !== 'main',
                                autocomplete: el.autocomplete || el.getAttribute('autocomplete') || '',
                                pattern:      el.pattern      || el.getAttribute('pattern')      || '',
                                minlength:    el.minLength    != null ? String(el.minLength) : '',
                                maxlength:    el.maxLength    != null ? String(el.maxLength) : '',
                                min:          el.min          || '',
                                max:          el.max          || '',
                                is_honeypot:  is_honeypot,
                            });
                        });
                    }

                    extractFrom(document, 'main');

                    // ── A: Shadow DOM traversal ──────────────────────────────
                    function extractShadowRoots(root) {
                        root.querySelectorAll('*').forEach(el => {
                            if (el.shadowRoot) {
                                extractFrom(el.shadowRoot, 'shadow_' + (el.id || el.tagName.toLowerCase()));
                                extractShadowRoots(el.shadowRoot);
                            }
                        });
                    }
                    extractShadowRoots(document);

                    // ── A: Stripe Elements mount point → reconstruct synthetic fields ─
                    const stripeContainers = document.querySelectorAll(
                        '[id*="card-element"],[id*="card-number"],[id*="card-expiry"],' +
                        '[id*="card-cvc"],[class*="StripeElement"],[data-elements-stable-field-name],' +
                        '[id*="payment-element"],[class*="stripe-element"]'
                    );
                    if (stripeContainers.length > 0) {
                        const stripeTypes = [
                            {name:'cardNumber',    card_type:'Card Number',   ac:'cc-number',    maxlen:'19'},
                            {name:'cardExpiry',    card_type:'Expiry MM/YY',  ac:'cc-exp',       maxlen:'5'},
                            {name:'cardCvc',       card_type:'CVV/CVC',       ac:'cc-csc',       maxlen:'4'},
                            {name:'cardholderName',card_type:'Cardholder Name',ac:'cc-name',     maxlen:'60'},
                        ];
                        stripeTypes.forEach(st => {
                            if (!seen.has('stripe:' + st.name)) {
                                seen.add('stripe:' + st.name);
                                fields.push({
                                    name: st.name, type: 'stripe_element',
                                    value: '', placeholder: st.card_type,
                                    required: true, label: st.card_type,
                                    options: [], from_iframe: true,
                                    autocomplete: st.ac, maxlength: st.maxlen,
                                    is_stripe_element: true,
                                    card_type_hint: st.card_type,
                                });
                            }
                        });
                    }

                    document.querySelectorAll('iframe').forEach((fr, i) => {
                        try {
                            const doc = fr.contentDocument || fr.contentWindow.document;
                            if (doc) extractFrom(doc, 'iframe_' + i);
                        } catch(e) {
                            const src   = fr.src || fr.getAttribute('src') || '';
                            const title = fr.title || fr.getAttribute('title') || '';
                            const fname = fr.name  || fr.getAttribute('name')  || '';
                            const w     = fr.width  || fr.style.width  || '';
                            const h     = fr.height || fr.style.height || '';
                            fields.push({
                                name:        'iframe_' + i,
                                type:        'iframe',
                                value:       src,
                                placeholder: '',
                                required:    false,
                                label:       'Cross-origin payment iframe: ' + (src || 'unknown'),
                                options:     [],
                                from_iframe: true,
                                iframe_meta: {src: src, title: title, name: fname, width: w, height: h},
                            });
                        }
                    });

                    const formInfo = [];
                    document.querySelectorAll('form').forEach((f,i) => {
                        formInfo.push({idx:i, action:f.action||'', method:(f.method||'POST').toUpperCase()});
                    });
                    return {fields, formInfo};
                }""")

                dom_fields = dom_raw.get('fields', []) if dom_raw else []
                form_info  = dom_raw.get('formInfo', []) if dom_raw else []

                if dom_fields:
                    # FIX 8: SPA endpoint detection — React/Next.js forms have no action=""
                    # Priority: form action → intercepted POST URL → XHR payment path → page URL
                    endpoint = page.url

                    # 1. Explicit form action (best)
                    if form_info:
                        act = form_info[0].get('action', '')
                        if act and act.startswith('http'):
                            endpoint = act
                        elif act and act.strip() not in ('', '#', 'javascript:void(0)'):
                            endpoint = urljoin(url, act)

                    # 2. Look in already-captured POST requests for payment endpoint
                    if endpoint == page.url:
                        _PAY_EP_RE = re.compile(
                            r'/(?:checkout|payment|pay|order|cart|billing|charge|'
                            r'confirm|purchase|subscribe|donate)(?:[/?#]|$)',
                            re.I
                        )
                        for _cap in captured:
                            _cap_ep = _cap.get('endpoint', '')
                            if (_cap.get('source') == 'playwright'
                                    and _cap_ep
                                    and _PAY_EP_RE.search(_cap_ep)):
                                endpoint = _cap_ep
                                break

                    # 3. Try JS-evaluated form submit URL from data-* attrs
                    if endpoint == page.url:
                        try:
                            _js_ep = page.evaluate("""() => {
                                const f = document.querySelector('form');
                                if (!f) return null;
                                return f.getAttribute('data-action') ||
                                       f.getAttribute('data-url') ||
                                       f.getAttribute('data-submit-url') ||
                                       f.dataset.action || null;
                            }""")
                            if _js_ep and _js_ep.strip():
                                endpoint = (
                                    _js_ep if _js_ep.startswith('http')
                                    else urljoin(url, _js_ep)
                                )
                        except Exception:
                            pass

                    fields_out = []
                    existing_names: set = set()
                    for f in dom_fields:
                        fname      = f.get('name', '')
                        ftype      = f.get('type', 'text')
                        fval       = f.get('value', '')
                        fph        = f.get('placeholder', '')
                        flabel     = f.get('label', '')
                        freq       = f.get('required', False)
                        fopts      = f.get('options', [])
                        label, icon, is_dyn, card_type = _classify_field(
                            fname, fval, ftype, fph, '', flabel
                        )
                        entry = {
                            'name': fname, 'type': ftype, 'value': fval[:80],
                            'required': freq,
                            'field_label': flabel or label,
                            'icon': icon, 'is_dynamic': is_dyn,
                            'is_card': card_type is not None,
                            'card_type': card_type,
                            'placeholder': fph,
                            'from_iframe': f.get('from_iframe', False),
                        }
                        if fopts:
                            entry['options'] = fopts
                        if fname not in existing_names:
                            fields_out.append(entry)
                            existing_names.add(fname)

                    card_fields_dom = [f for f in fields_out if f.get('is_card')]
                    captured.append({
                        'source': 'playwright_dom',
                        'form_idx': len(captured) + 1,
                        'endpoint': endpoint,
                        'method': form_info[0].get('method', 'POST') if form_info else 'POST',
                        'enctype': 'application/x-www-form-urlencoded',
                        'fields': fields_out,
                        'card_fields': card_fields_dom,
                        'is_payment': len(card_fields_dom) > 0,
                        'note': f'Playwright DOM ({len(dom_fields)} fields, includes iframes)',
                    })
                    if progress_cb:
                        progress_cb(f"✅ DOM: {len(fields_out)} fields (incl. iframes)")
            except Exception as dom_err:
                if progress_cb:
                    progress_cb(f"⚠️ DOM extract: {dom_err}")

            # ── ENH: localStorage / sessionStorage live dump ──────────────
            try:
                _storage_raw = page.evaluate("""() => {
                    const _tok_keys = /token|auth|jwt|session|csrf|nonce|key|secret|bearer/i;
                    const ls = {}, ss = {};
                    for (let i = 0; i < localStorage.length; i++) {
                        const k = localStorage.key(i);
                        const v = localStorage.getItem(k) || '';
                        if (_tok_keys.test(k) || _tok_keys.test(v.slice(0,80)))
                            ls[k] = v.slice(0, 200);
                    }
                    for (let i = 0; i < sessionStorage.length; i++) {
                        const k = sessionStorage.key(i);
                        const v = sessionStorage.getItem(k) || '';
                        if (_tok_keys.test(k) || _tok_keys.test(v.slice(0,80)))
                            ss[k] = v.slice(0, 200);
                    }
                    return { localStorage: ls, sessionStorage: ss };
                }""")
                if _storage_raw:
                    captured.append({
                        '_storage_dump': True,
                        'localStorage':  _storage_raw.get('localStorage', {}),
                        'sessionStorage': _storage_raw.get('sessionStorage', {}),
                    })
            except Exception:
                pass

            # FIX 7: JS bundle limit 50KB→500KB — Stripe/Adyen SDK bundles are 200KB+
            # Skip CDN/analytics scripts — only fetch same-origin + known payment CDNs
            _PAY_CDN_RE = re.compile(
                r'js\.stripe\.com|braintreegateway\.com|paypal\.com/sdk|'
                r'adyen\.com|squarecdn\.com|klarna\.com|checkout\.com|'
                r'pay\.google\.com|applePay',
                re.I
            )
            try:
                _parsed_origin = urlparse(url)
                _origin_host   = _parsed_origin.netloc
                _js_budget     = 0
                _JS_TOTAL_MAX  = 2_000_000   # 2MB total JS cap across all scripts

                for s in page.query_selector_all('script[src]'):
                    if _js_budget >= _JS_TOTAL_MAX:
                        break
                    _src = s.get_attribute('src') or ''
                    if not _src:
                        continue
                    _full = urljoin(url, _src) if not _src.startswith('http') else _src
                    _parsed_s = urlparse(_full)

                    # Include: same-origin OR known payment CDN
                    _is_same_origin = _parsed_s.netloc == _origin_host
                    _is_pay_cdn     = bool(_PAY_CDN_RE.search(_full))
                    if not (_is_same_origin or _is_pay_cdn):
                        continue

                    try:
                        _r = requests.get(_full, timeout=6, verify=False,
                                          headers=_get_headers())
                        if _r.status_code == 200:
                            _chunk = _r.text[:500_000]   # FIX 7: was 50_000
                            js_text += _chunk
                            _js_budget += len(_chunk)
                    except Exception:
                        pass
            except Exception:
                pass

            # FIX 3b: attach response bodies to first captured item
            if _resp_bodies and captured:
                captured[0].setdefault('_resp_bodies', {}).update(_resp_bodies)
            elif _resp_bodies:
                captured.append({'_js_only': True, '_js_text': '',
                                 '_resp_bodies': _resp_bodies})

            browser.close()
    except Exception as e:
        logger.warning(f"Playwright payload intercept error: {e}")

    # Attach js_text to first captured item for gateway detection
    if captured:
        captured[0]['_js_text'] = js_text
    elif js_text:
        captured.append({'_js_text': js_text, '_js_only': True})

    return captured



# ══════════════════════════════════════════════════════════════
# ── Token Source Detection  (Phase 6) ─────────────────────────
# ══════════════════════════════════════════════════════════════

_TOKEN_FIELD_PATTERNS = [
    # name pattern, source_type, location label, field label
    (re.compile(r'<input[^>]+type=["\']hidden["\'][^>]*name=["\']([^"\']+)["\'][^>]*value=["\']([^"\']*)["\']', re.I | re.S),
     'hidden_input', 'HTML <input type="hidden">',  'Hidden form field — injected by server per-request'),
    (re.compile(r'<input[^>]*name=["\']([^"\']*(?:csrf|token|nonce|_token|authenticity)[^"\']*)["\'][^>]*value=["\']([^"\']*)["\']', re.I | re.S),
     'hidden_input', 'HTML <input type="hidden">',  'CSRF / Auth token — hidden input'),
    (re.compile(r'<meta[^>]+name=["\']([^"\']*(?:csrf|token|_token)[^"\']*)["\'][^>]*content=["\']([^"\']*)["\']', re.I | re.S),
     'meta_tag',     'HTML <meta> tag',              'CSRF meta tag — read by JS before POST'),
    (re.compile(r'<meta[^>]+content=["\']([^"\']*)["\'][^>]*name=["\']([^"\']*(?:csrf|token)[^"\']*)["\']', re.I | re.S),
     'meta_tag',     'HTML <meta> tag',              'CSRF meta tag — read by JS before POST'),
]

_TOKEN_JS_PATTERNS = [
    # js_text pattern, source_type, location, label
    (re.compile(r'(?:csrf[_\-]?token|_token|csrfmiddlewaretoken|authenticity_token|nonce)\s*[:=]\s*["\']([^"\']{8,})["\']', re.I),
     'js_variable', 'Inline JS / <script> block', 'CSRF/Auth token assigned in JavaScript'),
    (re.compile(r'(?:access[_\-]?token|auth[_\-]?token|bearer[_\-]?token|id[_\-]?token|api[_\-]?key)\s*[:=]\s*["\']([^"\']{8,})["\']', re.I),
     'js_variable', 'Inline JS / <script> block', 'Auth token stored in JS variable'),
    (re.compile(r'(?:stripe\.setPublishableKey|stripe\(|pk_(?:live|test)_\w{10,})', re.I),
     'js_variable', 'Stripe JS SDK',              'Stripe publishable key — used for card tokenization'),
    (re.compile(r'braintree\.client\.create\s*\(\s*\{[^}]*authorization\s*:\s*["\']([^"\']+)["\']', re.I | re.S),
     'js_variable', 'Braintree JS SDK',           'Braintree client token — used for card tokenization'),
    (re.compile(r'localStorage\.(?:getItem|setItem)\s*\(\s*["\']([^"\']*(?:token|auth|session|jwt)[^"\']*)["\']', re.I),
     'js_variable', 'localStorage (JS)',          'Token stored / retrieved from localStorage'),
    (re.compile(r'sessionStorage\.(?:getItem|setItem)\s*\(\s*["\']([^"\']*(?:token|auth|session|jwt)[^"\']*)["\']', re.I),
     'js_variable', 'sessionStorage (JS)',        'Token stored / retrieved from sessionStorage'),
    (re.compile(r'document\.cookie\s*=.*?(["\'](?:[^"\']*(?:token|auth|session|jwt)[^"\']*)["\'])', re.I),
     'cookie',      'document.cookie (JS)',       'Token written to cookie via JS'),
]

_KNOWN_CSRF_NAMES = {
    '_token', 'csrf_token', 'csrfmiddlewaretoken', 'authenticity_token',
    '_csrf', 'csrf', '__requestverificationtoken', 'xsrf-token',
    '_wpnonce', 'nonce', 'woocommerce-process-checkout-nonce',
}

def _find_token_sources(html: str, js_text: str) -> list:
    """
    Scan HTML + JS text for dynamic token sources.
    Returns list of dicts:
      name, value_preview, source_type, location, label
    """
    html    = html    or ""
    js_text = js_text or ""
    html    = html    or ""
    js_text = js_text or ""
    results = []
    seen    = set()

    # ── 1. HTML hidden inputs + meta tags ─────────────────────
    for pat, src_type, location, label in _TOKEN_FIELD_PATTERNS:
        for m in pat.finditer(html):
            grps = m.groups()
            name  = grps[0].strip()
            value = grps[1].strip() if len(grps) > 1 else ''
            key   = (src_type, name.lower())
            if key in seen:
                continue
            seen.add(key)
            # Only include if name looks token-like or matches known names
            name_l = name.lower()
            if not (any(kw in name_l for kw in ('token','csrf','nonce','auth','key','secret','verify','hash'))
                    or name_l in _KNOWN_CSRF_NAMES):
                continue
            results.append({
                'name':          name,
                'value_preview': (value[:40] + '…') if len(value) > 40 else (value or '(empty)'),
                'source_type':   src_type,
                'location':      location,
                'label':         label,
            })

    # ── 2. Hidden inputs by name heuristic (broad scan) ────────
    for m in re.finditer(
        r'<input[^>]+type=["\']hidden["\'][^>]*name=["\']([^"\']+)["\'][^>]*value=["\']([^"\']*)["\']',
        html, re.I | re.S
    ):
        name  = m.group(1).strip()
        value = m.group(2).strip()
        key   = ('hidden_input', name.lower())
        if key in seen:
            continue
        name_l = name.lower()
        if not (any(kw in name_l for kw in ('token','csrf','nonce','auth','key','verify','hash','secret'))
                or name_l in _KNOWN_CSRF_NAMES):
            continue
        seen.add(key)
        results.append({
            'name':          name,
            'value_preview': (value[:40] + '…') if len(value) > 40 else (value or '(empty — runtime)'),
            'source_type':   'hidden_input',
            'location':      'HTML <input type="hidden">',
            'label':         'Hidden form field — injected by server per-request',
        })

    # ── 3. JS text patterns ─────────────────────────────────────
    html    = html    or ""
    js_text = js_text or ""
    combined_js = html + '\n' + js_text
    for pat, src_type, location, label in _TOKEN_JS_PATTERNS:
        for m in pat.finditer(combined_js):
            grps = m.groups()
            name  = grps[0].strip() if grps else m.group(0)[:60]
            key   = (src_type, name.lower()[:30])
            if key in seen:
                continue
            seen.add(key)
            results.append({
                'name':          name,
                'value_preview': '(runtime value)',
                'source_type':   src_type,
                'location':      location,
                'label':         label,
            })

    return results


# ══════════════════════════════════════════════════════════════
# ── Header Requirement Detection  (Phase 5) ───────────────────
# ══════════════════════════════════════════════════════════════

_PROBE_HEADERS = [
    ("X-CSRF-Token",      "CSRF protection token",       "🛡️",
     "Anti-CSRF — server rejects requests without valid token"),
    ("X-Requested-With",  "XMLHttpRequest marker",       "📡",
     "Marks request as AJAX — required by WP/Laravel/Django"),
    ("Referer",           "Request origin URL",          "🔗",
     "Origin check — missing Referer may trigger 403/block"),
    ("User-Agent",        "Browser identity string",     "🌐",
     "Bot detection — missing/generic UA triggers WAF block"),
    ("Origin",            "Cross-origin source",         "🌍",
     "CORS enforcement — required for cross-origin POST"),
    ("Accept",            "Accepted response types",     "📥",
     "Content negotiation — some APIs require specific Accept"),
    ("Accept-Language",   "Language preference",         "🗣️",
     "Locale enforcement — some sites geo-block without it"),
    ("Cookie",            "Session / auth cookies",      "🍪",
     "Session state — required for authenticated endpoints"),
    ("Authorization",     "Bearer / Basic auth token",   "🔐",
     "API auth — required for protected REST endpoints"),
    ("Content-Type",      "Request body format",         "📦",
     "Body parsing — server needs this to decode POST payload"),
]

_HDR_STATUS = {
    "required":    ("🔴 Required",  "Request fails/blocked without this header"),
    "important":   ("🟡 Important", "Affects behavior — may cause 403 or partial response"),
    "optional":    ("🟢 Optional",  "Server accepts without it"),
    "not_checked": ("⚪ Unknown",   "Could not determine — test manually"),
}


def _probe_header_requirement(url: str, progress_cb=None) -> list:
    """
    Each header ကို ဖြုတ်ပြီး request ပို့引 response ကွာခြားမှု စစ်ဆေးသည်။
    Returns: list of header result dicts
    """
    base_headers = {
        "User-Agent":      ("Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                            "AppleWebKit/537.36 (KHTML, like Gecko) "
                            "Chrome/122.0.0.0 Safari/537.36"),
        "Accept":          "text/html,application/xhtml+xml,*/*;q=0.8",
        "Accept-Language": "en-US,en;q=0.9",
        "Referer":         url,
        "Origin":          f"{urlparse(url).scheme}://{urlparse(url).netloc}",
        "X-Requested-With":"XMLHttpRequest",
        "X-CSRF-Token":    "probe-token-value",
        "Content-Type":    "application/x-www-form-urlencoded",
    }

    try:
        base_resp   = requests.get(url, headers=base_headers,
                                   timeout=TIMEOUT, verify=False, allow_redirects=True)
        base_status = base_resp.status_code
        base_len    = len(base_resp.content)
    except Exception:
        return []

    if progress_cb:
        progress_cb(f"📋 Baseline {base_status} ({base_len}B) — probing headers...")

    results = []
    for hdr_name, description, icon, reason in _PROBE_HEADERS:
        probe_hdrs = {k: v for k, v in base_headers.items()
                      if k.lower() != hdr_name.lower()}
        status_key   = "not_checked"
        probe_status = None
        probe_len    = None
        notes        = ""

        try:
            r            = requests.get(url, headers=probe_hdrs,
                                        timeout=TIMEOUT, verify=False, allow_redirects=True)
            probe_status = r.status_code
            probe_len    = len(r.content)

            if probe_status in (400, 401, 403, 405, 419, 422, 429):
                status_key = "required"
                notes      = f"Without header → {probe_status}"
            elif probe_status != base_status:
                status_key = "important"
                notes      = f"Status changed: {base_status} → {probe_status}"
            elif probe_len < base_len * 0.7:
                status_key = "important"
                notes      = f"Body shrank: {base_len}B → {probe_len}B"
            else:
                status_key = "optional"
                notes      = f"No change ({probe_status}, {probe_len}B)"
        except Exception as e:
            status_key = "not_checked"
            notes      = str(e)[:60]

        label, meaning = _HDR_STATUS[status_key]
        results.append({
            "header":       hdr_name,
            "description":  description,
            "icon":         icon,
            "reason":       reason,
            "status_key":   status_key,
            "status_label": label,
            "meaning":      meaning,
            "base_status":  base_status,
            "probe_status": probe_status,
            "probe_len":    probe_len,
            "notes":        notes,
        })

    return results

# ── Token Source location patterns ────────────────────────────
_TOKEN_SOURCE_RULES = [
    # (token_name_pattern, source_type, description, icon)
    # Hidden input
    (re.compile(r'csrf|_token|authenticity_token|__requestverification|xsrf', re.I),
     'hidden_input', 'Hidden <input type="hidden"> in form', '🔒'),
    (re.compile(r'nonce|_nonce|wp_nonce', re.I),
     'hidden_input', 'Hidden <input> / WordPress nonce field', '🔒'),
    (re.compile(r'sess|session|phpsessid', re.I),
     'cookie', 'Server-set Cookie (not in HTML source)', '🍪'),
    (re.compile(r'otp|pin|verification_?code', re.I),
     'server_response', 'Server sends via SMS/Email — not in HTML', '📟'),
    (re.compile(r'payment.?token|pm_|pay.?token|stripe|braintree', re.I),
     'js_gateway', 'JS gateway SDK generates at runtime', '💳'),
]

_JS_VAR_PATTERNS = [
    # window.xxx = "..."  /  var xxx = "..."  /  const xxx = "..."
    re.compile(r'(?:window\.|var\s+|const\s+|let\s+)(\w*(?:token|nonce|csrf|xsrf|secret|key)\w*)\s*[=:]\s*["\']([^"\']{8,})["\']', re.I),
    # PHP/template inline: "csrfToken":"abc..."
    re.compile(r'["\'](\w*(?:token|nonce|csrf|xsrf)\w*)["\']\s*:\s*["\']([^"\']{8,})["\']', re.I),
]

_META_PATTERN = re.compile(
    r'<meta[^>]+name=["\'](\w*(?:token|nonce|csrf|xsrf)\w*)["\'][^>]+content=["\']([^"\']{4,})["\']',
    re.I
)

_HIDDEN_INPUT_PATTERN = re.compile(
    r'<input[^>]+type=["\']hidden["\'][^>]*name=["\']([^"\']+)["\'][^>]*value=["\']([^"\']*)["\']',
    re.I
)


_RECAPTCHA_SITEKEY_PATTERNS = [
    # data-sitekey="xxx"
    re.compile(r'data-sitekey=["\']([A-Za-z0-9_\-]{20,})["\']', re.I),
    # grecaptcha.render(..., {sitekey: "xxx"})
    re.compile(r'sitekey["\']?\s*[=:]\s*["\']([A-Za-z0-9_\-]{20,})["\']', re.I),
    # grecaptcha.execute('xxx')
    re.compile(r'grecaptcha\.execute\(["\']([A-Za-z0-9_\-]{20,})["\']', re.I),
    # hcaptcha data-sitekey
    re.compile(r'h-captcha[^>]*data-sitekey=["\']([A-Za-z0-9_\-\-]{20,})["\']', re.I),
    # turnstile (Cloudflare)
    re.compile(r'turnstile[^>]*data-sitekey=["\']([A-Za-z0-9_\-]{20,})["\']', re.I),
    # JS var: recaptchaSiteKey = "..."
    re.compile(r'(?:recaptcha|captcha|siteKey|site_key)\w*\s*[=:]\s*["\']([A-Za-z0-9_\-]{20,})["\']', re.I),
]

def _extract_recaptcha_info(html: str, js_text: str, page_url: str) -> dict | None:
    """
    HTML + JS မှ reCAPTCHA / hCaptcha / Turnstile site key ဖမ်းသည်။
    Returns {site_key, page_url, base_url, captcha_type} or None
    """
    html    = html    or ""
    js_text = js_text or ""
    html    = html    or ""
    js_text = js_text or ""
    combined = html + js_text

    # Detect captcha type
    captcha_type = 'reCAPTCHA v2'
    if re.search(r'grecaptcha\.execute', combined, re.I):
        captcha_type = 'reCAPTCHA v3'
    elif re.search(r'h-captcha|hcaptcha', combined, re.I):
        captcha_type = 'hCaptcha'
    elif re.search(r'cf-turnstile|turnstile', combined, re.I):
        captcha_type = 'Cloudflare Turnstile'

    site_key = None
    for pat in _RECAPTCHA_SITEKEY_PATTERNS:
        m = pat.search(combined)
        if m:
            site_key = m.group(1)
            break

    if not site_key:
        return None

    parsed   = urlparse(page_url)
    base_url = f"{parsed.scheme}://{parsed.netloc}"

    return {
        'site_key':    site_key,
        'page_url':    page_url,
        'base_url':    base_url,
        'captcha_type': captcha_type,
    }



    """
    HTML + JS ထဲမှ dynamic token တွေ ဘယ်နေရာမှာ define လုပ်သည် စစ်သည်။
    Returns list of dicts: {name, value_preview, source_type, location, icon}
    """
    results = []
    seen = set()

    # 1. Hidden input fields
    for m in _HIDDEN_INPUT_PATTERN.finditer(html):
        name  = m.group(1)
        value = m.group(2)
        label, icon, is_dyn, _ = _classify_field(name, value)
        if not is_dyn:
            continue
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        results.append({
            'name':          name,
            'value_preview': value[:30] + ('…' if len(value) > 30 else ''),
            'source_type':   'hidden_input',
            'location':      'HTML → <input type="hidden">',
            'icon':          '🔒',
            'label':         label,
        })

    # 2. Meta tag tokens
    for m in _META_PATTERN.finditer(html):
        name  = m.group(1)
        value = m.group(2)
        key   = name.lower()
        if key in seen:
            continue
        seen.add(key)
        results.append({
            'name':          name,
            'value_preview': value[:30] + ('…' if len(value) > 30 else ''),
            'source_type':   'meta_tag',
            'location':      'HTML → <meta name="…" content="…">',
            'icon':          '🏷️',
            'label':         'CSRF/Nonce Token',
        })

    # 3. JS variable tokens (inline scripts + external JS)
    combined_js = html + js_text
    for pat in _JS_VAR_PATTERNS:
        for m in pat.finditer(combined_js):
            name  = m.group(1)
            value = m.group(2)
            key   = name.lower()
            if key in seen:
                continue
            seen.add(key)
            # Determine if it's inline script or external JS
            # Check if match position is inside a <script> tag in html
            pos   = m.start()
            loc   = ('HTML → inline <script> variable'
                     if pos < len(html) else 'External JS file variable')
            results.append({
                'name':          name,
                'value_preview': value[:30] + ('…' if len(value) > 30 else ''),
                'source_type':   'js_variable',
                'location':      loc,
                'icon':          '📜',
                'label':         'Dynamic JS Token',
            })

    # 4. Cookie-based tokens (infer from field names)
    all_html = html
    for rule_pat, src_type, desc, icon in _TOKEN_SOURCE_RULES:
        if src_type != 'cookie':
            continue
        # Look for cookie reads in JS: document.cookie, getCookie(
        if re.search(r'document\.cookie|getCookie\(|Cookies\.get\(', combined_js, re.I):
            # find field names that match session pattern
            for m in re.finditer(
                r'["\'](\w*(?:sess|session|phpsessid)\w*)["\']', combined_js, re.I
            ):
                name = m.group(1)
                key  = name.lower()
                if key in seen:
                    continue
                seen.add(key)
                results.append({
                    'name':          name,
                    'value_preview': '(runtime value)',
                    'source_type':   'cookie',
                    'location':      'Browser Cookie → JS reads via document.cookie',
                    'icon':          '🍪',
                    'label':         'Session Cookie',
                })

    return results




