async def cmd_bypass403(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/bypass403 <url> — Test 403 Forbidden bypass techniques"""
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/bypass403 https://example.com/admin`\n\n"
            "🔓 *Tests 50+ bypass techniques:*\n"
            "  • Header manipulation (X-Original-URL, X-Forwarded-For...)\n"
            "  • Path normalization variants (/admin/, /ADMIN, /admin/..)\n"
            "  • HTTP method override (POST, PUT, OPTIONS...)\n"
            "  • X-HTTP-Method-Override header\n"
            "  • Content-Type tricks\n"
            "  • URL encoding bypass (%20, %09, %00)\n\n"
            "⚠️ _For authorized security testing only._",
            parse_mode='Markdown'
        )
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url

    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{escape_md(reason)}`", parse_mode='Markdown')
        return

    domain = urlparse(url).hostname
    path   = urlparse(url).path or "/"

    msg = await update.effective_message.reply_text(
        f"🔓 *Bypass Testing — `{escape_md(domain)}`*\n"
        f"Path: `{escape_md(path)}`\n\n"
        "Running 50+ bypass techniques...\n⏳",
        parse_mode='Markdown'
    )

    try:
        results = await run_scan(uid, _bypass_sync, url)
    except Exception as e:
        await msg.edit_text(f"❌ Error: `{escape_md(e)}`", parse_mode='Markdown')
        return

    baseline    = next((r for r in results if r.get("technique") == "Baseline"), None)
    baseline_st = baseline["status"] if baseline else "?"
    bypasses    = [r for r in results if r.get("bypassed")]
    tested      = len(results) - 1   # exclude baseline

    lines = [
        f"🔓 *Bypass Results — `{escape_md(path)}`*",
        f"🌐 `{escape_md(domain)}` | Baseline: `{escape_md(baseline_st)}`",
        f"🧪 Tested: `{escape_md(tested)}` techniques | ✅ Bypassed: `{len(bypasses)}`\n",
    ]

    if not bypasses:
        lines.append("🔒 No bypasses found — endpoint is well-protected.")
    else:
        lines.append(f"*🚨 {len(bypasses)} Bypass(es) Found:*")
        for b in bypasses[:15]:
            st_icon = "✅" if b["status"] in (200,201,204) else "↪️"
            lines.append(
                f"  {st_icon} `{b['status']}` [{b['method']}] `{b['label'][:55]}`"
            )
            if b["status"] in (301, 302):
                loc = b.get("headers", {}).get("Location", "")
                if loc:
                    lines.append(f"      → `{escape_md(loc[:60])}`")

    # ── Summary by technique type ────────────────────
    tech_counts = {}
    for b in bypasses:
        t = b.get("technique", "other")
        tech_counts[t] = tech_counts.get(t, 0) + 1
    if tech_counts:
        lines.append("\n*By technique:*")
        for t, c in sorted(tech_counts.items(), key=lambda x: -x[1]):
            lines.append(f"  • `{escape_md(t)}`: {c}")

    lines.append("\n⚠️ _Authorized testing only._")

    # ── Export JSON if bypasses found ────────────────
    if bypasses:
        import io
        report = json.dumps({
            "url": url, "baseline_status": baseline_st,
            "tested": tested, "bypasses_found": len(bypasses),
            "bypass_details": [{
                "label": b["label"], "method": b["method"],
                "status": b["status"], "size": b["size"],
                "technique": b["technique"],
                "location": b.get("headers",{}).get("Location",""),
            } for b in bypasses],
            "all_results": [{
                "label": r["label"], "method": r["method"],
                "status": r["status"], "size": r["size"],
            } for r in results],
        }, indent=2)
        buf = io.BytesIO(report.encode())
        try:
            await safe_markdown_reply(msg, _truncate_safe_md("\n".join(lines)))
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            await context.bot.send_document(
                chat_id=update.effective_chat.id,
                document=buf,
                filename=f"bypass403_{domain}_{ts}.json",
                caption=f"🔓 Bypass report — `{escape_md(domain)}` — `{len(bypasses)}` bypasses",
                parse_mode='Markdown'
            )
        except Exception:
            await safe_markdown_reply(update.effective_message, _truncate_safe_md("\n".join(lines)))
    else:
        await safe_markdown_reply(msg, _truncate_safe_md("\n".join(lines)))




async def cmd_payload(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/payload <url> — Extract request payload + payment structure (JSON export)"""
    if not context.args:
        # UI/UX refactor: compact MarkdownV2 capability card replaces long bullet list
        await update.effective_message.reply_text(
            "🧩 *Payload Extractor*\n"
            "`/payload <url>`\n\n"
            "*Forms*  fields · endpoints · hidden · honeypots\n"
            "*Security*  headers · cookies · CSP · CORS · 3DS\n"
            "*Gateways*  23\\+ detectors · tokenization risk\n"
            "*Tokens*  CSRF · nonce · localStorage dump\n"
            "*Output*  inline report \\+ JSON export\n\n"
            "⚠️ _Authorized testing only\\._",
            parse_mode='MarkdownV2'
        )
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url

    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{escape_md(reason)}`", parse_mode='Markdown')
        return

    domain = urlparse(url).hostname or url

    # ── Phase definitions (icon, label, keyword triggers from progress_cb) ──
    _PAYLOAD_PHASES = [
        ("⬇️", "Static HTML parse",              ["Fetching HTML"]),
        ("🌐", "Playwright JS render",            ["Playwright launching", "Playwright loading"]),
        ("📡", "Network intercept (XHR/fetch)",   ["intercepting", "form(s)", "DOM fields", "Extracting DOM"]),
        ("💳", "Payment gateway detection",        ["gateway"]),
        ("🖐️", "Device fingerprint SDK scan",     ["Scanning device fingerprint", "device fingerprint", "fingerprint SDK"]),
        ("🛡️", "Anti-fraud middleware detection", ["Detecting anti-fraud", "anti-fraud middleware", "anti_fraud"]),
        ("🔍", "Header requirement probing",       ["Probing header requirement", "Probing header"]),
        ("🔎", "Token source detection",           ["token source", "Locating token"]),
        ("🤖", "CAPTCHA sitekey scan (Playwright)",["CAPTCHA", "site key", "reCAPTCHA", "Sitekeys found"]),
        ("🔗", "Sub-page scan",                   ["sub-page", "Sub-page", "subpage"]),
        ("🔐", "3DS / SCA signal detection",      ["3DS", "SCA", "3d secure"]),
        ("📱", "Wallet / Express pay detection",   ["wallet", "Wallet", "express pay"]),
        ("📊", "Rate limit headers",               ["rate limit", "Rate limit"]),
        ("🍪", "Auth cookie security",             ["Analyzing auth cookie", "auth cookie", "Cookie security"]),
        ("🛡️", "CSP analysis",                    ["Content-Security", "CSP"]),
        ("🌐", "CORS policy",                     ["CORS", "cors"]),
        ("🔷", "GraphQL probe",                   ["GraphQL", "graphql"]),
        ("📖", "API schema discovery",             ["OpenAPI", "Swagger", "schema"]),
        ("⚙️", "Framework detection",              ["framework", "Framework"]),
        ("🪜", "Multi-step checkout",              ["multi-step", "multi step", "checkout"]),
        ("📋", "Request snippet generation",       ["snippet", "curl"]),
        ("🔴", "Live intercept (Enhanced · 5-phase)",  ["Live intercept", "Hooks active", "Live:", "live_result", "focus-probe", "pay-click", "field-fill"]),
        ("🔎", "Success / Decline pattern scan",   ["success / decline", "Patterns:", "Scanning success"]),
        ("⚡", "Velocity / rate-limit detection",    ["Detecting velocity", "velocity", "rate-limit protection"]),
        ("🔒", "Form action security check",          ["Checking form action", "form action security"]),
        ("🔢", "Luhn card pattern validation",        ["Luhn-validating", "Luhn", "luhn"]),
        ("🎟️", "Coupon / promo field scan",           ["Scanning for coupon", "coupon", "promo code"]),
        ("🔗", "Post-payment redirect extraction",    ["Extracting post-payment", "redirect URL", "Redirect URLs"]),
        ("🔐", "WebAuthn / Passkey detection",        ["Scanning WebAuthn", "WebAuthn", "Passkey"]),
        ("📊", "Gateway field completeness score",    ["Scoring gateway", "Completeness", "completeness score"]),
        ("🗺️", "Payment flow sequence mapping",       ["Building payment flow sequence", "payment flow sequence"]),
        ("🔗", "Request dependency mapping",           ["Mapping request dependencies", "request dependencies"]),
        ("🔐", "Encryption logic replication",         ["Detecting and replicating encryption", "encryption logic"]),
    ]
    TOTAL_PHASES = len(_PAYLOAD_PHASES)

    # PATCHED: clean note truncation, internal prefix stripping, no ▓ running block
    def _build_progress_msg(domain: str, phase_idx: int, note: str = "") -> str:
        filled = min(phase_idx, TOTAL_PHASES)
        pct    = int((filled / TOTAL_PHASES) * 100)
        bar    = "█" * filled + "░" * (TOTAL_PHASES - filled)

        if phase_idx < TOTAL_PHASES:
            icon, cur_label, _ = _PAYLOAD_PHASES[phase_idx]
            phase_line = (
                f"{icon} {escape_md(cur_label)}  "
                f"_{phase_idx + 1} / {TOTAL_PHASES}_"
            )
        else:
            phase_line = f"✅ _All {TOTAL_PHASES} phases done_"

        # Clean note: take only the first clause, strip internal debug strings
        short_note = ""
        if note:
            # Drop anything after first "..." or newline, cap at 55 chars
            short_note = note.split("...")[0].split("\n")[0].strip()[:55]
            # Strip known internal prefixes that are not user-facing
            for _pfx in ("Fetching", "Playwright", "intercepting",
                         "Probing", "Scanning", "Extracting", "Locating"):
                if short_note.startswith(_pfx):
                    short_note = short_note[len(_pfx):].lstrip(" —:-")
                    break

        note_line = f"\n_→ {escape_md(short_note)}_" if short_note else ""

        return (
            f"🧩 *Payload Extractor*  ·  `{escape_md(domain)}`\n\n"
            f"`[{bar}]`  {pct}%\n\n"
            f"{phase_line}{note_line}"
        )

    def _msg_to_phase(text: str) -> int | None:
        # PATCHED: guard against backward jump handled in progress_cb
        tl = text.lower()
        for i, (_, _, keywords) in enumerate(_PAYLOAD_PHASES):
            if any(kw.lower() in tl for kw in keywords):
                return i
        return None

    # ── Send initial progress message ──────────────────────────
    msg = await update.effective_message.reply_text(
        _build_progress_msg(domain, 0, "Starting…"),
        parse_mode='Markdown'
    )

    # ── Thread-safe progress bridge ────────────────────────────
    loop           = asyncio.get_event_loop()
    progress_queue: asyncio.Queue = asyncio.Queue()
    phase_state    = [0]   # mutable so thread closure can update

    def progress_cb(text: str):
        # PATCHED: backward jump guard — phase index never decreases
        detected = _msg_to_phase(text)
        if detected is not None:
            phase_state[0] = max(phase_state[0], detected)  # never go back
        loop.call_soon_threadsafe(
            progress_queue.put_nowait, (phase_state[0], text)
        )

    async def progress_editor():
        """Async task: drain queue, edit Telegram message.
        Throttle: edit at most once every 3s to avoid Telegram rate-limit.
        """
        import time as _time
        last_text    = ""
        last_edit_ts = 0.0
        EDIT_INTERVAL = 3.0   # seconds between edits
        while True:
            try:
                item = await asyncio.wait_for(progress_queue.get(), timeout=0.5)
            except asyncio.TimeoutError:
                task_obj = _user_tasks.get(uid)
                if task_obj and task_obj.done():
                    break
                continue
            if item is None:        # sentinel — scan done
                break
            idx, note = item
            new_text = _build_progress_msg(domain, idx, note)
            if new_text == last_text:
                continue
            now = _time.monotonic()
            if now - last_edit_ts < EDIT_INTERVAL:
                continue          # skip — too soon, drop this update
            last_text    = new_text
            last_edit_ts = now
            try:
                await msg.edit_text(new_text, parse_mode='Markdown')
            except Exception:
                pass

    editor_task = asyncio.create_task(progress_editor())

    try:
        data = await run_scan(uid, _payload_sync, url, progress_cb)
    except asyncio.CancelledError:
        loop.call_soon_threadsafe(progress_queue.put_nowait, None)   # stop editor
        editor_task.cancel()
        await msg.edit_text("🛑 Cancelled.", parse_mode='Markdown')
        return
    except Exception as e:
        loop.call_soon_threadsafe(progress_queue.put_nowait, None)   # stop editor
        editor_task.cancel()
        await msg.edit_text(f"❌ Error: `{escape_md(str(e))}`", parse_mode='Markdown')
        return

    # Signal editor task to stop (normal flow only — exceptions handle their own sentinel above)
    loop.call_soon_threadsafe(progress_queue.put_nowait, None)

    # Wait for editor to finish (max 2s)
    try:
        await asyncio.wait_for(editor_task, timeout=2.0)
    except Exception:
        editor_task.cancel()

    # ── Show all-done bar before report ────────────────────────
    try:
        done_msg = (
            f"🧩 *Payload Extractor — `{escape_md(domain)}`*\n\n"
            f"✅ All {TOTAL_PHASES} phases completed\n"
            f"`[{'█' * TOTAL_PHASES}]` 100%\n\n"
            f"📄 Generating report..."
        )
        await msg.edit_text(done_msg, parse_mode='Markdown')
    except Exception:
        pass

    # ── Markdown report ────────────────────────────────────────
    report = _format_payload_report(data)

    # ── Smart chunk splitter — code block aware ────────────────
    MAX_LEN  = 3900   # safe margin below Telegram's 4096 hard limit
    HARD_MAX = 4090   # absolute ceiling — force-flush even inside a block

    def _smart_chunks(text: str) -> list:
        """
        3900 char ကျော်ရင် split လုပ်သည်။
        ``` code block အတွင်းမှာ ဖြတ်ရမယ်ဆိုရင် fence ကို
        close/reopen လုပ်ပြီး ဆက်ပြသည်။
        Single line ကိုယ်တိုင် MAX_LEN ထက်ကြီးနေရင်
        hard-split (fence-safe) လုပ်သည်။
        """
        if len(text) <= MAX_LEN:
            return [text]

        chunks     = []
        current    = []
        cur_len    = 0
        in_block   = False
        fence_lang = ""   # language tag of the currently open fence, e.g. "python"

        def flush(reopen: bool = False):
            # PATCHED: capture fence_lang before clearing state so reopen uses correct lang
            nonlocal current, cur_len, in_block
            if not current:
                return
            saved_lang = fence_lang          # snapshot before any mutation
            if in_block:
                current.append("```\n")
            chunks.append("".join(current))
            current = []
            cur_len = 0
            if reopen and in_block:
                opener = f"```{saved_lang}\n"  # use snapshot, not (now-cleared) fence_lang
                current.append(opener)
                cur_len = len(opener)

        for line in text.splitlines(keepends=True):
            stripped = line.strip()
            if stripped.startswith("```"):
                if not in_block:
                    fence_lang = stripped[3:].strip()
                    in_block   = True
                else:
                    in_block   = False
                    fence_lang = ""

            line_len = len(line)

            # Single line longer than MAX_LEN: hard-split it in pieces
            if line_len > MAX_LEN:
                flush(reopen=True)
                pos = 0
                while pos < line_len:
                    piece = line[pos:pos + MAX_LEN]
                    pos  += MAX_LEN
                    if pos < line_len:
                        chunks.append(piece)
                    else:
                        current.append(piece)
                        cur_len = len(piece)
                continue

            # Normal line: flush if adding it would exceed the safe limit
            if cur_len + line_len > MAX_LEN and current:
                flush(reopen=True)

            # Force-flush if we somehow still hit the hard ceiling
            if cur_len + line_len > HARD_MAX and current:
                flush(reopen=True)

            current.append(line)
            cur_len += line_len

        flush(reopen=False)
        return chunks

    async def _safe_send_report(text: str):
        parts = _smart_chunks(text)
        await asyncio.sleep(1.5)  # rate-limit cooling after many progress edits
        for part in parts:
            try:
                await update.effective_message.reply_text(part, parse_mode='Markdown')
            except Exception:
                await update.effective_message.reply_text(part)

    await _safe_send_report(report)

    # PATCHED: cache scan data + send inline keyboard
    import hashlib as _hl
    _url_hash = _hl.md5(url.encode()).hexdigest()[:8]
    context.bot_data[f'payload_cache_{_url_hash}'] = {
        'url': url, 'data': data}

    _kb = InlineKeyboardMarkup([
        [
            InlineKeyboardButton("🔄 Re-scan",   callback_data=f"pla_rescan_{_url_hash}"),
            InlineKeyboardButton("📋 curl",      callback_data=f"pla_curl_{_url_hash}"),
            InlineKeyboardButton("📄 JSON",      callback_data=f"pla_json_{_url_hash}"),
            InlineKeyboardButton("📜 Script",    callback_data=f"pla_script_{_url_hash}"),
        ],
        [
            InlineKeyboardButton("🔴 Live Intercept", callback_data=f"pla_live_{_url_hash}"),
            InlineKeyboardButton("💳 Flow",           callback_data=f"pla_flow_{_url_hash}"),
            InlineKeyboardButton("🔥 Fire POST",      callback_data=f"pla_fire_{_url_hash}"),
        ],
    ])
    await update.effective_message.reply_text(
        "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
        reply_markup=_kb
    )

    # ── JSON file export ───────────────────────────────────────
    try:
        json_str = _build_json_export(data)
        safe_dom = re.sub(r'[^\w\-]', '_', domain)[:40]
        fname    = f"payload_{safe_dom}.json"
        tmp_path = os.path.join(tempfile.gettempdir(), fname)
        with open(tmp_path, 'w', encoding='utf-8') as f:
            f.write(json_str)
        with open(tmp_path, 'rb') as f:
            await update.effective_message.reply_document(
                document=f, filename=fname,
                caption=(
                    f"📄 *Payload JSON — `{escape_md(domain)}`*\n"
                    f"Forms: `{len(data['forms'])}` | "
                    f"XHR: `{len(data['requests'])}` | "
                    f"Gateways: `{len(data['gateways'])}`"
                ),
                parse_mode='Markdown'
            )
        os.unlink(tmp_path)
    except Exception as e:
        logger.warning(f"payload JSON export error: {e}")
        try:
            await update.effective_message.reply_text(
                f"⚠️ *JSON export failed*\n"
                f"`{escape_md(str(e)[:120])}`\n"
                f"_Report ကိုတော့ အပေါ်မှာ ကြည့်နိုင်ပါတယ်_",
                parse_mode='Markdown'
            )
        except Exception:
            pass

    # ── Payment Flow JSON export ───────────────────────────────
    try:
        flow_str  = _build_payment_flow_json(data)
        _safe_flow_dom = re.sub(r'[^\w\-]', '_', domain)[:36]
        flow_name = f"flow_{_safe_flow_dom}.json"
        flow_tmp  = os.path.join(tempfile.gettempdir(), flow_name)
        with open(flow_tmp, 'w', encoding='utf-8') as f:
            f.write(flow_str)

        # Count steps with real data for caption
        _flow_obj    = json.loads(flow_str)
        _gw_caption  = _flow_obj.get('meta', {}).get('gateway', '—')
        _step_count  = len(_flow_obj.get('steps', []))
        _has_captcha = bool(data.get('recaptcha', {}).get('site_key'))
        _has_3ds     = bool(data.get('threeds_signals'))

        _flow_tags = '  '.join(filter(None, [
            f"💳 {escape_md(_gw_caption)}",
            '🤖 CAPTCHA' if _has_captcha else None,
            '🔐 3DS'     if _has_3ds     else None,
        ]))

        with open(flow_tmp, 'rb') as f:
            await update.effective_message.reply_document(
                document=f,
                filename=flow_name,
                caption=(
                    f"🔀 *Payment Flow — `{escape_md(domain)}`*\n"
                    f"{_flow_tags}\n"
                    f"Step 1 GET · Step 2 Stripe · Step 3 POST · Step 4 Logic"
                ),
                parse_mode='Markdown'
            )
        os.unlink(flow_tmp)
    except Exception as e:
        logger.warning(f"payment flow JSON export error: {e}")


