# 🔴 /payloadlive — Realtime Network Request Stream
# ══════════════════════════════════════════════════════════════

# Known tokenization endpoints — request ဒီ URLs တွေ သွားရင် tokenize လုပ်တယ်
_TOKENIZATION_ENDPOINTS = [
    (re.compile(r'api\.stripe\.com', re.I),                    "Stripe",      "💳"),
    (re.compile(r'payments\.braintree-api\.com|braintreepayments', re.I), "Braintree", "🌿"),
    (re.compile(r'api\.paypal\.com|paypalobjects', re.I),      "PayPal",      "🅿️"),
    (re.compile(r'accept\.authorize\.net', re.I),              "Authorize.Net","🏦"),
    (re.compile(r'checkout\.adyen\.com|adyen\.com/v\d', re.I), "Adyen",       "🔷"),
    (re.compile(r'api\.squareup\.com|squareup\.com/v\d', re.I),"Square",      "⬛"),
    (re.compile(r'api\.razorpay\.com', re.I),                  "Razorpay",    "🇮🇳"),
    (re.compile(r'api\.klarna\.com|klarna\.com/v\d', re.I),    "Klarna",      "🟢"),
    (re.compile(r'api\.mollie\.com', re.I),                    "Mollie",      "🟡"),
    (re.compile(r'checkout\.shopify\.com|\.myshopify\.com', re.I), "Shopify", "🛍️"),
    (re.compile(r'js\.stripe\.com/v\d', re.I),                 "Stripe JS",   "💳"),
    (re.compile(r'token|tokenize|createToken|paymentMethod', re.I), "Token Endpoint", "🔐"),
]

def _detect_tokenization_url(url: str) -> tuple | None:
    """Request URL ကို tokenization endpoint ဆိုး စစ်သည်။ Returns (name, icon) or None."""
    for pattern, name, icon in _TOKENIZATION_ENDPOINTS:
        if pattern.search(url):
            return name, icon
    return None


def _format_live_entry(idx: int, endpoint: str, method: str, ct: str,
                        fields: list, tokenization: tuple | None,
                        raw_body: str = '') -> str:
    """Single intercepted request ကို Telegram message format ထုတ်သည်။"""
    ep_short = endpoint[:70]
    ct_short = (ct.replace('application/', '')
                  .replace('x-www-form-urlencoded', 'urlencoded')
                  .replace('; charset=utf-8', '').strip()[:35])

    lines = [f"{'─'*34}"]

    # Tokenization badge
    if tokenization:
        tok_name, tok_icon = tokenization
        lines.append(f"🔐 *Tokenization → {tok_icon} {escape_md(tok_name)}*")

    lines.append(f"📡 *#{idx}* `{escape_md(method)}` → `{escape_md(ep_short)}`")
    lines.append(f"📦 `{escape_md(ct_short)}`")

    if not fields:
        if raw_body:
            lines.append(f"📝 `{escape_md(raw_body[:120])}`")
        else:
            lines.append("⚠️ No parseable fields")
        return '\n'.join(lines)

    # Classify fields
    card_f   = [f for f in fields if f.get('card_type') in
                ('Card Number', 'CVV/CVC', 'Expiry', 'Cardholder Name')]
    pay_f    = [f for f in fields if f.get('card_type') in
                ('Amount', 'Currency', 'Order/Txn ID', 'Billing Address')]
    user_f   = [f for f in fields
                if not f.get('is_card') and not f.get('is_dynamic')
                and f.get('type') not in ('hidden', 'submit', 'button', 'reset')
                and f not in pay_f]
    dyn_f    = [f for f in fields if f.get('is_dynamic') and not f.get('is_card')]
    hidden_f = [f for f in fields
                if not f.get('is_card') and not f.get('is_dynamic')
                and f.get('type') in ('hidden', 'submit', 'button')
                and f not in pay_f]

    if card_f:
        lines.append(f"\n💳 *Card Fields* ({len(card_f)}):")
        card_lines = ["{"]
        for f in card_f:
            val = (f['value'][:40] if f.get('value')
                   else _smart_placeholder(f['name'], f.get('field_label',''), f.get('type','text')))
            comment = " // required" if f.get('required') else ""
            card_lines.append(f'  "{f["name"]}": "{val}",{comment}')
        card_lines.append("}")
        lines.append("```\n" + "\n".join(card_lines) + "\n```")

    if pay_f:
        lines.append(f"💰 *Payment Info* ({len(pay_f)}):")
        pay_lines = ["{"]
        for f in pay_f:
            val = (f['value'][:40] if f.get('value')
                   else _smart_placeholder(f['name'], f.get('field_label',''), f.get('type','text')))
            pay_lines.append(f'  "{f["name"]}": "{val}",')
        pay_lines.append("}")
        lines.append("```\n" + "\n".join(pay_lines) + "\n```")

    if user_f:
        lines.append(f"✏️ *User Fields* ({len(user_f)}):")
        user_lines = ["{"]
        for f in user_f:
            val     = (f['value'][:40] if f.get('value')
                       else _smart_placeholder(f['name'], f.get('field_label',''), f.get('type','text')))
            comment = " // required" if f.get('required') else ""
            user_lines.append(f'  "{f["name"]}": "{val}",{comment}')
        user_lines.append("}")
        lines.append("```\n" + "\n".join(user_lines) + "\n```")

    if dyn_f:
        dyn_names = ", ".join(f"`{escape_md(f['name'])}`" for f in dyn_f)
        lines.append(f"🔄 *Auto* ({len(dyn_f)}): {dyn_names}")

    if hidden_f:
        hid_names = ", ".join(f"`{escape_md(f['name'])}`" for f in hidden_f[:8])
        extra     = f" +{len(hidden_f)-8}" if len(hidden_f) > 8 else ""
        lines.append(f"📌 *Hidden* ({len(hidden_f)}): {hid_names}{escape_md(extra)}")

    return '\n'.join(lines)


# ══════════════════════════════════════════════════════════════
# 🔥 _fire_post_classify_sync — Live POST fire + response classifier
# ══════════════════════════════════════════════════════════════

def _fire_post_classify_sync(data: dict, progress_cb=None) -> dict:
    """
    Fire the payment form POST using cached /payload scan data.
    GET → CSRF prime → POST → classify (pattern + JSON + 3DS).
    Uses Stripe test cards only. Never touches real card data.
    """
    all_entries = data.get('forms', []) + data.get('requests', [])
    pay_entry   = next(
        (e for e in all_entries
         if e.get('is_payment') and (e.get('endpoint') or e.get('action'))),
        next((e for e in all_entries
              if e.get('endpoint') or e.get('action')), None)
    )
    if not pay_entry:
        return {'error': 'No form endpoint found in cached data', 'verdict': 'error'}

    submit_url = pay_entry.get('endpoint') or pay_entry.get('action', '')
    method     = (pay_entry.get('method') or 'POST').upper()
    enctype    = pay_entry.get('enctype', 'application/x-www-form-urlencoded')
    fields     = pay_entry.get('fields', [])
    page_url   = data.get('url', submit_url)
    gateways   = data.get('gateways', [])
    gw_name    = gateways[0].get('name', '') if gateways else ''

    if not submit_url:
        return {'error': 'Submit URL empty', 'verdict': 'error'}

    if progress_cb:
        progress_cb(f"🔥 Fire POST: {method} {submit_url[:60]}")

    _parsed_pg = urlparse(page_url)
    _origin    = f"{_parsed_pg.scheme}://{_parsed_pg.netloc}"
    _engine    = _make_engine("chrome")

    # ── Step 1: GET — prime session + fresh CSRF ──────────────────────────
    if progress_cb:
        progress_cb("⬇️ Step 1: Priming session (GET)…")
    resolved = dict(data.get('resolved_tokens', {}))
    try:
        _init_resp = _engine.get(page_url)
        _init_html = _init_resp.text
        _init_js   = '\n'.join(re.findall(r'<script[^>]*>(.+?)</script>',
                                          _init_html, re.S | re.I))
        _fresh_ts  = _find_token_sources(_init_html, _init_js)
        _fresh_rt  = _resolve_dynamic_tokens(
            url=page_url, token_sources=_fresh_ts, engine=_engine,
            html=_init_html, js_text=_init_js, progress_cb=progress_cb,
        )
        resolved.update(_fresh_rt)
        _live_n = sum(1 for v in resolved.values() if v.get('confidence') == 'live')
        if progress_cb:
            progress_cb(f"✅ Step 1 done — {_live_n} live token(s), "
                        f"{len(_engine.cookies)} cookie(s)")
    except Exception as _e1:
        if progress_cb:
            progress_cb(f"⚠️ Step 1 partial: {str(_e1)[:60]}")

    # ── Step 2: Stripe tokenization (test card only) ──────────────────────
    _stripe_pm_id = None
    _stripe_tok   = None
    _stripe_pk    = None
    _tok_type     = 'direct'
    _pk_re        = re.compile(r'\b(pk_(?:live|test)_[A-Za-z0-9]{20,})\b')

    for _src in [
        *[rt.get('value', '') for rt in resolved.values()],
        *[ts.get('value', '') or ts.get('value_preview', '')
          for ts in data.get('token_sources', [])],
    ]:
        _m = _pk_re.search(_src or '')
        if _m:
            _stripe_pk = _m.group(1)
            break

    if gw_name == 'Stripe' and _stripe_pk:
        _env_tag = 'LIVE 🔴' if 'pk_live_' in _stripe_pk else 'TEST 🟡'
        if progress_cb:
            progress_cb(f"🔑 pk_ [{_env_tag}]: {_stripe_pk[:16]}…{_stripe_pk[-4:]}")
        _sh = {
            'Authorization':  f'Bearer {_stripe_pk}',
            'Content-Type':   'application/x-www-form-urlencoded',
            'Stripe-Version': '2024-06-20',
        }
        try:
            _pm_r = requests.post(
                'https://api.stripe.com/v1/payment_methods',
                data={'type': 'card', 'card[number]': '4242424242424242',
                      'card[exp_month]': '12', 'card[exp_year]': '2029',
                      'card[cvc]': '123'},
                headers=_sh, timeout=12, verify=True,
            )
            _pm_b = _pm_r.json()
            if _pm_r.status_code == 200 and _pm_b.get('id', '').startswith('pm_'):
                _stripe_pm_id = _pm_b['id']
                _tok_type     = 'pm'
                _cc           = _pm_b.get('card', {})
                if progress_cb:
                    progress_cb(
                        f"✅ pm_ obtained: {_stripe_pm_id[:16]}…  "
                        f"brand:{_cc.get('brand','?')}  "
                        f"3ds:{_cc.get('three_d_secure_usage',{}).get('supported','?')}"
                    )
        except Exception as _pme:
            if progress_cb:
                progress_cb(f"⚠️ pm_ failed: {str(_pme)[:50]}")

        if not _stripe_pm_id:
            try:
                _tk_r = requests.post(
                    'https://api.stripe.com/v1/tokens',
                    data={'card[number]': '4242424242424242', 'card[exp_month]': '12',
                          'card[exp_year]': '2029', 'card[cvc]': '123'},
                    headers=_sh, timeout=12, verify=True,
                )
                _tk_b = _tk_r.json()
                if _tk_r.status_code == 200 and _tk_b.get('id', '').startswith('tok_'):
                    _stripe_tok = _tk_b['id']
                    _tok_type   = 'tok'
                    if progress_cb:
                        progress_cb(f"✅ tok_ fallback: {_stripe_tok[:12]}…")
            except Exception:
                pass

    # ── Build POST body ───────────────────────────────────────────────────
    _CARD_TEST = {
        'Card Number': '4242424242424242', 'CVV/CVC': '123',
        'Expiry Month': '12', 'Expiry Year': '2029', 'Expiry MM/YY': '12/29',
        'Cardholder Name': 'John Doe', 'Amount': '1.00', 'Currency': 'USD',
        'Billing First Name': 'John', 'Billing Last Name': 'Doe',
        'Billing Address': '123 Test St', 'Billing City': 'New York',
        'Billing State': 'NY', 'Billing Zip': '10001', 'Billing Country': 'US',
    }
    _best_token = _stripe_pm_id or _stripe_tok
    post_body: dict = {}

    for f in fields:
        nm  = f.get('name', '')
        ft  = f.get('type', 'text')
        ct  = f.get('card_type', '')
        val = f.get('value', '')
        if not nm or ft in ('submit', 'button', 'reset', 'image', 'iframe'):
            continue
        if f.get('is_honeypot'):
            continue
        rt = resolved.get(nm, {})
        if rt.get('value') and rt.get('confidence') in ('live', 'static', 'inferred'):
            post_body[nm] = rt['value']
            continue
        if _best_token and re.search(
            r'card.?token|stripe.?token|payment.?method|token.?card|'
            r'pm_id|payment_method_id|nonce|stripeToken|paymentMethodId', nm, re.I
        ):
            post_body[nm] = _best_token
            continue
        if re.search(r'g-recaptcha-response|recaptcha|h-captcha', nm, re.I):
            post_body[nm] = ''
            continue
        if ct in _CARD_TEST:
            post_body[nm] = _CARD_TEST[ct]
            continue
        if val and len(val) > 1 and not f.get('is_dynamic'):
            post_body[nm] = val
            continue
        nm_l = nm.lower()
        if   re.search(r'email|mail',        nm_l): post_body[nm] = 'test@test.com'
        elif re.search(r'phone|tel|mobile',  nm_l): post_body[nm] = '5555555555'
        elif re.search(r'fname|first.?name', nm_l): post_body[nm] = 'John'
        elif re.search(r'lname|last.?name',  nm_l): post_body[nm] = 'Doe'
        elif re.search(r'address|street',    nm_l): post_body[nm] = '123 Test St'
        elif re.search(r'\bcity\b',          nm_l): post_body[nm] = 'New York'
        elif re.search(r'state|province',    nm_l): post_body[nm] = 'NY'
        elif re.search(r'zip|postal',        nm_l): post_body[nm] = '10001'
        elif re.search(r'country',           nm_l): post_body[nm] = 'US'
        elif val:
            post_body[nm] = val

    # ── Step 3: Fire POST ─────────────────────────────────────────────────
    if progress_cb:
        progress_cb(f"🟠 Step 3: Firing {method} → {submit_url[:55]}…")

    submit_headers: dict = {
        **_get_headers(),
        'Referer': page_url,
        'Origin':  _origin,
    }
    for _tn, _rt in resolved.items():
        _hk = _rt.get('header_key')
        if _hk and _rt.get('value'):
            submit_headers[_hk] = _rt['value']
    if gw_name == 'Stripe':
        import hashlib as _hl3
        submit_headers['Idempotency-Key'] = _hl3.md5(
            f"fire-{page_url}-{time.time()}".encode()
        ).hexdigest()

    submit_status = 0
    submit_body   = ''
    submit_ct     = ''
    redirect_loc  = ''
    resp_json     = None
    resp_json_keys: dict = {}

    try:
        _is_json_enc = 'json' in enctype.lower()
        if method == 'POST':
            _sr = _engine.post(
                submit_url,
                **(dict(json_body=post_body,
                        headers={**submit_headers, 'Content-Type': 'application/json'})
                   if _is_json_enc else
                   dict(data=post_body, headers=submit_headers))
            )
        else:
            _qs = '&'.join(f"{k}={v}" for k, v in post_body.items())
            _sr = _engine.get(f"{submit_url}?{_qs}", headers=submit_headers)

        submit_status = _sr.status_code
        submit_body   = _sr.text[:20_000]
        try:
            submit_ct    = _sr.headers.get('Content-Type', '')
            redirect_loc = _sr.headers.get('Location', '')
        except Exception:
            pass

        if 'json' in submit_ct or submit_body.lstrip().startswith(('{', '[')):
            try:
                resp_json = json.loads(submit_body)
                _JSON_KEYS = (
                    'status', 'message', 'error', 'code', 'success', 'paid',
                    'declined', 'result', 'response_code', 'auth_code', 'approved',
                    'transaction_id', 'order_id', 'reference', 'description',
                    'next_action', 'client_secret', 'payment_intent',
                    'respstat', 'respcode', 'resptext', 'retref', 'setlstat',
                    'resultCode', 'pspReference', 'refusalReason',
                    'redirect', 'messages',
                )
                if isinstance(resp_json, dict):
                    for _rk in _JSON_KEYS:
                        _rv = resp_json.get(_rk)
                        if _rv is not None:
                            resp_json_keys[_rk] = str(_rv)[:100]
            except Exception:
                pass

        if progress_cb:
            progress_cb(
                f"📡 Step 3 response — HTTP {submit_status} "
                f"({len(submit_body)} chars)"
                + (f" → {redirect_loc[:60]}" if redirect_loc else '')
                + (' [JSON]' if resp_json is not None else '')
            )
    except Exception as _e3:
        if progress_cb:
            progress_cb(f"❌ Step 3 error: {str(_e3)[:80]}")
        _engine.close()
        return {'error': f'POST failed: {str(_e3)[:100]}', 'verdict': 'error',
                'post_body': post_body, 'endpoint': submit_url, 'method': method}

    # ── Step 4: Classify ──────────────────────────────────────────────────
    if progress_cb:
        progress_cb("🔎 Step 4: Classifying response…")

    patterns = _scan_response_patterns(
        html=submit_body, js_text='', url=submit_url,
        live_bodies=[submit_body],
    )

    _3ds_triggered = False
    _3ds_signals: list[str] = []
    for _pat, _lbl in [
        (r'requires_action|next_action|authentication_required', 'Stripe requires_action'),
        (r'3ds|3d.secure|acs.?url|pareq|threeDSMethodData|creq|cres', '3DS ACS challenge'),
        (r'ChallengeShopper|IdentifyShopper', 'Adyen 3DS challenge'),
        (r'"enrolled"\s*:\s*"Y"', '3DS enrolled=Y'),
        (r'redirect.*acs|acs.*redirect', 'ACS redirect'),
    ]:
        if re.search(_pat, submit_body, re.I | re.S):
            _3ds_triggered = True
            _3ds_signals.append(_lbl)
    if resp_json and isinstance(resp_json, dict):
        if resp_json.get('status') == 'requires_action':
            _3ds_triggered = True
            _3ds_signals.append('Stripe JSON requires_action')
        if resp_json.get('resultCode') in ('ChallengeShopper', 'IdentifyShopper'):
            _3ds_triggered = True
            _3ds_signals.append(f"Adyen {resp_json['resultCode']}")

    # HTTP verdict
    if submit_status in (200, 201):
        http_verdict = 'possible_success'
    elif submit_status in (400, 402, 422):
        http_verdict = 'validation_or_decline'
    elif submit_status == 403:
        http_verdict = 'blocked_csrf_or_auth'
    elif submit_status == 429:
        http_verdict = 'rate_limited'
    elif submit_status in (301, 302, 303, 307, 308):
        if re.search(r'success|confirm|thank|complete|approved', redirect_loc, re.I):
            http_verdict = 'redirect_success'
        elif re.search(r'fail|error|decline|reject', redirect_loc, re.I):
            http_verdict = 'redirect_decline'
        else:
            http_verdict = 'redirect_unknown'
    elif submit_status >= 500:
        http_verdict = 'server_error'
    else:
        http_verdict = f'http_{submit_status}'

    # JSON override
    if resp_json and isinstance(resp_json, dict):
        _js  = str(resp_json.get('status', '')).lower()
        _jok = resp_json.get('success')
        _jap = resp_json.get('approved')
        if _js in ('success', 'approved', 'ok', 'captured', 'authorized') \
                or _jok is True or _jap is True:
            http_verdict = 'json_success'
        elif _js in ('failed', 'declined', 'error', 'refused') \
                or _jok is False or _jap is False:
            http_verdict = 'json_decline'

    # Merge final verdict
    pat_verdict = patterns.get('verdict', 'unknown')
    if pat_verdict in ('success', 'decline'):
        final_verdict = pat_verdict
    elif _3ds_triggered:
        final_verdict = '3ds_challenge'
    elif http_verdict in ('redirect_success', 'json_success'):
        final_verdict = 'success'
    elif http_verdict in ('redirect_decline', 'json_decline', 'validation_or_decline'):
        final_verdict = 'decline'
    elif http_verdict == 'blocked_csrf_or_auth':
        final_verdict = 'blocked'
    elif http_verdict == 'rate_limited':
        final_verdict = 'rate_limited'
    elif http_verdict == 'server_error':
        final_verdict = 'server_error'
    else:
        final_verdict = pat_verdict or 'unknown'

    _VI = {
        'success': '✅', 'decline': '🔴', '3ds_challenge': '🔐',
        'blocked': '🚫', 'rate_limited': '⏳', 'server_error': '💥', 'unknown': '⚪',
    }
    if progress_cb:
        progress_cb(f"{_VI.get(final_verdict,'⚪')} Verdict: {final_verdict.upper()}")

    _engine.close()
    return {
        'verdict': final_verdict, 'http_status': submit_status,
        'http_verdict': http_verdict, 'pat_verdict': pat_verdict,
        'patterns': patterns, 'resp_json_keys': resp_json_keys,
        'resp_body': submit_body[:2000], 'resp_body_full': submit_body[:8000],
        'redirect_loc': redirect_loc, '3ds_triggered': _3ds_triggered,
        '3ds_signals': _3ds_signals, 'endpoint': submit_url,
        'method': method, 'enctype': enctype, 'post_body': post_body,
        'token_type': _tok_type, 'stripe_pm_id': _stripe_pm_id,
        'stripe_tok': _stripe_tok, 'gateway': gw_name,
    }




def _payloadlive_sync(url: str, on_request_cb, stop_event, timeout_sec: int = 180):
    """
    Playwright realtime intercept.
    on_request_cb(entry_text: str) — ဒါကို main thread safe queue ထဲ ထည့်မယ်
    stop_event: threading.Event — set() ဖြစ်ရင် ရပ်မယ်
    """
    if not PLAYWRIGHT_OK:
        on_request_cb("❌ Playwright မရှိ — `pip install playwright && playwright install chromium`")
        return

    import threading
    safe, reason = is_safe_url(url)
    if not safe:
        on_request_cb(f"🚫 {reason}")
        return

    counter    = [0]      # intercepted request counter
    seen_keys  = set()    # deduplicate sitekeys already reported
    seen_reqs  = set()    # deduplicate identical requests

    # ── Static asset filter (skip these for GET) ──────────────
    _STATIC_EXT = re.compile(
        r'\.(js|css|png|jpg|jpeg|gif|svg|ico|woff2?|ttf|eot|mp4|mp3|webp|avif)'
        r'(?:\?|$)', re.I)

    # ── API-like path pattern — GET requests worth showing ──────
    _API_PATH = re.compile(
        r'/(?:api|ajax|graphql|rest|v\d+|data|service|endpoint|query|fetch|rpc'
        r'|checkout|payment|cart|order|auth|login|session|token|user|account'
        r'|verify|validate|submit|process|search|config|setting|profile'
        r'|transaction|billing|invoice|product|catalog|price)(?:[/?]|$)',
        re.I)

    try:
        from playwright.sync_api import sync_playwright
        with sync_playwright() as pw:
            browser = pw.chromium.launch(
                headless=True,
                args=["--no-sandbox", "--disable-dev-shm-usage",
                      "--disable-blink-features=AutomationControlled", "--disable-gpu"])
            ctx = browser.new_context(
                user_agent=("Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                            "AppleWebKit/537.36 (KHTML, like Gecko) "
                            "Chrome/122.0.0.0 Safari/537.36"),
                viewport={"width": 1366, "height": 768},
                ignore_https_errors=True)
            ctx.add_init_script(
                "Object.defineProperty(navigator,'webdriver',{get:()=>undefined});")
            page = ctx.new_page()

            # ── Response hook — scan JS files for sitekeys ──────
            def on_resp(response):
                if stop_event.is_set():
                    return
                resp_url = response.url
                ct       = response.headers.get('content-type', '')
                # Only scan JS / HTML responses
                if not any(x in ct for x in ('javascript', 'html', 'text')):
                    return
                # Skip large files — response.text() blocks on large files
                content_len = int(response.headers.get('content-length', '0') or 0)
                if content_len > 500_000:   # skip > 500KB
                    return
                try:
                    body_text = response.text()
                    if len(body_text) > 500_000:
                        body_text = body_text[:500_000]
                except Exception:
                    return

                for pat in _RECAPTCHA_SITEKEY_PATTERNS:
                    m = pat.search(body_text)
                    if not m:
                        continue
                    key = m.group(1)
                    if key in seen_keys:
                        continue
                    seen_keys.add(key)

                    # Detect type
                    captcha_type = 'reCAPTCHA v2'
                    if re.search(r'grecaptcha\.execute', body_text, re.I):
                        captcha_type = 'reCAPTCHA v3'
                    elif re.search(r'h-captcha|hcaptcha', body_text, re.I):
                        captcha_type = 'hCaptcha'
                    elif re.search(r'cf-turnstile|turnstile', body_text, re.I):
                        captcha_type = 'Cloudflare Turnstile'

                    parsed   = urlparse(url)
                    base_url = f"{parsed.scheme}://{parsed.netloc}"

                    # Source location
                    if 'javascript' in ct:
                        src_loc = f"External JS — `{resp_url[:60]}`"
                    else:
                        src_loc = "Inline HTML / <script> tag"

                    msg_text = (
                        f"{'─'*34}\n"
                        f"🤖 *{escape_md(captcha_type)} — Site Key Found*\n\n"
                        f"  `RECAPTCHA_SITE_KEY` = `{escape_md(key)}`\n"
                        f"  `RECAPTCHA_PAGE_URL` = `{escape_md(url)}`\n"
                        f"  `BASE_URL`           = `{escape_md(base_url)}`\n\n"
                        f"📍 *Source:* {escape_md(src_loc)}"
                    )
                    on_request_cb(msg_text)

            def on_req(request):
                if stop_event.is_set():
                    return

                method   = request.method
                endpoint = request.url

                # ── Decide whether to capture this request ──────────
                is_write = method in ('POST', 'PUT', 'PATCH', 'DELETE')
                is_get   = method == 'GET'

                if not is_write and not is_get:
                    return

                if is_get:
                    # Skip static assets
                    if _STATIC_EXT.search(endpoint):
                        return
                    # Skip non-API GET unless it's XHR (Accept: application/json)
                    accept = request.headers.get('accept', '')
                    is_xhr = 'json' in accept or 'xml' in accept
                    if not is_xhr and not _API_PATH.search(endpoint):
                        return

                # ── Dedup — skip identical endpoint+method combos ───
                dedup_key = f"{method}:{endpoint[:120]}"
                if dedup_key in seen_reqs:
                    return
                seen_reqs.add(dedup_key)

                try:
                    from urllib.parse import parse_qs, parse_qsl, urlparse as _up_live
                    body = request.post_data or ''
                    ct   = request.headers.get('content-type', '')
                    fields = []

                    if is_get:
                        # Extract query params as fields
                        qs = _up_live(endpoint).query
                        if not qs:
                            return   # GET with no query params — skip
                        for k, v in parse_qsl(qs):
                            label, icon, is_dyn, card_type = _classify_field(k, v)
                            fields.append({
                                'name': k, 'type': 'query_param', 'value': v[:80],
                                'required': False, 'field_label': label, 'icon': icon,
                                'is_dynamic': is_dyn,
                                'is_card': card_type is not None,
                                'card_type': card_type,
                            })
                    elif 'json' in ct:
                        try:
                            data = json.loads(body)
                            if isinstance(data, dict):
                                for k, v in data.items():
                                    label, icon, is_dyn, card_type = _classify_field(k, str(v))
                                    fields.append({
                                        'name': k, 'type': 'json', 'value': str(v)[:80],
                                        'required': True, 'field_label': label, 'icon': icon,
                                        'is_dynamic': is_dyn,
                                        'is_card': card_type is not None,
                                        'card_type': card_type,
                                    })
                        except Exception:
                            pass
                    elif 'urlencoded' in ct or 'form' in ct:
                        try:
                            for k, vals in parse_qs(body).items():
                                v = vals[0] if vals else ''
                                label, icon, is_dyn, card_type = _classify_field(k, v)
                                fields.append({
                                    'name': k, 'type': 'form', 'value': v[:80],
                                    'required': True, 'field_label': label, 'icon': icon,
                                    'is_dynamic': is_dyn,
                                    'is_card': card_type is not None,
                                    'card_type': card_type,
                                })
                        except Exception:
                            pass
                    elif 'multipart' in ct:
                        for match in re.finditer(r'name="([^"]+)"', body):
                            k = match.group(1)
                            label, icon, is_dyn, card_type = _classify_field(k, '')
                            fields.append({
                                'name': k, 'type': 'multipart', 'value': '',
                                'required': False, 'field_label': label, 'icon': icon,
                                'is_dynamic': is_dyn,
                                'is_card': card_type is not None,
                                'card_type': card_type,
                            })

                    # For write methods: show even if no fields (raw body)
                    # For GET: must have at least 1 field (query param)
                    if is_get and not fields:
                        return
                    if not is_get and not fields and not body:
                        return

                    counter[0] += 1

                    # ── Tokenization gateway detection ──────────────
                    tok    = None
                    ep_low = endpoint.lower()
                    for tok_pat, tok_name, tok_icon in _TOKENIZATION_ENDPOINTS:
                        if tok_pat.search(endpoint):
                            tok = (tok_name, tok_icon)
                            break

                    # Method icon
                    method_icon = {
                        'POST': '📤', 'PUT': '🔄', 'PATCH': '✏️',
                        'DELETE': '🗑️', 'GET': '📥',
                    }.get(method, '📡')

                    entry_text = _format_live_entry(
                        counter[0], endpoint, f"{method_icon} {method}", ct, fields, tok, body)
                    on_request_cb(entry_text)
                except Exception:
                    pass

            page.on('response', on_resp)
            page.on('request',  on_req)

            # domcontentloaded = ပိုမြန်တယ်၊ initial requests miss မဖြစ်ဘူး
            try:
                page.goto(url, wait_until="domcontentloaded", timeout=40_000)
            except Exception:
                try:
                    page.goto(url, wait_until="commit", timeout=25_000)
                except Exception:
                    pass

            # ── Keep Playwright event loop alive ────────────────
            # time.sleep() သုံးလျှင် Playwright event loop block ဖြစ်ပြီး
            # requests process မဖြစ်တော့ဘူး — page.wait_for_timeout() သာ သုံးရမည်
            elapsed_ms = 0
            interval_ms = 500
            timeout_ms  = timeout_sec * 1000
            while not stop_event.is_set() and elapsed_ms < timeout_ms:
                try:
                    page.wait_for_timeout(interval_ms)
                except Exception:
                    break
                elapsed_ms += interval_ms

            browser.close()

    except Exception as e:
        on_request_cb(f"❌ Playwright error: `{escape_md(str(e))}`")


# ═══════════════════════════════════════════════════════════════════════════
#  Request Role Classifier  +  Dependency Graph Builder
#  ─────────────────────────────────────────────────────────────────────────
#  _ROLE_RULES         — URL / method / body pattern → role mapping
#  _classify_request_role(url, method, body) → role str
#  _build_payflow_timeline(data)             → list[TimelineEntry dict]
#
#  TimelineEntry keys:
#    step         int    — 1-based execution order
#    url          str
#    method       str    — GET / POST / PUT …
#    role         str    — session_init | token_fetch | stripe_tokenize | …
#    depends_on   list   — step numbers this entry depends on
#    must_precede list   — step numbers that depend on this entry
#    timing_ms    int    — round-trip ms (from xhr_profile; None if unknown)
#    status       int    — HTTP status (None if unknown)
#    source       str    — "profiler" | "payload" | "live"
#    label        str    — human-readable one-liner
# ═══════════════════════════════════════════════════════════════════════════

# ── Role classification rules ─────────────────────────────────────────────
# Each entry: (role_name, [(url_re, method_re, body_re), ...])
