    progress_q = []
    async def _prog():
        while True:
            await asyncio.sleep(3)
            if progress_q:
                t = progress_q[-1]; progress_q.clear()
                try: await msg.edit_text(f"🔍 *API Scan — `{escape_md(domain)}`*\n\n{t}", parse_mode='Markdown')
                except: pass
    prog = asyncio.create_task(_prog())
